INSERT INTO "compounds" VALUES (1,'structmsd__sim_1_1_acceleration','struct','Acceleration','msd_sim::Acceleration',NULL,21,'3D acceleration vector type [m/s^2] with transfer object support','Thin wrapper around Vec3DBase providing: Full Eigen matrix operation compatibility fromRecord/toRecord for database serialization std::format support Memory footprint: 24 bytes (same as Eigen::Vector3d)','[''msd_sim::detail::Vec3DBase< Acceleration >'']',1,0);
INSERT INTO "compounds" VALUES (2,'structmsd__transfer_1_1_acceleration_record','struct','AccelerationRecord','msd_transfer::AccelerationRecord',NULL,18,'Database record for a 3D acceleration vector [m/s^2].','Stores the x, y, z components of an msd_sim::Acceleration as individual scalar doubles for human-readable database inspection and queryability.','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (3,'structmsd__sim_1_1_constraint_solver_1_1_active_set_result','struct','ActiveSetResult','msd_sim::ConstraintSolver::ActiveSetResult',NULL,118,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (4,'classmsd__sim_1_1_angular_acceleration','class','AngularAcceleration','msd_sim::AngularAcceleration',NULL,26,'Angular acceleration vector [rad/s^2] without normalization.','Inherits from Eigen::Vector3d for full matrix operation support. Provides semantic pitch/roll/yaw accessors without any normalization. Axis convention (ZYX intrinsic rotation): pitch: Rotation around Y-axis (component 0) roll: Rotation around X-axis (component 1) yaw: Rotation around Z-axis (component 2) Memory footprint: 24 bytes (same as Eigen::Vector3d)','[''Eigen::Vector3d'']',1,0);
INSERT INTO "compounds" VALUES (5,'structmsd__transfer_1_1_angular_acceleration_record','struct','AngularAccelerationRecord','msd_transfer::AngularAccelerationRecord',NULL,19,'Database record for a 3D angular acceleration vector [rad/s^2].','Stores the pitch, roll, yaw components of an msd_sim::AngularAcceleration as individual scalar doubles for human-readable database inspection and queryability.','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (6,'classmsd__sim_1_1_angular_coordinate','class','AngularCoordinate','msd_sim::AngularCoordinate',NULL,43,'Orientation angles with deferred normalization.','Inherits from Eigen::Vector3d for full matrix operation support. Provides semantic pitch/roll/yaw accessors. Normalization strategy: Values are normalized to (-π, π] only when |value| exceeds kNormalizationThreshold Check occurs in assignment and compound operators (+=, -=, *=, /=) Accessors return raw values (fast, no normalization check) Use normalized() or normalize() for explicit normalization to (-π, π] LIMITATION: Direct access via operator[] bypasses normalization. Use semantic accessors ( pitch() , roll() , yaw() ) and setters for normal use. Axis convention (ZYX intrinsic rotation): pitch: Rotation around Y-axis (component 0) roll: Rotation around X-axis (component 1) yaw: Rotation around Z-axis (component 2) Memory footprint: 24 bytes (same as Eigen::Vector3d) docs/designs/0024_angular_coordinate/0024_angular_coordinate.puml Ticket:\n 0024_angular_coordinate','[''Eigen::Vector3d'']',1,0);
INSERT INTO "compounds" VALUES (7,'structmsd__transfer_1_1_angular_coordinate_record','struct','AngularCoordinateRecord','msd_transfer::AngularCoordinateRecord',NULL,26,'Database record for a 3D angular coordinate (orientation angles).','Stores the pitch, roll, yaw components of an msd_sim::AngularCoordinate as individual scalar doubles for human-readable database inspection and queryability. All angles are in radians. Axis convention (ZYX intrinsic rotation): pitch: Rotation around Y-axis roll: Rotation around X-axis yaw: Rotation around Z-axis','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (8,'classmsd__sim_1_1_angular_velocity','class','AngularVelocity','msd_sim::AngularVelocity',NULL,27,'Angular velocity vector [rad/s] without normalization.','Inherits from Eigen::Vector3d for full matrix operation support. Provides semantic pitch/roll/yaw accessors without any normalization. Rates can exceed 2pi rad/s and should not be normalized. Axis convention (ZYX intrinsic rotation): pitch: Rotation around Y-axis (component 0) roll: Rotation around X-axis (component 1) yaw: Rotation around Z-axis (component 2) Memory footprint: 24 bytes (same as Eigen::Vector3d)','[''Eigen::Vector3d'']',1,0);
INSERT INTO "compounds" VALUES (9,'structmsd__transfer_1_1_angular_velocity_record','struct','AngularVelocityRecord','msd_transfer::AngularVelocityRecord',NULL,19,'Database record for a 3D angular velocity vector [rad/s].','Stores the pitch, roll, yaw components of an msd_sim::AngularVelocity as individual scalar doubles for human-readable database inspection and queryability.','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (10,'classmsd__assets_1_1_asset','class','Asset','msd_assets::Asset',NULL,24,'Represents a complete asset with optional visual and collision geometry.','Asset encapsulates an object from the database along with its associated visual and/or collision geometry. Assets are immutable once created and provide access to their geometry components.',NULL,0,0);
INSERT INTO "compounds" VALUES (11,'structmsd__sim_1_1_asset_dynamic_state','struct','AssetDynamicState','msd_sim::AssetDynamicState',NULL,28,'Per-frame mutable state of a dynamic rigid body.','Groups the three quantities that change every simulation frame: Kinematic state (position, velocity, orientation, etc.) Individual external force contributions Individual forces are stored per-entry for diagnostics and recording; use ExternalForce::accumulate() for net force/torque sums. Mirrors the transfer-layer AssetDynamicStateRecord for clean domain ↔ persistence mapping. Ticket:\n 0056h_asset_dynamic_state_struct',NULL,0,0);
INSERT INTO "compounds" VALUES (12,'structmsd__transfer_1_1_asset_dynamic_state_record','struct','AssetDynamicStateRecord','msd_transfer::AssetDynamicStateRecord',NULL,28,'Complete per-frame dynamic state of an AssetInertial.','Captures the full kinematic state (via InertialStateRecord ) plus accumulated force and torque for a single body at a single simulation frame. msd_sim::AssetDynamicState msd_sim::AssetInertial','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (13,'classmsd__sim_1_1_asset_environment','class','AssetEnvironment','msd_sim::AssetEnvironment',NULL,54,'Stationary geometric element with no rigid body dynamics.','AssetEnvironment represents static, immovable objects in the simulation environment. These assets inherit visual geometry, convex hull, and reference frame from AssetPhysical , but have no rigid body properties and cannot be moved by forces or interactions. Key features: Visual geometry for rendering (inherited) Convex hull for collision detection (inherited) Reference frame defining position and orientation (inherited) Always stationary (no dynamics) Lightweight compared to InertialAsset (no mass properties) Provides zero mass/inertia for unified solver path (Ticket 0032) Typical use cases: Terrain and ground surfaces Buildings and structures Static obstacles Environmental boundaries Walls and barriers Usage pattern: auto geometry = std::make_shared<msd_assets::Geometry>(...); ReferenceFrame frame(Coordinate(10, 0, 0)); // Position at x=10 auto asset = AssetEnvironment::create(geometry, frame); // Use for rendering renderer.draw(asset->getVisualGeometry(), asset->getReferenceFrame()); // Use for collision detection if (asset->getCollisionHull().contains(point)) { // Handle collision with static environment } Ticket:\n 0032_contact_constraint_refactor','[''msd_sim::AssetPhysical'']',0,0);
INSERT INTO "compounds" VALUES (14,'classmsd__sim_1_1_asset_inertial','class','AssetInertial','msd_sim::AssetInertial',NULL,53,'Dynamic geometric element with full rigid body physics.','AssetInertial extends AssertPhysical by adding rigid body dynamics properties (mass, inertia tensor, center of mass) and dynamic state (velocities and accelerations). These assets can be acted upon by forces, collide with other objects, and move according to the laws of physics. Key features: Visual geometry for rendering (inherited) Convex hull for collision detection (inherited) Reference frame defining position and orientation (inherited) Rigid body properties (mass, inertia tensor, center of mass) Dynamic state (linear/angular velocity and acceleration) Can participate in physics simulations Automatic mass property computation from geometry Typical use cases: Movable objects (boxes, spheres, etc.) Vehicles and characters Projectiles Debris and destructible objects Any object that responds to forces and collisions Usage pattern: auto geometry = std::make_shared<msd_assets::Geometry>(...); ReferenceFrame frame(Coordinate(5, 0, 10)); // Initial position auto asset = AssetInertial::create(geometry, 50.0, frame); // 50 kg mass // Use for rendering renderer.draw(asset->getVisualGeometry(), asset->getReferenceFrame()); // Use for physics const auto & props = asset->getPhysicsProperties(); asset->getDynamicState().setLinearVelocity(Coordinate(1, 0, 0)); applyForce (force, asset->getReferenceFrame()); // Update position and orientation after physics step asset->getReferenceFrame().setOrigin(newPosition);','[''msd_sim::AssetPhysical'']',0,0);
INSERT INTO "compounds" VALUES (15,'structmsd__transfer_1_1_asset_inertial_static_record','struct','AssetInertialStaticRecord','msd_transfer::AssetInertialStaticRecord',NULL,27,'Per-body user-set physics properties from AssetInertial.','Records the physics properties (mass, restitution, friction) of an inertial asset at spawn time. Unlike per-frame records, this has NO ForeignKey to SimulationFrameRecord . msd_sim::AssetInertial Ticket:\n 0056a_collision_force_transfer_records','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (16,'classmsd__sim_1_1_asset_physical','class','AssetPhysical','msd_sim::AssetPhysical',NULL,43,'Base class for geometric elements in the simulation.','AssetPhysical is the base class for all geometric objects in the simulation, providing visual geometry, collision detection via convex hull, and a reference frame defining position and orientation in world space. This class serves as the foundation for: EnvironmentAsset: Stationary objects with no dynamics InertialAsset: Dynamic objects with rigid body properties Key features: Visual geometry for rendering Convex hull for collision detection (computed lazily) Reference frame defining position and orientation in world space Shared ownership model for efficient memory usage Usage pattern: // Typically used via derived classes EnvironmentAsset or InertialAsset auto geometry = std::make_shared<msd_assets::Geometry>(...); ReferenceFrame frame(Coordinate(10, 0, 0)); auto asset = EnvironmentAsset::create(geometry, frame); // Access base class functionality const auto & hull = asset->getCollisionHull(); const auto & frame = asset->getReferenceFrame();',NULL,0,0);
INSERT INTO "compounds" VALUES (17,'structmsd__transfer_1_1_asset_physical_dynamic_record','struct','AssetPhysicalDynamicRecord','msd_transfer::AssetPhysicalDynamicRecord',NULL,31,'Per-frame position and orientation of an AssetPhysical.','Captures the ReferenceFrame state (origin + quaternion) for any physical asset at a given simulation frame. Enables environment asset replay (environment objects have no InertialState but do have a ReferenceFrame). msd_sim::ReferenceFrame msd_sim::AssetPhysical Ticket:\n 0056a_collision_force_transfer_records','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (18,'structmsd__transfer_1_1_asset_physical_static_record','struct','AssetPhysicalStaticRecord','msd_transfer::AssetPhysicalStaticRecord',NULL,26,'Per-body identity metadata from AssetPhysical.','Records the identity of a physical asset at spawn time: instance ID, reference asset ID, and whether it is an environment object. Unlike per-frame records, this has NO ForeignKey to SimulationFrameRecord . msd_sim::AssetPhysical Ticket:\n 0056a_collision_force_transfer_records','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (19,'classmsd__assets_1_1_asset_registry','class','AssetRegistry','msd_assets::AssetRegistry',NULL,29,'Singleton registry for managing in-memory geometry asset cache.','AssetRegistry provides lazy-loading and caching of geometry assets from the database. Visual meshes are loaded on-demand when first accessed and cached for subsequent use. Thread Safety: All public methods are thread-safe via internal mutex.',NULL,0,0);
INSERT INTO "compounds" VALUES (20,'class_asset_registry_wrapper','class','AssetRegistryWrapper','AssetRegistryWrapper',NULL,21,'Python wrapper for AssetRegistry.','Provides geometry lookup by ObjectRecord.id (asset_id), matching the C++ AssetRegistry::loadCollisionGeometry() interface.',NULL,0,0);
INSERT INTO "compounds" VALUES (21,'structmsd__sim_1_1_asset_static_state','struct','AssetStaticState','msd_sim::AssetStaticState',NULL,24,'Spawn-time static properties of a dynamic rigid body.','Groups the quantities that are set once at construction and do not change per-frame: mass and surface material properties. Mirrors the transfer-layer AssetInertialStaticRecord for clean domain-persistence mapping. Ticket:\n 0056a_collision_force_transfer_records',NULL,0,0);
INSERT INTO "compounds" VALUES (22,'classmsd__sim_1_1_base_agent','class','BaseAgent','msd_sim::BaseAgent',NULL,6,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (23,'classmsd__assets_1_1_base_geometry','class','BaseGeometry','msd_assets::BaseGeometry',NULL,55,'Simple 3D geometry container storing a collection of vertices.','This class represents pure geometry data - just a list of 3D coordinates. It contains no rendering logic or dependencies on graphics APIs. Rendering is handled by the msd-gui layer. Vertices are stored as triangulated mesh data, where each group of 3 vertices represents a triangle.',NULL,0,0);
INSERT INTO "compounds" VALUES (24,'structmsd__sim_1_1_energy_tracker_1_1_body_energy','struct','BodyEnergy','msd_sim::EnergyTracker::BodyEnergy',NULL,43,'Per-body energy breakdown.','',NULL,0,0);
INSERT INTO "compounds" VALUES (25,'structmsd__sim_1_1_constraint_solver_1_1_body_forces','struct','BodyForces','msd_sim::ConstraintSolver::BodyForces',NULL,66,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (26,'structmsd__sim_1_1_projected_gauss_seidel_1_1_body_forces','struct','BodyForces','msd_sim::ProjectedGaussSeidel::BodyForces',NULL,61,'Per-body forces result (mirrors ConstraintSolver::BodyForces ).','',NULL,0,0);
INSERT INTO "compounds" VALUES (27,'structmsd__assets_1_1_bounding_box','struct','BoundingBox','msd_assets::BoundingBox',NULL,28,'Bounding volume metadata for geometry.','',NULL,0,0);
INSERT INTO "compounds" VALUES (28,'structmsd__sim_1_1_convex_hull_1_1_bounding_box','struct','BoundingBox','msd_sim::ConvexHull::BoundingBox',NULL,52,'Axis-aligned bounding box.','',NULL,0,0);
INSERT INTO "compounds" VALUES (29,'structmsd__gui_1_1_g_p_u_manager_1_1_buffer_deleter','struct','BufferDeleter','msd_gui::GPUManager::BufferDeleter',NULL,518,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (30,'structmsd__sim_1_1_cached_contact','struct','CachedContact','msd_sim::CachedContact',NULL,31,'Cached contact data for a single body pair.','Stores the solved lambda values, contact normal, and contact point locations from the previous frame. Used for warm-starting the Active Set Method solver. Extended to track sliding contact state for friction direction alignment. Ticket:\n 0040d_contact_persistence_warm_starting Ticket:\n 0069_friction_velocity_reversal',NULL,0,0);
INSERT INTO "compounds" VALUES (31,'classmsd__gui_1_1_camera3_d','class','Camera3D','msd_gui::Camera3D',NULL,32,'A 3D camera for rendering with perspective projection.','This class references a ReferenceFrame and provides camera-specific functionality including view matrix and projection matrix computation for 3D rendering. It generates the Model-View-Projection (MVP) matrix needed by shaders. The camera uses a right-handed coordinate system with: X: right Y: up Z: forward (out of screen, opposite viewing direction) docs/designs/0005_camera_controller_sim/0005_camera_controller_sim.puml Ticket:\n 0005_camera_controller_sim',NULL,0,0);
INSERT INTO "compounds" VALUES (32,'classmsd__sim_1_1_collision_handler','class','CollisionHandler','msd_sim::CollisionHandler',NULL,31,'Orchestrates collision detection algorithms (GJK/EPA).','Provides a unified interface for collision detection that: Runs GJK to detect intersection If collision detected, runs EPA to compute contact info Returns std::optional to indicate collision presence This abstraction allows future enhancements (broadphase, continuous collision detection, etc.) without changing callers. docs/designs/0027a_expanding_polytope_algorithm/0027a_expanding_polytope_algorithm.puml Ticket:\n 0027a_expanding_polytope_algorithm',NULL,0,0);
INSERT INTO "compounds" VALUES (33,'structmsd__sim_1_1_collision_pipeline_1_1_collision_pair','struct','CollisionPair','msd_sim::CollisionPipeline::CollisionPair',NULL,161,'Collision pair data from last execute() .','Holds body indices, instance IDs, CollisionResult , and material coefficients for a single colliding pair. Data is valid from end of execute() until start of next execute() . collisions_ is owned by the pipeline and cleared at the start of each frame — no intermediate snapshot copy needed. Ticket:\n 0056b_collision_pipeline_data_extraction',NULL,0,0);
INSERT INTO "compounds" VALUES (34,'classmsd__sim_1_1_collision_pipeline','class','CollisionPipeline','msd_sim::CollisionPipeline',NULL,68,'Orchestrates collision response pipeline with warm-starting and position correction.','Extracts the collision detection, constraint creation, solver invocation, cache management, and position correction logic from WorldModel into a dedicated orchestrator class with independently testable phases. The pipeline executes the following phases: Collision Detection — O(n²) pairwise narrow-phase checks Contact Constraint Creation — Factory calls to build ContactConstraint objects Solver Input Assembly — Gathering states, masses, inertias 3.5. Warm-Starting — Query ContactCache for previous frame''s lambdas Constraint Solving — Active Set Method with initial lambda 4.5. Cache Update — Store solved lambdas in ContactCache Force Application — Apply solved constraint forces to inertial bodies Position Correction — Split-impulse penetration correction Design rationale: Separates concerns ( WorldModel manages simulation lifecycle, CollisionPipeline implements collision response algorithm), improves testability (each phase can be unit-tested independently), and enhances extensibility (easier to add broadphase culling or friction). Thread safety: Not thread-safe (contains mutable state in member vectors) Error handling: Empty asset spans handled gracefully (early return) Solver non-convergence propagated from ConstraintSolver No exceptions thrown for normal operation docs/designs/0044_collision_pipeline_integration/0044_collision_pipeline_integration.puml Ticket:\n 0044_collision_pipeline_integration',NULL,0,0);
INSERT INTO "compounds" VALUES (35,'structmsd__sim_1_1_collision_result','struct','CollisionResult','msd_sim::CollisionResult',NULL,106,'Complete collision information for physics response with contact manifold.','This struct is returned by EPA when a collision is detected. It does NOT contain an ''intersecting'' boolean because: CollisionHandler returns std::optional<CollisionResult> std::nullopt indicates no collision Presence of CollisionResult implies collision exists All coordinates are in world space. Contact normal points from object A toward object B. Breaking change (Ticket 0028_epa_witness_points): Replaced single contactPoint with contactPointA and contactPointB Witness points enable accurate torque calculation (τ = r × F) Breaking change (Ticket 0029_contact_manifold_generation): Replaced contactPointA/contactPointB with contacts array Added contactCount field for number of valid contacts [1, 4] Enables multi-point collision response for improved stability docs/designs/0027a_expanding_polytope_algorithm/0027a_expanding_polytope_algorithm.puml docs/designs/0028_epa_witness_points/0028_epa_witness_points.puml docs/designs/0029_contact_manifold_generation/0029_contact_manifold_generation.puml Ticket:\n 0027a_expanding_polytope_algorithm Ticket:\n 0028_epa_witness_points Ticket:\n 0029_contact_manifold_generation',NULL,0,0);
INSERT INTO "compounds" VALUES (36,'structmsd__transfer_1_1_collision_result_record','struct','CollisionResultRecord','msd_transfer::CollisionResultRecord',NULL,33,'Complete collision result record for a body pair at one frame.','Captures collision geometry (normal, penetration depth) and a manifold of up to 4 contact points via a RepeatedField of ContactPointRecord . Body/frame context is stored here; individual ContactPointRecords are pure geometry sub-records. Ticket:\n 0056a_collision_force_transfer_records','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (37,'structmsd__sim_1_1_data_recorder_1_1_config','struct','Config','msd_sim::DataRecorder::Config',NULL,64,'Configuration for DataRecorder behavior.','',NULL,0,0);
INSERT INTO "compounds" VALUES (38,'structmsd__sim_1_1_position_corrector_1_1_config','struct','Config','msd_sim::PositionCorrector::Config',NULL,38,'Configuration parameters for position correction.','',NULL,0,0);
INSERT INTO "compounds" VALUES (39,'classmsd__sim_1_1_constraint','class','Constraint','msd_sim::Constraint',NULL,60,'Abstract base class for constraint definitions in Lagrangian mechanics.','Defines the mathematical interface for arbitrary constraints C(q, t) that can be enforced via Lagrange multipliers. Each constraint implementation provides: Constraint function evaluation C(qA, qB, t) for two bodies Constraint Jacobian J = ∂C/∂q Optional time derivative ∂C/∂t Baumgarte stabilization parameters (α, β) Lagrange multiplier bounds (bilateral/unilateral/box-constrained) Body count and indices for solver dispatch Lagrange multiplier formulation: J·M⁻¹·Jᵀ·λ = -J·M⁻¹·F_ext - J̇·q̇ - α·C - β·Ċ F_constraint = Jᵀ·λ Unified Evaluation Signature: All constraints use a two-body signature evaluate(stateA, stateB, time). Single-body constraints ignore stateB. This eliminates LSP violations and enables polymorphic treatment of all constraint types. Convenience Overloads: Non-virtual convenience methods evaluate(state, time) and jacobian(state, time) delegate to the two-body virtual methods, passing state as both stateA and stateB. Jacobian Column Count: Single-body constraints ( bodyCount() == 1): dimension × 7 (position-level DOFs) Two-body constraints ( bodyCount() == 2): dimension × 12 (velocity-level DOFs) Thread safety: Implementations must be thread-safe for concurrent evaluation (read-only after construction). Error handling: Implementations may throw std::invalid_argument for invalid state or parameters. docs/designs/0043_constraint_hierarchy_refactor/0043_constraint_hierarchy_refactor.puml Ticket:\n 0043_constraint_hierarchy_refactor',NULL,0,1);
INSERT INTO "compounds" VALUES (40,'structmsd__sim_1_1_n_lopt_friction_solver_1_1_constraint_data','struct','ConstraintData','msd_sim::NLoptFrictionSolver::ConstraintData',NULL,150,'Data passed to constraint function.','',NULL,0,0);
INSERT INTO "compounds" VALUES (41,'classmsd__sim_1_1_constraint_island_builder','class','ConstraintIslandBuilder','msd_sim::ConstraintIslandBuilder',NULL,40,'Partitions constraints into independent contact islands via union-find.','Uses union-find (disjoint set) to partition a flat constraint list into independent connected components. Two bodies are connected if they share at least one constraint. Environment bodies (index >= numInertialBodies) are intentionally excluded from connectivity: two inertial bodies touching the same floor remain in separate islands, because environment bodies have infinite mass and are unperturbed by contacts. This is a pure orchestration utility for CollisionPipeline . It produces island subsets that are passed to ConstraintSolver::solve() individually, reducing the effective mass matrix from O((3C)³) global to O(Σᵢ (3Cᵢ)³) per-island. Complexity: O(n · α(n)) where α is the inverse Ackermann function (effectively O(n) total for all operations). Thread safety: Stateless static utility — safe to call from any thread. Error handling: Returns empty vector for empty input. No exceptions thrown. docs/designs/0071a_constraint_solver_scalability/design.md docs/designs/0071a_constraint_solver_scalability/0071a_constraint_solver_scalability.puml Ticket:\n 0071a_constraint_solver_scalability',NULL,0,0);
INSERT INTO "compounds" VALUES (42,'classmsd__sim_1_1_constraint_pool','class','ConstraintPool','msd_sim::ConstraintPool',NULL,56,'Per-frame typed free-list pool for constraint objects.','Maintains two contiguous backing stores — one for ContactConstraint , one for FrictionConstraint . After the first frame the backing vectors have grown to their high-water mark; subsequent reset() calls clear the vectors without releasing capacity, achieving zero heap allocation for constraint objects in steady state. Implementation note: Uses reserve() + emplace_back() + clear() rather than resize() + assignment because ContactConstraint and FrictionConstraint have no default constructors. clear() calls trivial virtual destructors (no owned resources) and preserves capacity, so subsequent emplace_back() calls reuse the allocated memory. Pointer stability: Pointers returned by allocate*() are valid until the next reset() call. Callers must not store pointers across frames. Frame lifecycle (pointer safety guarantee): reset() — clear counts, preserve capacity allocate*() batch — all emplace_back calls for this frame Solver, position correction, recording — read-only pointer usage Next frame — goto 1 There is no interleaving of grow and use within a frame. When the vector must grow (first frame or new high-water mark), all pointers already stored in allConstraints_ from this frame would be invalidated — but because all allocations happen in the createConstraints() batch before any pointer is stored, this is safe. Extensibility: New constraint types (joints, limits) add a new typed backing vector and a corresponding allocate*() method. No changes are needed to existing allocation paths. Thread safety: Not thread-safe (single-threaded physics loop assumed). docs/designs/0071g_constraint_pool_allocation/design.md Ticket:\n 0071g_constraint_pool_allocation',NULL,0,0);
INSERT INTO "compounds" VALUES (43,'classmsd__transfer_1_1_constraint_record_visitor','class','ConstraintRecordVisitor','msd_transfer::ConstraintRecordVisitor',NULL,23,'Visitor interface for type-safe constraint record dispatching.','This interface enables polymorphic constraint recording without dynamic_cast or std::any. Each concrete constraint type calls the appropriate visit() overload, and the compiler enforces that all constraint types are handled. To add a new constraint type: Add new visit(const NewConstraintRecord&) overload to this interface Implement the overload in all concrete visitors (e.g., DataRecorderVisitor) The constraint calls visitor.visit(record) in its recordState() method Compiler will catch missing visit() implementations at build time.',NULL,0,1);
INSERT INTO "compounds" VALUES (44,'classmsd__sim_1_1_constraint_solver','class','ConstraintSolver','msd_sim::ConstraintSolver',NULL,52,'Computes Lagrange multipliers for arbitrary constraint systems.','Dispatches between: Active Set Method (ASM): exact LCP, O(k^3), used when numRows <= kASMThreshold Projected Gauss-Seidel (PGS): approximate, O(n) per sweep, used for large islands Uses constraint flattening to expand multi-row constraints ( FrictionConstraint dim=2) into per-row entries for the friction system. Ticket:\n 0031_generalized_lagrange_constraints Ticket:\n 0052d_solver_integration_ecos_removal Ticket:\n 0073_hybrid_pgs_large_islands',NULL,0,0);
INSERT INTO "compounds" VALUES (45,'classmsd__sim_1_1_contact_cache','class','ContactCache','msd_sim::ContactCache',NULL,61,'Contact cache for warm-starting the constraint solver.','Maps body pairs to their previous frame''s solved contact data (lambda values, contact normals, contact points). When contacts persist between frames, the solver starts from the previous lambda, requiring only small corrections. When contacts change significantly (normal rotation >15°), the cache is invalidated. Cache keying uses a symmetric body pair key: (min(id_A, id_B), max(id_A, id_B)) to ensure body order independence. Thread safety: Not thread-safe (single-threaded simulation) Ticket:\n 0040d_contact_persistence_warm_starting',NULL,0,0);
INSERT INTO "compounds" VALUES (46,'classmsd__sim_1_1_contact_constraint','class','ContactConstraint','msd_sim::ContactConstraint',NULL,50,'Non-penetration unilateral constraint for a single contact point.','Implements the contact constraint C(q) = (x_B - x_A) · n ≥ 0 where: x_A, x_B are contact points on bodies A and B (world space) n is the contact normal (A → B, unit length) Each ContactConstraint has dimension() = 1 (one scalar constraint per contact point). A CollisionResult with contactCount = 4 produces 4 ContactConstraint instances. This follows the math formulation Section 2.5 and provides better stability for resting contacts than a centroid approximation. Design decisions: Pre-computed lever arms: r_A and r_B computed once at construction Stores pre-impact velocity: Relative normal velocity at impact time captured for restitution RHS term Baumgarte parameters: Uses Error Reduction Parameter (ERP) formulation standard in physics engines. Default: ERP = 0.2 (equivalent to α_accel ≈ 781 [1/s²] at 60 FPS). Validated by Prototype P1 parameter sweep. CRITICAL: Restitution formula uses v_target = -e · v_pre (not -(1+e)·v_pre). The constraint RHS for PGS is b = -(1+e) · J·q̇⁻, but the target velocity is -e·v_pre. See P2 Debug Findings for details. Thread safety: Immutable after construction; thread-safe for concurrent reads Error handling: Constructor validates normal is unit length, penetration >= 0, restitution in [0, 1] docs/designs/0032_contact_constraint_refactor/0032_contact_constraint_refactor.puml prototypes/0032_contact_constraint_refactor/p1_pgs_convergence/Debug_Findings.md prototypes/0032_contact_constraint_refactor/p2_energy_conservation/Debug_Findings.md Ticket:\n 0032_contact_constraint_refactor','[''msd_sim::Constraint'']',0,0);
INSERT INTO "compounds" VALUES (47,'structmsd__transfer_1_1_contact_constraint_record','struct','ContactConstraintRecord','msd_transfer::ContactConstraintRecord',NULL,22,'Transfer record for contact constraint state.','Records the geometry and parameters of a contact constraint after constraint creation. Used for debugging constraint solver behavior and validating contact detection. Note: All vector fields (normal, lever arms) are Vector3DRecord (directions), not CoordinateRecord (points), to avoid globalToLocal overload issues.','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (48,'structmsd__sim_1_1_contact_point','struct','ContactPoint','msd_sim::ContactPoint',NULL,37,'A single contact pair within a collision manifold.','Stores contact locations on both object surfaces in world space, along with the penetration depth at this specific contact point. Simple POD struct with value semantics. docs/designs/0029_contact_manifold_generation/0029_contact_manifold_generation.puml docs/designs/0040a-per-contact-penetration-depth/0040a-per-contact-penetration-depth.puml Ticket:\n 0029_contact_manifold_generation Ticket:\n 0040a_per_contact_penetration_depth',NULL,0,0);
INSERT INTO "compounds" VALUES (49,'structmsd__transfer_1_1_contact_point_record','struct','ContactPointRecord','msd_transfer::ContactPointRecord',NULL,28,'Per-contact-point geometry sub-record.','Pure geometry record storing contact locations on both bodies. Body/frame context lives in the parent CollisionResultRecord . Replaces ContactRecord which had body IDs, frame FK, and contact_index baked in as a standalone per-row record. Ticket:\n 0056a_collision_force_transfer_records','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (50,'classmsd__sim_1_1_convex_hull','class','ConvexHull','msd_sim::ConvexHull',NULL,46,'Represents a 3D convex hull for collision detection.','This class wraps Qhull functionality to compute convex hulls from point clouds or geometry objects. It provides the minimal data required for collision detection algorithms ( GJK , EPA , etc.). Key features: Construct from point clouds or msd_assets::Geometry objects Access to hull vertices and facets Point containment testing Support for geometric intersection operations Axis-aligned bounding box for broad-phase collision detection Note: For inertial properties (mass, centroid, moment of inertia), use AssetInertial which contains a ConvexHull along with physics properties.',NULL,0,0);
INSERT INTO "compounds" VALUES (51,'structmsd__sim_1_1_coordinate','struct','Coordinate','msd_sim::Coordinate',NULL,20,'3D spatial coordinate (position in space)','Inherits from msd_sim::Vector3D via Vec3DBase for full matrix operation support. Provides semantic x/y/z accessors and transfer object support. Memory footprint: 24 bytes (same as msd_sim::Vector3D )','[''msd_sim::detail::Vec3DBase< Coordinate >'']',1,0);
INSERT INTO "compounds" VALUES (52,'structmsd__transfer_1_1_coordinate_record','struct','CoordinateRecord','msd_transfer::CoordinateRecord',NULL,18,'Database record for a 3D spatial coordinate.','Stores the x, y, z components of an msd_sim::Coordinate as individual scalar doubles for human-readable database inspection and queryability.','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (53,'class_database_wrapper','class','DatabaseWrapper','DatabaseWrapper',NULL,20,'Python wrapper for cpp_sqlite::Database with read-only queries.','Provides generic select_all() and select_by_id() methods that work with any record type exposed in record_bindings.cpp . For FK-based queries (select_by_frame, select_by_body), uses raw SQL via Database::select<T>().',NULL,0,0);
INSERT INTO "compounds" VALUES (54,'classmsd__sim_1_1_data_recorder','class','DataRecorder','msd_sim::DataRecorder',NULL,58,'Orchestrates background recording of simulation data to SQLite database.','DataRecorder operates on a dedicated background thread, periodically flushing buffered records to disk. Record submission from the simulation thread is thread-safe via cpp_sqlite''s double-buffered DAOs. Architecture: Simulation thread calls recordFrame() to create timestamped frames Simulation thread calls getDAO<T>() .addToBuffer(record) for per-frame data Recorder thread wakes periodically to flush all buffers via transaction Destructor ensures all pending records are written before shutdown docs/designs/0038_simulation_data_recorder/0038_simulation_data_recorder.puml Ticket:\n 0038_simulation_data_recorder',NULL,0,0);
INSERT INTO "compounds" VALUES (55,'classmsd__sim_1_1_data_recorder_visitor','class','DataRecorderVisitor','msd_sim::DataRecorderVisitor',NULL,32,'Concrete visitor that buffers constraint records to DataRecorder DAOs.','Implements the ConstraintRecordVisitor interface to enable type-safe constraint state recording without dynamic_cast or std::any_cast. Each visit() method receives a typed constraint record, sets the frame FK, and buffers it to the appropriate DAO. Usage: DataRecorderVisitor visitor{recorder, frameId}; constraint->recordState(visitor, bodyAId, bodyBId); // Dispatches to appropriate visit() Thread safety: Not thread-safe (caller must ensure DataRecorder thread safety) Error handling: Exceptions from DAO operations propagate to caller msd_transfer::ConstraintRecordVisitor DataRecorder','[''msd_transfer::ConstraintRecordVisitor'']',0,0);
INSERT INTO "compounds" VALUES (56,'classmsd__sim_1_1_distance_constraint','class','DistanceConstraint','msd_sim::DistanceConstraint',NULL,37,'Fixed distance constraint from origin (single-object example).','Maintains the constraint C(X) = |X|² - d² = 0 to keep an object at a fixed distance d from the origin. This is a simplified single-object constraint demonstrating the constraint framework. Multi-object distance constraints (between two objects) are deferred to future ticket 0032. Mathematical formulation: Constraint : C(X) = |X|² - d² = 0 (scalar constraint) Jacobian: J = 2·X^T (1×3 row vector w.r.t. position components) Time derivative: ∂C/∂t = 0 (time-independent) Use cases: Orbital mechanics: fixed orbital radius Pendulum: fixed rod length Tethered objects: cable length constraint Thread safety: Thread-safe for concurrent evaluation after construction Error handling: Throws std::invalid_argument if targetDistance <= 0 docs/designs/0043_constraint_hierarchy_refactor/0043_constraint_hierarchy_refactor.puml Ticket:\n 0043_constraint_hierarchy_refactor','[''msd_sim::Constraint'']',0,0);
INSERT INTO "compounds" VALUES (57,'structmsd__sim_1_1_convex_hull_1_1_edge','struct','Edge','msd_sim::ConvexHull::Edge',NULL,222,'Represents an edge of the convex hull as a pair of vertex coordinates.','Ticket:\n 0040c_edge_contact_manifold',NULL,0,0);
INSERT INTO "compounds" VALUES (58,'structmsd__transfer_1_1_energy_record','struct','EnergyRecord','msd_transfer::EnergyRecord',NULL,35,'Database record for per-body energy values.','Stores computed energy components for a single rigid body at a given simulation frame. Uses ForeignKey<AssetInertialStaticRecord> for body identification and ForeignKey<SimulationFrameRecord> for temporal association with the recording frame. Energy components: linear_ke: Linear kinetic energy KE = 0.5 * m * v^2 [J] rotational_ke: Rotational kinetic energy KE = 0.5 * omega^T * I_world * omega [J] potential_e: Gravitational potential energy PE = -m * (g . r) [J] total_e: Total mechanical energy E = KE_lin + KE_rot + PE [J] msd_sim::EnergyTracker Ticket:\n 0039a_energy_tracking_diagnostic_infrastructure Ticket:\n 0056i_static_asset_recording_and_fk','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (59,'classmsd__sim_1_1_energy_tracker','class','EnergyTracker','msd_sim::EnergyTracker',NULL,37,'Energy computation utility for rigid body diagnostics.','Provides static methods to compute kinetic and potential energy for individual bodies and the entire system. Used by WorldModel to record energy data for collision debugging and anomaly detection. CRITICAL: Rotational kinetic energy uses world-frame inertia tensor: KE_rot = 0.5 * omega^T * I_world * omega where I_world = R * I_body * R^T Using body-frame inertia with world-frame angular velocity produces chaotic-looking energy even when physics are correct. Ticket:\n 0039a_energy_tracking_diagnostic_infrastructure',NULL,0,0);
INSERT INTO "compounds" VALUES (60,'classmsd__sim_1_1_engine','class','Engine','msd_sim::Engine',NULL,29,'Top-level simulation orchestrator.','Coordinates asset loading (via AssetRegistry), world management (via WorldModel ), and physics simulation updates. Provides the primary entry point for spawning objects into the simulation and stepping time forward. Also exposed to Python as msd_reader.Engine via the pybind11 EngineWrapper (see msd-pybind/src/engine_bindings.cpp ). Not thread-safe — single-threaded simulation assumed.',NULL,0,0);
INSERT INTO "compounds" VALUES (61,'class_engine_wrapper','class','EngineWrapper','EngineWrapper',NULL,35,'Python wrapper for msd_sim::Engine .','Converts C++ types (Coordinate, AngularCoordinate, Eigen quaternions) to Python-native dicts/tuples internally. No Eigen type casters are exposed. Follows the DatabaseWrapper / AssetRegistryWrapper pattern: all conversion happens inside the C++ wrapper so the Python API stays simple. Ticket:\n 0072a_engine_pybind_bindings',NULL,0,0);
INSERT INTO "compounds" VALUES (62,'classmsd__sim_1_1_e_p_a','class','EPA','msd_sim::EPA',NULL,66,'Expanding Polytope Algorithm ( EPA ) for contact information extraction.','EPA computes penetration depth, contact normal, and contact point from a GJK terminating simplex. When GJK detects an intersection, EPA expands the terminating simplex (tetrahedron containing the origin) into a polytope until the closest face to the origin is found, yielding complete collision data. Algorithm steps: Initialize polytope from GJK simplex (4 vertices, 4 triangular faces) Find closest face to origin Query support point in direction of face normal If new point within tolerance, found closest face → terminate Else, remove visible faces, build horizon edges, add new faces Repeat until convergence Contact extraction: Contact normal = closest face normal (normalized, A→B) Penetration depth = distance from origin to closest face Contact point = barycentric centroid of closest face docs/designs/0027a_expanding_polytope_algorithm/0027a_expanding_polytope_algorithm.puml Ticket:\n 0027a_expanding_polytope_algorithm',NULL,0,0);
INSERT INTO "compounds" VALUES (63,'structmsd__sim_1_1_e_p_a_1_1_e_p_a_edge','struct','EPAEdge','msd_sim::EPA::EPAEdge',NULL,106,'Edge in polytope for horizon construction.','',NULL,0,0);
INSERT INTO "compounds" VALUES (64,'structmsd__sim_1_1_external_force','struct','ExternalForce','msd_sim::ExternalForce',NULL,21,'A single external force contribution applied to a rigid body.','Stores the linear force, resulting torque, and the world-space application point. Multiple ExternalForce entries are collected per frame; use accumulate() to compute the net result.',NULL,0,0);
INSERT INTO "compounds" VALUES (65,'structmsd__transfer_1_1_external_force_record','struct','ExternalForceRecord','msd_transfer::ExternalForceRecord',NULL,23,'Database record bundling force and torque as composed sub-records.','Groups a ForceVectorRecord and TorqueVectorRecord into a single composite record. Used by AssetDynamicStateRecord to represent the external force/torque accumulator for a rigid body. msd_sim::ExternalForce','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (66,'structmsd__sim_1_1inertial__calculations_1_1_face_integrals','struct','FaceIntegrals','msd_sim::inertial_calculations::FaceIntegrals',NULL,45,'Face integrals computed over 3D surface.','Ticket:\n 0026_mirtich_inertia_tensor',NULL,0,0);
INSERT INTO "compounds" VALUES (67,'structmsd__sim_1_1_facet','struct','Facet','msd_sim::Facet',NULL,19,'Represents a triangular facet of the convex hull.','Each facet stores indices into the hull''s vertex array, along with the outward-facing normal vector.',NULL,0,0);
INSERT INTO "compounds" VALUES (68,'structmsd__sim_1_1_projected_gauss_seidel_1_1_flat_row','struct','FlatRow','msd_sim::ProjectedGaussSeidel::FlatRow',NULL,153,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (69,'structmsd__sim_1_1_constraint_solver_1_1_flattened_constraints','struct','FlattenedConstraints','msd_sim::ConstraintSolver::FlattenedConstraints',NULL,136,'Flattened constraint representation: one Jacobian row per entry.','',NULL,0,0);
INSERT INTO "compounds" VALUES (70,'structmsd__sim_1_1_force_vector','struct','ForceVector','msd_sim::ForceVector',NULL,21,'3D force vector type [N] with transfer object support','Thin wrapper around Vec3DBase providing: Full Eigen matrix operation compatibility fromRecord/toRecord for database serialization std::format support Memory footprint: 24 bytes (same as Eigen::Vector3d)','[''msd_sim::detail::Vec3DBase< ForceVector >'']',1,0);
INSERT INTO "compounds" VALUES (71,'structmsd__transfer_1_1_force_vector_record','struct','ForceVectorRecord','msd_transfer::ForceVectorRecord',NULL,18,'Database record for a 3D force vector [N].','Stores the x, y, z components of an msd_sim::ForceVector as individual scalar doubles for human-readable database inspection and queryability.','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (72,'structstd_1_1formatter_3_01msd__sim_1_1_acceleration_01_4','struct','Acceleration >','std::formatter< msd_sim::Acceleration >',NULL,52,'','','[''msd_sim::detail::Vec3FormatterBase< msd_sim::Acceleration >'']',0,0);
INSERT INTO "compounds" VALUES (73,'structstd_1_1formatter_3_01msd__sim_1_1_angular_acceleration_01_4','struct','AngularAcceleration >','std::formatter< msd_sim::AngularAcceleration >',NULL,122,'','','[''msd_sim::detail::Vec3FormatterBase< msd_sim::AngularAcceleration >'']',0,0);
INSERT INTO "compounds" VALUES (74,'structstd_1_1formatter_3_01msd__sim_1_1_angular_coordinate_01_4','struct','AngularCoordinate >','std::formatter< msd_sim::AngularCoordinate >',NULL,243,'','','[''msd_sim::detail::Vec3FormatterBase< msd_sim::AngularCoordinate >'']',0,0);
INSERT INTO "compounds" VALUES (75,'structstd_1_1formatter_3_01msd__sim_1_1_angular_velocity_01_4','struct','AngularVelocity >','std::formatter< msd_sim::AngularVelocity >',NULL,123,'','','[''msd_sim::detail::Vec3FormatterBase< msd_sim::AngularVelocity >'']',0,0);
INSERT INTO "compounds" VALUES (76,'structstd_1_1formatter_3_01msd__sim_1_1_coordinate_01_4','struct','Coordinate >','std::formatter< msd_sim::Coordinate >',NULL,58,'','','[''msd_sim::detail::Vec3FormatterBase< msd_sim::Coordinate >'']',0,0);
INSERT INTO "compounds" VALUES (77,'structstd_1_1formatter_3_01msd__sim_1_1_force_vector_01_4','struct','ForceVector >','std::formatter< msd_sim::ForceVector >',NULL,51,'','','[''msd_sim::detail::Vec3FormatterBase< msd_sim::ForceVector >'']',0,0);
INSERT INTO "compounds" VALUES (78,'structstd_1_1formatter_3_01msd__sim_1_1_quaternion_d_01_4','struct','QuaternionD >','std::formatter< msd_sim::QuaternionD >',NULL,60,'','','[''msd_sim::detail::Vec4FormatterBase< msd_sim::QuaternionD >'']',0,0);
INSERT INTO "compounds" VALUES (79,'structstd_1_1formatter_3_01msd__sim_1_1_torque_vector_01_4','struct','TorqueVector >','std::formatter< msd_sim::TorqueVector >',NULL,51,'','','[''msd_sim::detail::Vec3FormatterBase< msd_sim::TorqueVector >'']',0,0);
INSERT INTO "compounds" VALUES (80,'structstd_1_1formatter_3_01msd__sim_1_1_vector3_d_01_4','struct','Vector3D >','std::formatter< msd_sim::Vector3D >',NULL,59,'','','[''msd_sim::detail::Vec3FormatterBase< msd_sim::Vector3D >'']',0,0);
INSERT INTO "compounds" VALUES (81,'structstd_1_1formatter_3_01msd__sim_1_1_vector4_d_01_4','struct','Vector4D >','std::formatter< msd_sim::Vector4D >',NULL,69,'','','[''msd_sim::detail::Vec4FormatterBase< msd_sim::Vector4D >'']',0,0);
INSERT INTO "compounds" VALUES (82,'structstd_1_1formatter_3_01msd__sim_1_1_velocity_01_4','struct','Velocity >','std::formatter< msd_sim::Velocity >',NULL,51,'','','[''msd_sim::detail::Vec3FormatterBase< msd_sim::Velocity >'']',0,0);
INSERT INTO "compounds" VALUES (83,'classmsd__sim_1_1_friction_constraint','class','FrictionConstraint','msd_sim::FrictionConstraint',NULL,58,'Friction constraint for two-body contact (two tangential constraint rows).','Implements tangential friction constraints for a contact point using two orthogonal tangent directions. Each FrictionConstraint has dimension() = 2 (one row per tangent). Constraint formulation: C_t1(q) = relative tangential velocity in t1 direction C_t2(q) = relative tangential velocity in t2 direction Jacobian J_ti = [ti^T, (rA×ti)^T, -ti^T, -(rB×ti)^T] ∈ R^(1×12) Box constraints (Coulomb cone projection): -μ/√2 · λn ≤ λt1 ≤ μ/√2 · λn -μ/√2 · λn ≤ λt2 ≤ μ/√2 · λn √2 factor distributes circular cone into two orthogonal box constraints Design notes: Tangent basis computed once at construction via TangentBasis::computeTangentBasis() Friction coefficient μ stored (combined from materials, computed externally) Normal force λn updated each solver iteration via setNormalLambda() Follows same 12-DOF Jacobian structure as ContactConstraint (direct angular velocity) Mathematical formulation: docs/designs/0035_friction_constraints/M2-friction-jacobian.md Thread safety: Immutable after construction except setNormalLambda() (not thread-safe) Error handling: Constructor validates normal unit length, mu in [0, ∞) Constraint ContactConstraint docs/designs/0035a_tangent_basis_and_friction_constraint/0035a_tangent_basis_and_friction_constraint.puml Ticket:\n 0035a_tangent_basis_and_friction_constraint','[''msd_sim::Constraint'']',0,0);
INSERT INTO "compounds" VALUES (84,'structmsd__transfer_1_1_friction_constraint_record','struct','FrictionConstraintRecord','msd_transfer::FrictionConstraintRecord',NULL,23,'Transfer record for friction constraint state.','Records the tangent basis and parameters of a friction constraint after constraint creation. Enables visualization of contact frames (normal + two orthogonal tangents) and debugging of friction force magnitudes. Note: All vector fields (normal, tangents, lever arms) are Vector3DRecord (directions), not CoordinateRecord (points), to avoid globalToLocal overload issues when transforming between reference frames.','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (85,'structmsd__sim_1_1_friction_spec','struct','FrictionSpec','msd_sim::FrictionSpec',NULL,18,'','Friction specification for the cone solver (replaces FrictionConeSpec). Lightweight data structure carrying per-contact friction coefficients and optional tangent1 lower bounds for sliding mode. Ticket:\n 0052b_cone_projection_and_linear_algebra Ticket:\n 0069_friction_velocity_reversal',NULL,0,0);
INSERT INTO "compounds" VALUES (86,'structmsd__gui_1_1_full_transform_instance_data','struct','FullTransformInstanceData','msd_gui::FullTransformInstanceData',NULL,46,'Instance data for PositionRotation3DColorTransform shader (full transform rendering).','Ticket:\n 0002_remove_rotation_from_gpu Stores full 4x4 model matrix, color, and geometry index for each instance. Size: 96 bytes (80 bytes data + 16 bytes padding for 16-byte alignment)',NULL,0,0);
INSERT INTO "compounds" VALUES (87,'classmsd__gui_1_1_full_transform_shader_policy','class','FullTransformShaderPolicy','msd_gui::FullTransformShaderPolicy',NULL,167,'Shader policy for PositionRotation3DColorTransform shader.','Ticket:\n 0002_remove_rotation_from_gpu docs/designs/modularize-gpu-shader-system/modularize-gpu-shader-system.puml Provides configuration for full transform rendering with 4x4 model matrices. Uses PositionRotation3DColorTransform.vert shader which supports translation and rotation. Thread safety: All methods are const and stateless (thread-safe)',NULL,0,0);
INSERT INTO "compounds" VALUES (88,'classmsd__assets_1_1_geometry_factory','class','GeometryFactory','msd_assets::GeometryFactory',NULL,27,'Factory class for creating common 3D geometric shapes.','Provides static template methods to generate MeshRecord or CollisionMeshRecord objects for standard shapes. All geometries are triangulated and centered at the origin. Usage: auto cube = GeometryFactory::createCube<msd_transfer::MeshRecord> (1.0); auto collisionCube = GeometryFactory::createCube<msd_transfer::CollisionMeshRecord> (1.0);',NULL,0,0);
INSERT INTO "compounds" VALUES (89,'structmsd__gui_1_1_geometry_info','struct','GeometryInfo','msd_gui::GeometryInfo',NULL,25,'Geometry registry entry tracking a geometry type''s location within the unified vertex buffer.','Ticket:\n 0001_link-gui-sim-object',NULL,0,0);
INSERT INTO "compounds" VALUES (90,'classmsd__sim_1_1_g_j_k','class','GJK','msd_sim::GJK',NULL,36,'GJK (Gilbert-Johnson-Keerthi) collision detection algorithm.','The GJK algorithm efficiently detects collision between convex shapes by iteratively constructing a simplex in Minkowski difference space that attempts to contain the origin. https://computerwebsite.net/writing/gjk Key insight: Two convex shapes A and B intersect if and only if their Minkowski difference (A ⊖ B) contains the origin. This class maintains the algorithm state (simplex and search direction) as it iterates toward a solution. It works with AssetPhysical objects to support collision detection between objects with arbitrary world-space transformations. docs/designs/0022_gjk_asset_physical_transform/0022_gjk_asset_physical_transform.puml Ticket:\n 0022_gjk_asset_physical_transform',NULL,0,0);
INSERT INTO "compounds" VALUES (91,'classmsd__gui_1_1_g_p_u_manager','class','GPUManager','msd_gui::GPUManager',NULL,49,'Templated GPU manager for SDL GPU rendering with configurable shader policies.','ShaderPolicy Shader policy type (e.g., PositionOnlyShaderPolicy , FullTransformShaderPolicy ) Ticket:\n 0002_remove_rotation_from_gpu docs/designs/modularize-gpu-shader-system/modularize-gpu-shader-system.puml Manages GPU device, pipeline, buffers, and rendering for instanced 3D objects. The shader policy determines vertex attributes, instance data layout, and shader files. Thread safety: Not thread-safe - all operations must occur on the main thread.',NULL,0,0);
INSERT INTO "compounds" VALUES (92,'classmsd__sim_1_1_gravity_potential','class','GravityPotential','msd_sim::GravityPotential',NULL,23,'Uniform gravitational field potential energy.','Implements V = m * g * z where z is the vertical position component. The gravitational vector g is typically (0, 0, -9.81) in z-up convention. Uniform gravity produces constant force F = m*g but no torque (orientation-independent). docs/designs/0030_lagrangian_quaternion_physics/0030_lagrangian_quaternion_physics.puml Ticket:\n 0030_lagrangian_quaternion_physics','[''msd_sim::PotentialEnergy'']',0,0);
INSERT INTO "compounds" VALUES (93,'structmsd__sim_1_1_inertial_state','struct','InertialState','msd_sim::InertialState',NULL,43,'Complete kinematic state representation with 7-state quaternion formulation.','State vector: (X, Q, Ẋ, Q̇) with 14 components total. Contains position, velocity, and acceleration for both linear and angular motion. Uses quaternion representation for orientation to eliminate gimbal lock singularities. Quaternion rate Q̇ is stored directly for efficiency (avoids ω→Q̇ conversion every step). Conversion formulas: Q̇ → ω: ω = 2 * Q̄ ⊗ Q̇ (where Q̄ is conjugate) ω → Q̇: Q̇ = ½ * Q ⊗ [0, ω] docs/designs/0030_lagrangian_quaternion_physics/0030_lagrangian_quaternion_physics.puml Ticket:\n 0030_lagrangian_quaternion_physics',NULL,0,0);
INSERT INTO "compounds" VALUES (94,'structmsd__transfer_1_1_inertial_state_record','struct','InertialStateRecord','msd_transfer::InertialStateRecord',NULL,46,'Database record for complete kinematic state.','Stores the 14-component state vector (X, Q, Ẋ, Q̇) plus acceleration for an msd_sim::InertialState . Uses composition of existing record types for each member. Components: position: 3D spatial coordinate [m] velocity: Linear velocity [m/s] acceleration: Linear acceleration [m/s²] orientation: Unit quaternion (w, x, y, z) quaternionRate: Quaternion time derivative Q̇ angularAcceleration: Angular acceleration [rad/s²] body: Foreign key to AssetInertialStaticRecord for body identification frame: Foreign key to SimulationFrameRecord for timestamping msd_sim::InertialState Ticket:\n 0038_simulation_data_recorder Ticket:\n 0056i_static_asset_recording_and_fk','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (95,'classmsd__gui_1_1_input_binding','class','InputBinding','msd_gui::InputBinding',NULL,43,'Binds a key to an action with specified input mode.','Encapsulates the binding logic separate from state tracking. The shouldTrigger() method implements mode-specific logic (continuous, once, interval). Thread safety: Not thread-safe (assumes single-threaded execution)',NULL,0,0);
INSERT INTO "compounds" VALUES (96,'structmsd__sim_1_1_input_commands','struct','InputCommands','msd_sim::InputCommands',NULL,21,'Plain data structure representing current input command state.','This struct is the bridge between msd-gui (input source) and msd-sim (consumer). It decouples input representation from simulation logic. Boolean flags indicate command state; velocity/force calculation happens in the agent. Extensible for future commands (attack, interact, etc.). Thread safety: Value type (safe to copy)',NULL,0,0);
INSERT INTO "compounds" VALUES (97,'classmsd__sim_1_1_input_control_agent','class','InputControlAgent','msd_sim::InputControlAgent',NULL,29,'Agent implementation that translates InputCommands into InertialState updates.','Implements the BaseAgent interface to fit cleanly into the simulation architecture. Separates input commands from state update logic. Usage flow: GUI calls setInputCommands() with current input state Engine calls updateState() during simulation update Agent translates boolean commands into velocity/acceleration Thread safety: Not thread-safe','[''msd_sim::BaseAgent'']',0,0);
INSERT INTO "compounds" VALUES (98,'classmsd__gui_1_1_input_handler','class','InputHandler','msd_gui::InputHandler',NULL,114,'Manages collection of input bindings and processes them based on InputState .','Central coordination point for input processing. Owns InputState (single source of truth) and evaluates all bindings to execute triggered actions. Thread safety: Not thread-safe',NULL,0,0);
INSERT INTO "compounds" VALUES (99,'classmsd__gui_1_1_input_state','class','InputState','msd_gui::InputState',NULL,37,'Tracks the current state of all keyboard inputs.','Provides centralized input state tracking with timestamp information for duration-based queries. Separates state tracking from input handling logic. Thread safety: Not thread-safe (single-threaded GUI operation assumed)',NULL,0,0);
INSERT INTO "compounds" VALUES (100,'classmsd__gui_1_1_instance_manager','class','InstanceManager','msd_gui::InstanceManager',NULL,32,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (101,'classmsd__sim_1_1_integrator','class','Integrator','msd_sim::Integrator',NULL,39,'Abstract interface for numerical integration of rigid body dynamics.','Decouples the integration scheme from the physics computation, enabling: Swappable integrators (Euler, RK4, Verlet, etc.) Isolated testing of integration math WorldModel as pure orchestrator Ticket 0031 breaking change: Replaced QuaternionConstraint & with std::vector<Constraint*>& to support arbitrary constraint combinations. Thread safety: Implementations should be stateless and thread-safe docs/designs/0030_lagrangian_quaternion_physics/0030_lagrangian_quaternion_physics.puml docs/designs/0031_generalized_lagrange_constraints/0031_generalized_lagrange_constraints.puml Ticket:\n 0030_lagrangian_quaternion_physics Ticket:\n 0031_generalized_lagrange_constraints',NULL,0,1);
INSERT INTO "compounds" VALUES (102,'structmsd__sim_1_1_constraint_island_builder_1_1_island','struct','Island','msd_sim::ConstraintIslandBuilder::Island',NULL,51,'One independent contact island.','An island is a connected component in the contact graph. All constraints in an island share at least one body with another constraint in the same island (via transitive connectivity). Bodies with no contacts do not appear in any island.',NULL,0,0);
INSERT INTO "compounds" VALUES (103,'structmsd__gui_1_1_key_state','struct','KeyState','msd_gui::KeyState',NULL,21,'State information for a single key.','Tracks whether a key is pressed, just pressed (this frame), and timing information for duration-based queries and interval-based triggers.',NULL,0,0);
INSERT INTO "compounds" VALUES (104,'structmsd__sim_1_1_lambda_bounds','struct','LambdaBounds','msd_sim::LambdaBounds',NULL,25,'Represents lower and upper bounds on a constraint''s Lagrange multiplier.','LambdaBounds is a value type that encodes the multiplier bound semantics for different constraint types: Bilateral constraints: λ ∈ (-∞, +∞) — unconstrained multiplier Unilateral constraints: λ ∈ [0, +∞) — non-negative multiplier (inequalities) Box-constrained: λ ∈ [lo, hi] — bounded multiplier (friction cone) Factory methods provide semantic construction, and query methods enable solver dispatch without dynamic_cast. docs/designs/0043_constraint_hierarchy_refactor/0043_constraint_hierarchy_refactor.puml Ticket:\n 0043_constraint_hierarchy_refactor',NULL,0,0);
INSERT INTO "compounds" VALUES (105,'structmsd__sim_1_1_material_properties','struct','MaterialProperties','msd_sim::MaterialProperties',NULL,21,'Surface material properties shared by inertial and environment assets.','Consolidates coefficient of restitution and friction coefficient with validated setters, eliminating duplicated validation logic between AssetInertial and AssetEnvironment . Ticket:\n 0056a_collision_force_transfer_records',NULL,0,0);
INSERT INTO "compounds" VALUES (106,'structmsd__transfer_1_1_material_record','struct','MaterialRecord','msd_transfer::MaterialRecord',NULL,19,'Database record for rendering materials.','Stores shader references and default material properties for rendering. Future extension point for PBR materials, textures, etc.','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (107,'structmsd__transfer_1_1_mesh_record','struct','MeshRecord','msd_transfer::MeshRecord',NULL,21,'Database record for visual mesh geometry.','Stores visual rendering mesh data (positions, normals, colors). This is a standalone table referenced by ObjectRecord .','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (108,'structmsd__sim_1_1_minkowski_vertex','struct','MinkowskiVertex','msd_sim::MinkowskiVertex',NULL,28,'Minkowski difference vertex with witness point tracking.','Used internally by EPA to maintain the association between Minkowski space points and their contributing surface points. This enables extraction of physical contact locations after EPA convergence. Ticket:\n 0028_epa_witness_points',NULL,0,0);
INSERT INTO "compounds" VALUES (109,'classmsd__sim_1_1_motion_controller','class','MotionController','msd_sim::MotionController',NULL,31,'Encapsulates 3D motion control logic for simulation objects.','Translates input commands into ReferenceFrame updates (translation and rotation). Replaces msd-gui::CameraController with simulation-appropriate implementation. Supports frame-rate independent movement through delta-time scaling. Movement is applied in the local coordinate frame of the provided ReferenceFrame . docs/designs/0005_camera_controller_sim/0005_camera_controller_sim.puml Ticket:\n 0005_camera_controller_sim Thread safety: Not thread-safe (modifies ReferenceFrame in place)',NULL,0,0);
INSERT INTO "compounds" VALUES (110,'classmsd__sim_1_1_n_lopt_friction_solver','class','NLoptFrictionSolver','msd_sim::NLoptFrictionSolver',NULL,29,'NLopt-based solver for the friction cone constrained QP.','Solves: minimize f(lambda) = (1/2) lambda^T A lambda - b^T lambda subject to mu_i^2 * lambda_n_i^2 - lambda_t1_i^2 - lambda_t2_i^2 >= 0 (cone constraint) lambda_n_i >= 0 (non-penetration) Uses NLopt''s SLSQP (Sequential Quadratic Programming) by default for efficient handling of quadratic objectives with nonlinear constraints. Supports warm-starting from previous frame''s solution via ContactCache . docs/designs/0068_nlopt_friction_cone_solver/0068_nlopt_friction_cone_solver.puml Ticket:\n 0068b_nlopt_friction_solver_class',NULL,0,0);
INSERT INTO "compounds" VALUES (111,'structmsd__sim_1_1_n_lopt_friction_solver_1_1_objective_data','struct','ObjectiveData','msd_sim::NLoptFrictionSolver::ObjectiveData',NULL,143,'Data passed to objective function.','',NULL,0,0);
INSERT INTO "compounds" VALUES (112,'structmsd__transfer_1_1_object_record','struct','ObjectRecord','msd_transfer::ObjectRecord',NULL,44,'Database record representing a complete object definition.','This is the main record that ties together visual and collision geometry. It contains foreign keys to MeshRecord (visual) and CollisionMeshRecord (collision). Objects can have: Both visual and collision mesh (most common for physics objects) Only visual mesh (visual-only objects, no physics) Only collision mesh (invisible collision volumes)','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (113,'structmsd__sim_1_1_collision_pipeline_1_1_pair_constraint_range','struct','PairConstraintRange','msd_sim::CollisionPipeline::PairConstraintRange',NULL,425,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (114,'structmsd__sim_1_1_contact_cache_1_1_pair_hash','struct','PairHash','msd_sim::ContactCache::PairHash',NULL,199,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (115,'structmsd__transfer_1_1_physics_template_record','struct','PhysicsTemplateRecord','msd_transfer::PhysicsTemplateRecord',NULL,24,'Database record for complete physics object templates.','Combines mesh reference (which contains both visual and collision data) and physical properties (mass, friction, etc.) into a reusable template for creating rigid body instances.','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (116,'structmsd__gui_1_1_g_p_u_manager_1_1_pipeline_deleter','struct','PipelineDeleter','msd_gui::GPUManager::PipelineDeleter',NULL,509,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (117,'classmsd__sim_1_1_platform','class','Platform','msd_sim::Platform',NULL,35,'Platform entity with kinematic state and agent control.','Platform owns an agent that controls its state and optionally links to an Object in WorldModel for visual representation synchronization. Per AC7: Agent logic is placed in Platform (not Object) Per AC3: Each Platform has its own non-unique internal state Thread safety: Not thread-safe',NULL,0,0);
INSERT INTO "compounds" VALUES (118,'classmsd__sim_1_1_position_corrector','class','PositionCorrector','msd_sim::PositionCorrector',NULL,34,'Position-level contact correction using pseudo-velocities.','Corrects penetration depth by computing position-level impulses that modify body positions and orientations without affecting real velocities. This is the position correction pass of the split impulse approach. Algorithm: For each contact, compute position-level bias: b_pos = (beta/dt) * max(depth - slop, 0) Build effective mass matrix A = J * M^-1 * J^T Solve A * lambda_pos = b_pos with lambda_pos >= 0 (using ASM) Compute pseudo-velocity: dv_pseudo = M^-1 * J^T * lambda_pos Apply as position change: dx = dv_pseudo * dt Discard pseudo-velocity (never becomes kinetic energy) Ticket:\n 0040b_split_impulse_position_correction',NULL,0,0);
INSERT INTO "compounds" VALUES (119,'structmsd__gui_1_1_position_only_instance_data','struct','PositionOnlyInstanceData','msd_gui::PositionOnlyInstanceData',NULL,31,'Instance data for Position3DColorTransform shader (position-only rendering).','Ticket:\n 0002_remove_rotation_from_gpu Stores only position offset and color for each instance. No rotation support. Size: 32 bytes (24 bytes data + 8 bytes padding for 16-byte alignment)',NULL,0,0);
INSERT INTO "compounds" VALUES (120,'classmsd__gui_1_1_position_only_shader_policy','class','PositionOnlyShaderPolicy','msd_gui::PositionOnlyShaderPolicy',NULL,66,'Shader policy for Position3DColorTransform shader.','Ticket:\n 0002_remove_rotation_from_gpu docs/designs/modularize-gpu-shader-system/modularize-gpu-shader-system.puml Provides configuration for simple position-offset rendering without rotation. Uses Position3DColorTransform.vert shader which applies only translation to geometry. Thread safety: All methods are const and stateless (thread-safe)',NULL,0,0);
INSERT INTO "compounds" VALUES (121,'classmsd__sim_1_1_potential_energy','class','PotentialEnergy','msd_sim::PotentialEnergy',NULL,34,'Abstract interface for environmental potential energy fields.','This interface enables extensible potential energy computation for rigid body dynamics. Implementations compute generalized forces from energy gradients. Lagrangian formulation: L = T - V where T is kinetic energy, V is potential energy Generalized forces: F = -∂V/∂X (linear force from position gradient) τ = -∂V/∂Q (torque from orientation gradient) Note: These are ENVIRONMENTAL potentials (gravity, magnetic fields) that apply uniformly to all objects. Per-object forces (thrusters, springs) would be handled separately in AssetInertial . Thread safety: Read-only methods after construction (thread-safe) docs/designs/0030_lagrangian_quaternion_physics/0030_lagrangian_quaternion_physics.puml Ticket:\n 0030_lagrangian_quaternion_physics',NULL,0,1);
INSERT INTO "compounds" VALUES (122,'classmsd__sim_1_1_projected_gauss_seidel','class','ProjectedGaussSeidel','msd_sim::ProjectedGaussSeidel',NULL,57,'O(n)-per-sweep iterative LCP solver using Projected Gauss-Seidel.','Used by ConstraintSolver as the solver backend for large constraint islands (numRows > kASMThreshold). PGS has O(n) cost per sweep and scales linearly with problem size, making it ~40x cheaper per sweep than a single ASM pivot at 160 constraints. Algorithm (Catto 2005): For each sweep, for each constraint row i: delta_i = (b_i - J_i * v_res) / A_ii using velocity-residual approach For normal rows: lambda_i = max(0, lambda_i + delta_i) For friction rows: solve both tangent components, then ball-project the 2D tangent vector onto the friction disk ||lambda_t|| <= mu * lambda_n Velocity-residual approach (O(n) workspace): v_res (6 * numBodies doubles) accumulates M^{-1} * J^T * lambda After each lambda update: v_res += M^{-1} * J_i^T * delta_lambda_i Off-diagonal contribution for row i: J_i * v_res Friction coupling (R1 from design review): PGS applies ball-projection directly on friction rows, bypassing FrictionConstraint::lambdaBounds() . The ball-projection cone (||lambda_t|| <= mu*lambda_n) is consistent with the decoupled solver from ticket 0070. setNormalLambda() is NOT called during PGS sweeps. docs/designs/0073_hybrid_pgs_large_islands/design.md Ticket:\n 0073_hybrid_pgs_large_islands',NULL,0,0);
INSERT INTO "compounds" VALUES (123,'structmsd__sim_1_1inertial__calculations_1_1_projection_axes','struct','ProjectionAxes','msd_sim::inertial_calculations::ProjectionAxes',NULL,16,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (124,'structmsd__sim_1_1inertial__calculations_1_1_projection_integrals','struct','ProjectionIntegrals','msd_sim::inertial_calculations::ProjectionIntegrals',NULL,27,'Projection integrals computed over 2D polygon projection.','Ticket:\n 0026_mirtich_inertia_tensor',NULL,0,0);
INSERT INTO "compounds" VALUES (125,'classmsd__sim_1_1detail_1_1_quat_d_base','class','QuatDBase','msd_sim::detail::QuatDBase',NULL,25,'CRTP base class for quaternion types.','Wraps Eigen::Quaterniond via composition (not inheritance, since Eigen::Quaterniond is not a matrix type). Uses Eigen/Hamilton convention: q = w + xi + yj + zk Derived The derived type (CRTP pattern)',NULL,0,0);
INSERT INTO "compounds" VALUES (126,'classmsd__sim_1_1_quaternion_constraint','class','QuaternionConstraint','msd_sim::QuaternionConstraint',NULL,34,'Enforces unit quaternion constraint via Lagrange multipliers.','Maintains the constraint g(Q) = QᵀQ - 1 = 0 using Baumgarte stabilization to correct drift accumulated during numerical integration. Constraint equations: Position: g(Q) = QᵀQ - 1 = 0 Velocity : ġ = 2QᵀQ̇ = 0 (Q̇ ⊥ Q) Baumgarte stabilization computes Lagrange multiplier as: λ = -α * g - β * ġ where α, β > 0 are tuning parameters. Ownership: Each AssetInertial owns its own QuaternionConstraint instance, since the constraint operates on per-object quaternion state. Thread safety: Not thread-safe (modifies quaternion state) docs/designs/0030_lagrangian_quaternion_physics/0030_lagrangian_quaternion_physics.puml Ticket:\n 0030_lagrangian_quaternion_physics',NULL,0,0);
INSERT INTO "compounds" VALUES (127,'structmsd__sim_1_1_quaternion_d','struct','QuaternionD','msd_sim::QuaternionD',NULL,27,'Quaternion type with transfer object support.','Thin wrapper around Eigen::Quaterniond providing: Access to underlying Eigen quaternion via eigen() fromRecord/toRecord for database serialization std::format support Uses Eigen/Hamilton convention: q = w + xi + yj + zk Memory footprint: 32 bytes (same as Eigen::Quaterniond)','[''msd_sim::detail::QuatDBase< QuaternionD >'']',1,0);
INSERT INTO "compounds" VALUES (128,'structmsd__transfer_1_1_quaternion_d_record','struct','QuaternionDRecord','msd_transfer::QuaternionDRecord',NULL,21,'Database record for a quaternion (double precision).','Stores the w, x, y, z components of an msd_sim::QuaternionD as individual scalar doubles for human-readable database inspection and queryability. Uses Eigen/Hamilton convention: q = w + xi + yj + zk where w is the scalar (real) part and (x, y, z) is the vector (imaginary) part.','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (129,'classmsd__sim_1_1_reference_frame','class','ReferenceFrame','msd_sim::ReferenceFrame',NULL,54,'A reference frame for coordinate transformations.','This class represents a reference frame that can be translated and rotated relative to a global frame. It uses AngularCoordinate (pitch, roll, yaw) for rotation specification and provides methods to transform coordinates between the global frame and the local frame. Rotation order: ZYX (yaw-pitch-roll) intrinsic rotations Roll: rotation around X-axis (component 1) Pitch: rotation around Y-axis (component 0) Yaw: rotation around Z-axis (component 2) docs/designs/0024_angular_coordinate/0024_angular_coordinate.puml Ticket:\n 0024_angular_coordinate',NULL,0,0);
INSERT INTO "compounds" VALUES (130,'structmsd__sim_1_1_collision_handler_1_1_s_a_t_result','struct','SATResult','msd_sim::CollisionHandler::SATResult',NULL,65,'SAT result: minimum penetration depth and corresponding normal.','Ticket: 0047_face_contact_manifold_generation',NULL,0,0);
INSERT INTO "compounds" VALUES (131,'classmsd__gui_1_1_s_d_l_application','class','SDLApplication','msd_gui::SDLApplication',NULL,26,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (132,'structmsd__gui_1_1_g_p_u_manager_1_1_s_d_l_device_deleter','struct','SDLDeviceDeleter','msd_gui::GPUManager::SDLDeviceDeleter',NULL,501,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (133,'classmsd__gui_1_1_s_d_l_exception','class','SDLException','msd_gui::SDLException',NULL,12,'','','[''std::runtime_error'']',1,0);
INSERT INTO "compounds" VALUES (134,'structmsd__gui_1_1_s_d_l_application_1_1_s_d_l_window_deleter','struct','SDLWindowDeleter','msd_gui::SDLApplication::SDLWindowDeleter',NULL,55,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (135,'classmsd__sim_1_1_semi_implicit_euler_integrator','class','SemiImplicitEulerIntegrator','msd_sim::SemiImplicitEulerIntegrator',NULL,40,'Semi-implicit Euler integrator (symplectic).','Integration order: Compute accelerations: a = F_ext / m, α = I^-1 * τ_ext Update velocities: v_new = v_old + a * dt Update positions: x_new = x_old + v_new * dt (uses NEW velocity) Integrate quaternion: Q_new = Q_old + Q̇ * dt Normalize quaternion (position-level drift correction) Properties: First-order accurate Symplectic (preserves phase space volume) Better energy conservation than explicit Euler Ticket 0045 breaking change: Removed constraint solving from integrator. Quaternion normalization is now handled via state.orientation.normalize() instead of UnitQuaternionConstraint . docs/designs/0030_lagrangian_quaternion_physics/0030_lagrangian_quaternion_physics.puml docs/designs/0045_constraint_solver_unification/design.md Ticket:\n 0030_lagrangian_quaternion_physics Ticket:\n 0045_constraint_solver_unification','[''msd_sim::Integrator'']',0,0);
INSERT INTO "compounds" VALUES (136,'structmsd__gui_1_1_shader_deleter','struct','ShaderDeleter','msd_gui::ShaderDeleter',NULL,22,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (137,'structmsd__transfer_1_1_simulation_frame_record','struct','SimulationFrameRecord','msd_transfer::SimulationFrameRecord',NULL,26,'Database record for simulation frame timestamping.','Each simulation frame has exactly one SimulationFrameRecord . Per-frame records ( InertialStateRecord , etc.) reference this frame via ForeignKey<SimulationFrameRecord> for temporal association. The id field is inherited from BaseTransferObject and serves as the primary key for frame identification. docs/designs/0038_simulation_data_recorder/0038_simulation_data_recorder.puml Ticket:\n 0038_simulation_data_recorder','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (138,'structmsd__sim_1_1_collision_pipeline_1_1_solver_data','struct','SolverData','msd_sim::CollisionPipeline::SolverData',NULL,76,'Solver diagnostic data captured after constraint solving.','Ticket:\n 0056b_collision_pipeline_data_extraction',NULL,0,0);
INSERT INTO "compounds" VALUES (139,'structmsd__transfer_1_1_solver_diagnostic_record','struct','SolverDiagnosticRecord','msd_transfer::SolverDiagnosticRecord',NULL,25,'Per-frame solver diagnostics.','Records constraint solver statistics for debugging convergence issues and analyzing solver performance. Ticket:\n 0056a_collision_force_transfer_records','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (140,'structmsd__sim_1_1_constraint_solver_1_1_solve_result','struct','SolveResult','msd_sim::ConstraintSolver::SolveResult',NULL,78,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (141,'structmsd__sim_1_1_n_lopt_friction_solver_1_1_solve_result','struct','SolveResult','msd_sim::NLoptFrictionSolver::SolveResult',NULL,42,'Result of the friction cone solve.','',NULL,0,0);
INSERT INTO "compounds" VALUES (142,'structmsd__sim_1_1_projected_gauss_seidel_1_1_solve_result','struct','SolveResult','msd_sim::ProjectedGaussSeidel::SolveResult',NULL,74,'Solve result (mirrors ConstraintSolver::SolveResult fields).','',NULL,0,0);
INSERT INTO "compounds" VALUES (143,'classmsd__assets_1_1_s_t_l_loader','class','STLLoader','msd_assets::STLLoader',NULL,48,'Loader for STL (STereoLithography) 3D model files.','Supports both binary and ASCII STL formats. Binary format is recommended for performance and file size. Binary STL format: 80-byte header (usually ignored) 4-byte unsigned int: triangle count For each triangle (50 bytes total): 12 bytes: normal vector (3 floats) 12 bytes: vertex 1 (3 floats) 12 bytes: vertex 2 (3 floats) 12 bytes: vertex 3 (3 floats) 2 bytes: attribute byte count (usually 0) ASCII STL format: Text-based format starting with "solid <name>" Each triangle defined with "facet normal" and three "vertex" lines Ends with "endsolid <name>"',NULL,0,0);
INSERT INTO "compounds" VALUES (144,'structmsd__assets_1_1_s_t_l_triangle','struct','STLTriangle','msd_assets::STLTriangle',NULL,19,'Data structure representing a single triangle from an STL file.','',NULL,0,0);
INSERT INTO "compounds" VALUES (145,'structmsd__sim_1_1_support_result','struct','SupportResult','msd_sim::SupportResult',NULL,25,'Result of Minkowski support query with witness tracking.','Contains both the Minkowski difference point and the original support points on each object''s surface that contributed to it. All coordinates are in world space. Ticket:\n 0028_epa_witness_points',NULL,0,0);
INSERT INTO "compounds" VALUES (146,'structmsd__sim_1_1_energy_tracker_1_1_system_energy','struct','SystemEnergy','msd_sim::EnergyTracker::SystemEnergy',NULL,71,'System-level energy summary.','',NULL,0,0);
INSERT INTO "compounds" VALUES (147,'structmsd__transfer_1_1_system_energy_record','struct','SystemEnergyRecord','msd_transfer::SystemEnergyRecord',NULL,37,'Database record for system-level energy summary.','Stores aggregated energy values across all rigid bodies for a given simulation frame. Includes energy change detection for anomaly identification during collision debugging. Fields: total_linear_ke: Sum of all body linear kinetic energies [J] total_rotational_ke: Sum of all body rotational kinetic energies [J] total_potential_e: Sum of all body potential energies [J] total_system_e: Total system mechanical energy [J] delta_e: Energy change from previous frame [J] energy_injection: 1 if delta_e exceeds tolerance (anomaly flag) collision_active: 1 if any collision detected this frame energy_injection and collision_active use uint32_t for SQLite compatibility (SQLite has no native boolean type). msd_sim::EnergyTracker Ticket:\n 0039a_energy_tracking_diagnostic_infrastructure','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (148,'structmsd__sim_1_1_tangent_frame','struct','TangentFrame','msd_sim::TangentFrame',NULL,35,'Orthonormal tangent frame {t1, t2} for a contact normal.','Represents the two orthonormal tangent directions perpendicular to a contact normal. Used by FrictionConstraint to define friction constraint directions. Invariants (enforced by TangentBasis::computeTangentBasis): ||t1|| = 1, ||t2|| = 1 (unit length) t1 · t2 = 0 (orthogonal) t1 · n = 0, t2 · n = 0 (perpendicular to normal) Thread safety: Value type, safe to copy across threads Error handling: Constructor validates unit length (throws std::invalid_argument if violated) docs/designs/0035a_tangent_basis_and_friction_constraint/0035a_tangent_basis_and_friction_constraint.puml Ticket:\n 0035a_tangent_basis_and_friction_constraint',NULL,0,0);
INSERT INTO "compounds" VALUES (149,'structmsd__sim_1_1_torque_vector','struct','TorqueVector','msd_sim::TorqueVector',NULL,21,'3D torque vector type [N*m] with transfer object support','Thin wrapper around Vec3DBase providing: Full Eigen matrix operation compatibility fromRecord/toRecord for database serialization std::format support Memory footprint: 24 bytes (same as Eigen::Vector3d)','[''msd_sim::detail::Vec3DBase< TorqueVector >'']',1,0);
INSERT INTO "compounds" VALUES (150,'structmsd__transfer_1_1_torque_vector_record','struct','TorqueVectorRecord','msd_transfer::TorqueVectorRecord',NULL,18,'Database record for a 3D torque vector [N*m].','Stores the x, y, z components of an msd_sim::TorqueVector as individual scalar doubles for human-readable database inspection and queryability.','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (151,'classmsd__sim_1_1_unit_quaternion_constraint','class','UnitQuaternionConstraint','msd_sim::UnitQuaternionConstraint',NULL,36,'Unit quaternion normalization constraint using Lagrange multipliers.','Maintains the constraint g(Q) = Q^T·Q - 1 = 0 to ensure quaternion remains normalized during numerical integration. This is a drop-in replacement for the deprecated QuaternionConstraint , reimplemented using the generalized constraint framework. Mathematical formulation: Constraint : C(Q) = Q^T·Q - 1 = 0 (scalar constraint) Jacobian: J = 2·Q^T (1×4 row vector w.r.t. quaternion components) Time derivative: ∂C/∂t = 0 (time-independent) Baumgarte stabilization: Position term: α·(Q^T·Q - 1) Velocity term: β·(2·Q^T·Q̇) Default parameters: α = 10.0, β = 10.0 (validated for dt ~ 0.016s) Thread safety: Thread-safe for concurrent evaluation after construction Error handling: No exceptions (all quaternion operations numerically stable) docs/designs/0043_constraint_hierarchy_refactor/0043_constraint_hierarchy_refactor.puml Ticket:\n 0043_constraint_hierarchy_refactor','[''msd_sim::Constraint'']',0,0);
INSERT INTO "compounds" VALUES (152,'classmsd__sim_1_1detail_1_1_vec3_d_base','class','Vec3DBase','msd_sim::detail::Vec3DBase',NULL,25,'CRTP base class for 3D vector types.','Provides common functionality for all 3D vector types by inheriting from Eigen::Vector3d. Derived types should use this as: struct MyVec3Type final : Vec3DBase<MyVec3Type> { ... }; Derived The derived type (CRTP pattern)','[''Eigen::Vector3d'']',0,0);
INSERT INTO "compounds" VALUES (153,'structmsd__sim_1_1detail_1_1_vec3_formatter_base','struct','Vec3FormatterBase','msd_sim::detail::Vec3FormatterBase',NULL,17,'','Shared formatter base for 3-component vector types. Provides parse() for [width][.precision][type] format specs and formatComponents() to emit "(c0, c1, c2)" output.',NULL,0,0);
INSERT INTO "compounds" VALUES (154,'classmsd__sim_1_1detail_1_1_vec4_d_base','class','Vec4DBase','msd_sim::detail::Vec4DBase',NULL,25,'CRTP base class for 4D vector types.','Provides common functionality for all 4D vector types by inheriting from Eigen::Vector4d. Derived types should use this as: struct MyVec4Type final : Vec4DBase<MyVec4Type> { ... }; Derived The derived type (CRTP pattern)','[''Eigen::Vector4d'']',0,0);
INSERT INTO "compounds" VALUES (155,'structmsd__sim_1_1detail_1_1_vec4_formatter_base','struct','Vec4FormatterBase','msd_sim::detail::Vec4FormatterBase',NULL,20,'Shared formatter base for 4-component vector types.','Provides parse() for [width][.precision][type] format specs and formatComponents() to emit "(c0, c1, c2, c3)" output.',NULL,0,0);
INSERT INTO "compounds" VALUES (156,'structmsd__sim_1_1_vector3_d','struct','Vector3D','msd_sim::Vector3D',NULL,28,'Generic 3D vector type with transfer object support.','Thin wrapper around msd_sim::Vector3D providing: Full Eigen matrix operation compatibility fromRecord/toRecord for database serialization std::format support Use this type for generic 3D vector data that needs to be recorded/transferred. For semantic types (positions, velocities), prefer the domain-specific types like Coordinate . Memory footprint: 24 bytes (same as msd_sim::Vector3D )','[''msd_sim::detail::Vec3DBase< Vector3D >'']',1,0);
INSERT INTO "compounds" VALUES (157,'structmsd__transfer_1_1_vector3_d_record','struct','Vector3DRecord','msd_transfer::Vector3DRecord',NULL,21,'Database record for a generic 3D vector.','Stores the x, y, z components of an msd_sim::Vector3D as individual scalar doubles for human-readable database inspection and queryability. Use this record for generic 3D vector data. For domain-specific types (positions, velocities), use their respective records ( CoordinateRecord , etc.).','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (158,'structmsd__sim_1_1_vector4_d','struct','Vector4D','msd_sim::Vector4D',NULL,30,'Generic 4D vector type with transfer object support.','Thin wrapper around Eigen::Vector4d providing: Full Eigen matrix operation compatibility fromRecord/toRecord for database serialization std::format support Commonly used for: Quaternions (w, x, y, z) Homogeneous coordinates (x, y, z, w) RGBA colors Memory footprint: 32 bytes (same as Eigen::Vector4d)','[''msd_sim::detail::Vec4DBase< Vector4D >'']',1,0);
INSERT INTO "compounds" VALUES (159,'structmsd__transfer_1_1_vector4_d_record','struct','Vector4DRecord','msd_transfer::Vector4DRecord',NULL,23,'Database record for a generic 4D vector.','Stores the x, y, z, w components of an msd_sim::Vector4D as individual scalar doubles for human-readable database inspection and queryability. Commonly used for: Quaternions (w, x, y, z ordering in physics) Homogeneous coordinates (x, y, z, w) RGBA colors','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (160,'structmsd__sim_1_1_velocity','struct','Velocity','msd_sim::Velocity',NULL,21,'3D velocity vector type [m/s] with transfer object support','Thin wrapper around Vec3DBase providing: Full Eigen matrix operation compatibility fromRecord/toRecord for database serialization std::format support Memory footprint: 24 bytes (same as Eigen::Vector3d)','[''msd_sim::detail::Vec3DBase< Velocity >'']',1,0);
INSERT INTO "compounds" VALUES (161,'structmsd__transfer_1_1_velocity_record','struct','VelocityRecord','msd_transfer::VelocityRecord',NULL,18,'Database record for a 3D velocity vector [m/s].','Stores the x, y, z components of an msd_sim::Velocity as individual scalar doubles for human-readable database inspection and queryability.','[''cpp_sqlite::BaseTransferObject'']',0,0);
INSERT INTO "compounds" VALUES (162,'structmsd__assets_1_1_vertex','struct','Vertex','msd_assets::Vertex',NULL,18,'','',NULL,0,0);
INSERT INTO "compounds" VALUES (163,'classmsd__sim_1_1_world_model','class','WorldModel','msd_sim::WorldModel',NULL,52,'Container and manager for all simulation objects.','WorldModel uses a unified storage approach with index-based iteration for efficient physics updates and collision detection. The WorldModel maintains: A single vector of all objects (graphical, inertial, environmental, boundary) Cached index lists for efficient iteration over specific object types Current simulation time Efficient iteration patterns: // Physics update - only iterate objects with physics for ( size_t idx : worldModel.getPhysicsObjectIndices()) { Object& obj = worldModel.getObject(idx); // Update physics... } // Collision detection - only iterate objects with collision hulls for ( size_t idx : worldModel.getCollisionObjectIndices()) { // Check collisions... } // Rendering - only iterate objects with visual geometry for ( size_t idx : worldModel.getRenderObjectIndices()) { // Render... }',NULL,0,0);
