INSERT INTO "fts_docs" VALUES ('Acceleration','msd_sim::Acceleration','3D acceleration vector type [m/s^2] with transfer object support Thin wrapper around Vec3DBase providing: Full Eigen matrix operation compatibility fromRecord/toRecord for database serialization std::format support Memory footprint: 24 bytes (same as Eigen::Vector3d)');
INSERT INTO "fts_docs" VALUES ('AccelerationRecord','msd_transfer::AccelerationRecord','Database record for a 3D acceleration vector [m/s^2]. Stores the x, y, z components of an msd_sim::Acceleration as individual scalar doubles for human-readable database inspection and queryability.');
INSERT INTO "fts_docs" VALUES ('AngularAcceleration','msd_sim::AngularAcceleration','Angular acceleration vector [rad/s^2] without normalization. Inherits from Eigen::Vector3d for full matrix operation support. Provides semantic pitch/roll/yaw accessors without any normalization. Axis convention (ZYX intrinsic rotation): pitch: Rotation around Y-axis (component 0) roll: Rotation around X-axis (component 1) yaw: Rotation around Z-axis (component 2) Memory footprint: 24 bytes (same as Eigen::Vector3d)');
INSERT INTO "fts_docs" VALUES ('AngularAccelerationRecord','msd_transfer::AngularAccelerationRecord','Database record for a 3D angular acceleration vector [rad/s^2]. Stores the pitch, roll, yaw components of an msd_sim::AngularAcceleration as individual scalar doubles for human-readable database inspection and queryability.');
INSERT INTO "fts_docs" VALUES ('AngularCoordinate','msd_sim::AngularCoordinate','Orientation angles with deferred normalization. Inherits from Eigen::Vector3d for full matrix operation support. Provides semantic pitch/roll/yaw accessors. Normalization strategy: Values are normalized to (-π, π] only when |value| exceeds kNormalizationThreshold Check occurs in assignment and compound operators (+=, -=, *=, /=) Accessors return raw values (fast, no normalization check) Use normalized() or normalize() for explicit normalization to (-π, π] LIMITATION: Direct access via operator[] bypasses normalization. Use semantic accessors ( pitch() , roll() , yaw() ) and setters for normal use. Axis convention (ZYX intrinsic rotation): pitch: Rotation around Y-axis (component 0) roll: Rotation around X-axis (component 1) yaw: Rotation around Z-axis (component 2) Memory footprint: 24 bytes (same as Eigen::Vector3d) docs/designs/0024_angular_coordinate/0024_angular_coordinate.puml Ticket:\n 0024_angular_coordinate');
INSERT INTO "fts_docs" VALUES ('kNormalizationThreshold','msd_sim::AngularCoordinate::kNormalizationThreshold','Normalization threshold (~50 revolutions). Values exceeding this trigger normalization.');
INSERT INTO "fts_docs" VALUES ('normalizeIfNeeded','msd_sim::AngularCoordinate::normalizeIfNeeded','Normalize only if any component exceeds threshold.');
INSERT INTO "fts_docs" VALUES ('normalizeAngle','msd_sim::AngularCoordinate::normalizeAngle','Normalize angle to (-π, π].');
INSERT INTO "fts_docs" VALUES ('AngularCoordinateRecord','msd_transfer::AngularCoordinateRecord','Database record for a 3D angular coordinate (orientation angles). Stores the pitch, roll, yaw components of an msd_sim::AngularCoordinate as individual scalar doubles for human-readable database inspection and queryability. All angles are in radians. Axis convention (ZYX intrinsic rotation): pitch: Rotation around Y-axis roll: Rotation around X-axis yaw: Rotation around Z-axis');
INSERT INTO "fts_docs" VALUES ('AngularVelocity','msd_sim::AngularVelocity','Angular velocity vector [rad/s] without normalization. Inherits from Eigen::Vector3d for full matrix operation support. Provides semantic pitch/roll/yaw accessors without any normalization. Rates can exceed 2pi rad/s and should not be normalized. Axis convention (ZYX intrinsic rotation): pitch: Rotation around Y-axis (component 0) roll: Rotation around X-axis (component 1) yaw: Rotation around Z-axis (component 2) Memory footprint: 24 bytes (same as Eigen::Vector3d)');
INSERT INTO "fts_docs" VALUES ('AngularVelocityRecord','msd_transfer::AngularVelocityRecord','Database record for a 3D angular velocity vector [rad/s]. Stores the pitch, roll, yaw components of an msd_sim::AngularVelocity as individual scalar doubles for human-readable database inspection and queryability.');
INSERT INTO "fts_docs" VALUES ('Asset','msd_assets::Asset','Represents a complete asset with optional visual and collision geometry. Asset encapsulates an object from the database along with its associated visual and/or collision geometry. Assets are immutable once created and provide access to their geometry components.');
INSERT INTO "fts_docs" VALUES ('AssetDynamicState','msd_sim::AssetDynamicState','Per-frame mutable state of a dynamic rigid body. Groups the three quantities that change every simulation frame: Kinematic state (position, velocity, orientation, etc.) Individual external force contributions Individual forces are stored per-entry for diagnostics and recording; use ExternalForce::accumulate() for net force/torque sums. Mirrors the transfer-layer AssetDynamicStateRecord for clean domain ↔ persistence mapping. Ticket:\n 0056h_asset_dynamic_state_struct');
INSERT INTO "fts_docs" VALUES ('clearForces','msd_sim::AssetDynamicState::clearForces','Clear all individual force entries. Called at the end of each physics step after integration.');
INSERT INTO "fts_docs" VALUES ('toRecord','msd_sim::AssetDynamicState::toRecord','Convert to a transfer record for database persistence. Each individual external force is stored as a separate record entry via a one-to-many relationship. bodyId The instance ID of the owning AssetInertial Transfer record containing all dynamic state data');
INSERT INTO "fts_docs" VALUES ('fromRecord','msd_sim::AssetDynamicState::fromRecord','Reconstruct from a transfer record. Each stored force record is reconstructed as an individual entry. record The transfer record to reconstruct from AssetDynamicState with all fields populated');
INSERT INTO "fts_docs" VALUES ('AssetDynamicStateRecord','msd_transfer::AssetDynamicStateRecord','Complete per-frame dynamic state of an AssetInertial. Captures the full kinematic state (via InertialStateRecord ) plus accumulated force and torque for a single body at a single simulation frame. msd_sim::AssetDynamicState msd_sim::AssetInertial');
INSERT INTO "fts_docs" VALUES ('AssetEnvironment','msd_sim::AssetEnvironment','Stationary geometric element with no rigid body dynamics. AssetEnvironment represents static, immovable objects in the simulation environment. These assets inherit visual geometry, convex hull, and reference frame from AssetPhysical , but have no rigid body properties and cannot be moved by forces or interactions. Key features: Visual geometry for rendering (inherited) Convex hull for collision detection (inherited) Reference frame defining position and orientation (inherited) Always stationary (no dynamics) Lightweight compared to InertialAsset (no mass properties) Provides zero mass/inertia for unified solver path (Ticket 0032) Typical use cases: Terrain and ground surfaces Buildings and structures Static obstacles Environmental boundaries Walls and barriers Usage pattern: auto geometry = std::make_shared<msd_assets::Geometry>(...); ReferenceFrame frame(Coordinate(10, 0, 0)); // Position at x=10 auto asset = AssetEnvironment::create(geometry, frame); // Use for rendering renderer.draw(asset->getVisualGeometry(), asset->getReferenceFrame()); // Use for collision detection if (asset->getCollisionHull().contains(point)) { // Handle collision with static environment } Ticket:\n 0032_contact_constraint_refactor');
INSERT INTO "fts_docs" VALUES ('AssetEnvironment','msd_sim::AssetEnvironment::AssetEnvironment','Constructor with default restitution. assetId Asset type ID instanceId Unique instance ID hull Collision hull reference frame Reference frame (position and orientation)');
INSERT INTO "fts_docs" VALUES ('AssetEnvironment','msd_sim::AssetEnvironment::AssetEnvironment','Constructor with custom restitution. assetId Asset type ID instanceId Unique instance ID hull Collision hull reference frame Reference frame (position and orientation) coefficientOfRestitution Coefficient of restitution [0, 1]');
INSERT INTO "fts_docs" VALUES ('AssetEnvironment','msd_sim::AssetEnvironment::AssetEnvironment','Constructor with custom restitution and friction. assetId Asset type ID instanceId Unique instance ID hull Collision hull reference frame Reference frame (position and orientation) coefficientOfRestitution Coefficient of restitution [0, 1] frictionCoefficient Friction coefficient [0, inf) Ticket:\n 0052d_solver_integration_ecos_removal');
INSERT INTO "fts_docs" VALUES ('getInertialState','msd_sim::AssetEnvironment::getInertialState','Get static inertial state (zero velocity). Static state with position from frame, zero velocities');
INSERT INTO "fts_docs" VALUES ('getCoefficientOfRestitution','msd_sim::AssetEnvironment::getCoefficientOfRestitution','Get coefficient of restitution. Coefficient of restitution [0, 1]');
INSERT INTO "fts_docs" VALUES ('setCoefficientOfRestitution','msd_sim::AssetEnvironment::setCoefficientOfRestitution','Set coefficient of restitution. e Coefficient of restitution [0, 1] std::invalid_argument if e not in [0, 1]');
INSERT INTO "fts_docs" VALUES ('getFrictionCoefficient','msd_sim::AssetEnvironment::getFrictionCoefficient','Get friction coefficient. Friction coefficient [0, inf) Ticket:\n 0052d_solver_integration_ecos_removal');
INSERT INTO "fts_docs" VALUES ('setFrictionCoefficient','msd_sim::AssetEnvironment::setFrictionCoefficient','Set friction coefficient. mu Friction coefficient [0, inf) std::invalid_argument if mu < 0 Ticket:\n 0052d_solver_integration_ecos_removal');
INSERT INTO "fts_docs" VALUES ('getInverseMass','msd_sim::AssetEnvironment::getInverseMass','Get inverse mass (infinite mass representation). 0.0 (infinite mass)');
INSERT INTO "fts_docs" VALUES ('getInverseInertiaTensor','msd_sim::AssetEnvironment::getInverseInertiaTensor','Get inverse inertia tensor (infinite inertia representation). Zero matrix (infinite inertia)');
INSERT INTO "fts_docs" VALUES ('AssetInertial','msd_sim::AssetInertial','Dynamic geometric element with full rigid body physics. AssetInertial extends AssertPhysical by adding rigid body dynamics properties (mass, inertia tensor, center of mass) and dynamic state (velocities and accelerations). These assets can be acted upon by forces, collide with other objects, and move according to the laws of physics. Key features: Visual geometry for rendering (inherited) Convex hull for collision detection (inherited) Reference frame defining position and orientation (inherited) Rigid body properties (mass, inertia tensor, center of mass) Dynamic state (linear/angular velocity and acceleration) Can participate in physics simulations Automatic mass property computation from geometry Typical use cases: Movable objects (boxes, spheres, etc.) Vehicles and characters Projectiles Debris and destructible objects Any object that responds to forces and collisions Usage pattern: auto geometry = std::make_shared<msd_assets::Geometry>(...); ReferenceFrame frame(Coordinate(5, 0, 10)); // Initial position auto asset = AssetInertial::create(geometry, 50.0, frame); // 50 kg mass // Use for rendering renderer.draw(asset->getVisualGeometry(), asset->getReferenceFrame()); // Use for physics const auto & props = asset->getPhysicsProperties(); asset->getDynamicState().setLinearVelocity(Coordinate(1, 0, 0)); applyForce (force, asset->getReferenceFrame()); // Update position and orientation after physics step asset->getReferenceFrame().setOrigin(newPosition);');
INSERT INTO "fts_docs" VALUES ('AssetInertial','msd_sim::AssetInertial::AssetInertial','Extended constructor with coefficient of restitution. assetId Asset type identifier instanceId Unique instance identifier hull Reference to collision hull mass Mass in kilograms [kg] frame Initial reference frame (position and orientation) coefficientOfRestitution Elasticity [0, 1] (0=inelastic, 1=elastic) std::invalid_argument if mass <= 0 std::invalid_argument if coefficientOfRestitution ∉ [0, 1] Ticket:\n 0027_collision_response_system');
INSERT INTO "fts_docs" VALUES ('AssetInertial','msd_sim::AssetInertial::AssetInertial','Extended constructor with coefficient of restitution and friction. assetId Asset type identifier instanceId Unique instance identifier hull Reference to collision hull mass Mass in kilograms [kg] frame Initial reference frame (position and orientation) coefficientOfRestitution Elasticity [0, 1] (0=inelastic, 1=elastic) frictionCoefficient Friction coefficient [0, inf) (default: 0.5) std::invalid_argument if mass <= 0 std::invalid_argument if coefficientOfRestitution not in [0, 1] std::invalid_argument if frictionCoefficient < 0 Ticket:\n 0052d_solver_integration_ecos_removal');
INSERT INTO "fts_docs" VALUES ('getDynamicState','msd_sim::AssetInertial::getDynamicState','Get the full dynamic state (mutable version). Provides access to the grouped per-frame state: kinematic state, accumulated force, and accumulated torque. Mutable reference to the dynamic state Ticket:\n 0056h_asset_dynamic_state_struct');
INSERT INTO "fts_docs" VALUES ('getInertialState','msd_sim::AssetInertial::getInertialState','Get the kinematic state (mutable version). Use this to modify velocities and accelerations during physics integration. Mutable reference to the inertial state');
INSERT INTO "fts_docs" VALUES ('getMass','msd_sim::AssetInertial::getMass','Get the current mass. Mass in kilograms [kg]');
INSERT INTO "fts_docs" VALUES ('getInverseMass','msd_sim::AssetInertial::getInverseMass','Get the inverse mass (convenience method). Inverse mass [1/kg] Ticket:\n 0032_contact_constraint_refactor');
INSERT INTO "fts_docs" VALUES ('getInertiaTensor','msd_sim::AssetInertial::getInertiaTensor','Get the inertia tensor about the centroid. 3x3 inertia tensor [kg⋅m²]');
INSERT INTO "fts_docs" VALUES ('getInverseInertiaTensor','msd_sim::AssetInertial::getInverseInertiaTensor','Get the inverse inertia tensor about the centroid (body frame). 3x3 inverse inertia tensor [1/(kg⋅m²)]');
INSERT INTO "fts_docs" VALUES ('getInverseInertiaTensorWorld','msd_sim::AssetInertial::getInverseInertiaTensorWorld','Get the inverse inertia tensor in world frame. Computes I⁻¹_world = R · I⁻¹_body · Rᵀ using the current orientation quaternion. Use this when multiplying with world-frame quantities (torques, angular velocities in world coordinates). 3x3 inverse inertia tensor in world frame [1/(kg⋅m²)] Ticket:\n 0032_contact_constraint_refactor');
INSERT INTO "fts_docs" VALUES ('applyForce','msd_sim::AssetInertial::applyForce','Apply a force at the center of mass. Placeholder implementation for ticket 0023a - only accumulates force. Actual integration will be implemented in ticket 0023. force Force vector in world coordinates [N]');
INSERT INTO "fts_docs" VALUES ('applyForceAtPoint','msd_sim::AssetInertial::applyForceAtPoint','Apply a force at a specific world-space point. Generates torque via τ = r × F, where r is the vector from the center of mass to the application point. Forces at the center of mass generate zero torque. force Force vector in world coordinates [N] worldPoint Application point in world coordinates [m]');
INSERT INTO "fts_docs" VALUES ('applyTorque','msd_sim::AssetInertial::applyTorque','Apply a torque about the center of mass. Placeholder implementation for ticket 0023a - only accumulates torque. torque Torque vector in world coordinates [N·m]');
INSERT INTO "fts_docs" VALUES ('clearForces','msd_sim::AssetInertial::clearForces','Clear all accumulated forces and torques. Call this at the end of each physics step after integration.');
INSERT INTO "fts_docs" VALUES ('getAccumulatedForce','msd_sim::AssetInertial::getAccumulatedForce','Get the accumulated force for this frame. Accumulated force vector [N]');
INSERT INTO "fts_docs" VALUES ('getAccumulatedTorque','msd_sim::AssetInertial::getAccumulatedTorque','Get the accumulated torque for this frame. Accumulated torque vector [N·m]');
INSERT INTO "fts_docs" VALUES ('getCoefficientOfRestitution','msd_sim::AssetInertial::getCoefficientOfRestitution','Get the coefficient of restitution. Determines elasticity of collisions: 0.0: Fully inelastic (objects stick together) 0.5: Moderate elasticity (default) 1.0: Fully elastic (perfect bounce) Coefficient of restitution [0, 1]');
INSERT INTO "fts_docs" VALUES ('setCoefficientOfRestitution','msd_sim::AssetInertial::setCoefficientOfRestitution','Set the coefficient of restitution. e Coefficient of restitution [0, 1] std::invalid_argument if e < 0.0 or e > 1.0 Ticket:\n 0027_collision_response_system');
INSERT INTO "fts_docs" VALUES ('getFrictionCoefficient','msd_sim::AssetInertial::getFrictionCoefficient','Get the friction coefficient. Determines tangential friction force magnitude: 0.0: Frictionless surface (ice) 0.5: Moderate friction (default) 1.0+: High friction (rubber) Friction coefficient [0, inf) Ticket:\n 0052d_solver_integration_ecos_removal');
INSERT INTO "fts_docs" VALUES ('setFrictionCoefficient','msd_sim::AssetInertial::setFrictionCoefficient','Set the friction coefficient. mu Friction coefficient [0, inf) std::invalid_argument if mu < 0 Ticket:\n 0052d_solver_integration_ecos_removal');
INSERT INTO "fts_docs" VALUES ('applyImpulse','msd_sim::AssetInertial::applyImpulse','Apply an instantaneous linear impulse at the center of mass. Unlike forces which are accumulated and integrated over time, impulses directly modify velocity: Δv = J / m This is used for collision response where velocity changes must be timestep-independent. impulse Impulse vector in world coordinates [N·s] Ticket:\n 0027_collision_response_system');
INSERT INTO "fts_docs" VALUES ('applyAngularImpulse','msd_sim::AssetInertial::applyAngularImpulse','Apply an instantaneous angular impulse. Unlike torques which are accumulated and integrated over time, angular impulses directly modify angular velocity: Δω = I⁻¹ * L This is used for collision response where angular velocity changes must be timestep-independent. angularImpulse Angular impulse vector in world coordinates [N·m·s] Ticket:\n 0027_collision_response_system');
INSERT INTO "fts_docs" VALUES ('toDynamicStateRecord','msd_sim::AssetInertial::toDynamicStateRecord','Convert dynamic state to a database record. Captures the complete per-frame dynamic state: kinematic state (position, velocity, acceleration, orientation, quaternion rate, angular acceleration) plus accumulated force and torque. Transfer record containing all dynamic state data');
INSERT INTO "fts_docs" VALUES ('toStaticRecord','msd_sim::AssetInertial::toStaticRecord','Convert physics properties to a spawn-time static record. Captures mass, restitution, and friction for this inertial asset. Transfer record with body_id, mass, restitution, friction Ticket:\n 0056a_collision_force_transfer_records');
INSERT INTO "fts_docs" VALUES ('AssetInertialStaticRecord','msd_transfer::AssetInertialStaticRecord','Per-body user-set physics properties from AssetInertial. Records the physics properties (mass, restitution, friction) of an inertial asset at spawn time. Unlike per-frame records, this has NO ForeignKey to SimulationFrameRecord . msd_sim::AssetInertial Ticket:\n 0056a_collision_force_transfer_records');
INSERT INTO "fts_docs" VALUES ('AssetPhysical','msd_sim::AssetPhysical','Base class for geometric elements in the simulation. AssetPhysical is the base class for all geometric objects in the simulation, providing visual geometry, collision detection via convex hull, and a reference frame defining position and orientation in world space. This class serves as the foundation for: EnvironmentAsset: Stationary objects with no dynamics InertialAsset: Dynamic objects with rigid body properties Key features: Visual geometry for rendering Convex hull for collision detection (computed lazily) Reference frame defining position and orientation in world space Shared ownership model for efficient memory usage Usage pattern: // Typically used via derived classes EnvironmentAsset or InertialAsset auto geometry = std::make_shared<msd_assets::Geometry>(...); ReferenceFrame frame(Coordinate(10, 0, 0)); auto asset = EnvironmentAsset::create(geometry, frame); // Access base class functionality const auto & hull = asset->getCollisionHull(); const auto & frame = asset->getReferenceFrame();');
INSERT INTO "fts_docs" VALUES ('AssetPhysical','msd_sim::AssetPhysical::AssetPhysical','Protected constructor - use derived class factory methods. geometry Shared pointer to visual geometry customHull Optional custom collision hull (if null, computed from geometry)');
INSERT INTO "fts_docs" VALUES ('~AssetPhysical','msd_sim::AssetPhysical::~AssetPhysical','Virtual destructor for proper cleanup of derived classes.');
INSERT INTO "fts_docs" VALUES ('getCollisionHull','msd_sim::AssetPhysical::getCollisionHull','Get the collision hull for collision detection. If the hull hasn''t been computed yet (deferred computation), this will compute it on first access. Reference to the collision convex hull std::runtime_error if hull computation fails');
INSERT INTO "fts_docs" VALUES ('getReferenceFrame','msd_sim::AssetPhysical::getReferenceFrame','Get the reference frame defining position and orientation. Reference to the reference frame');
INSERT INTO "fts_docs" VALUES ('getReferenceFrame','msd_sim::AssetPhysical::getReferenceFrame','Get the reference frame (mutable version). Use this to modify the asset''s position and orientation. Mutable reference to the reference frame');
INSERT INTO "fts_docs" VALUES ('toStaticRecord','msd_sim::AssetPhysical::toStaticRecord','Convert identity to a spawn-time static record. isEnvironment true for AssetEnvironment , false for AssetInertial Transfer record with body_id, asset_id, and is_environment flag Ticket:\n 0056a_collision_force_transfer_records');
INSERT INTO "fts_docs" VALUES ('AssetPhysicalDynamicRecord','msd_transfer::AssetPhysicalDynamicRecord','Per-frame position and orientation of an AssetPhysical. Captures the ReferenceFrame state (origin + quaternion) for any physical asset at a given simulation frame. Enables environment asset replay (environment objects have no InertialState but do have a ReferenceFrame). msd_sim::ReferenceFrame msd_sim::AssetPhysical Ticket:\n 0056a_collision_force_transfer_records');
INSERT INTO "fts_docs" VALUES ('AssetPhysicalStaticRecord','msd_transfer::AssetPhysicalStaticRecord','Per-body identity metadata from AssetPhysical. Records the identity of a physical asset at spawn time: instance ID, reference asset ID, and whether it is an environment object. Unlike per-frame records, this has NO ForeignKey to SimulationFrameRecord . msd_sim::AssetPhysical Ticket:\n 0056a_collision_force_transfer_records');
INSERT INTO "fts_docs" VALUES ('AssetRegistry','msd_assets::AssetRegistry','Singleton registry for managing in-memory geometry asset cache. AssetRegistry provides lazy-loading and caching of geometry assets from the database. Visual meshes are loaded on-demand when first accessed and cached for subsequent use. Thread Safety: All public methods are thread-safe via internal mutex.');
INSERT INTO "fts_docs" VALUES ('getAsset','msd_assets::AssetRegistry::getAsset','Load asset from database (lazy-loaded and cached). assetId ID of the asset to load Optional reference to cached asset, std::nullopt if asset not found');
INSERT INTO "fts_docs" VALUES ('getAsset','msd_assets::AssetRegistry::getAsset','Load asset from database (lazy-loaded and cached). assetId ID of the asset to load Optional reference to cached asset, std::nullopt if asset not found');
INSERT INTO "fts_docs" VALUES ('loadVisualGeometry','msd_assets::AssetRegistry::loadVisualGeometry','Load visual geometry from database (lazy-loaded and cached). assetId ID of the asset to load visual mesh for Optional reference to cached visual geometry, std::nullopt if asset not found or has no visual mesh');
INSERT INTO "fts_docs" VALUES ('loadCollisionGeometry','msd_assets::AssetRegistry::loadCollisionGeometry','Load collision geometry from database (lazy-loaded and cached). assetId ID of the asset to load collision mesh for Optional reference to cached collision geometry, std::nullopt if asset not found or has no collision mesh');
INSERT INTO "fts_docs" VALUES ('getCacheMemoryUsage','msd_assets::AssetRegistry::getCacheMemoryUsage','Estimate current cache memory usage. Approximate memory usage in bytes');
INSERT INTO "fts_docs" VALUES ('loadFromDatabase','msd_assets::AssetRegistry::loadFromDatabase','Initialize registry with database connection. dbPath Path to SQLite database file');
INSERT INTO "fts_docs" VALUES ('findAssetById','msd_assets::AssetRegistry::findAssetById','Find asset in cache by ID. assetId ID of the asset to find Iterator to the asset, or assetCache_.end() if not found');
INSERT INTO "fts_docs" VALUES ('findAssetByName','msd_assets::AssetRegistry::findAssetByName','Find asset in cache by name. assetName Name of the asset to find Iterator to the asset, or assetCache_.end() if not found');
INSERT INTO "fts_docs" VALUES ('AssetRegistryWrapper','AssetRegistryWrapper','Python wrapper for AssetRegistry. Provides geometry lookup by ObjectRecord.id (asset_id), matching the C++ AssetRegistry::loadCollisionGeometry() interface.');
INSERT INTO "fts_docs" VALUES ('getCollisionVertices','AssetRegistryWrapper::getCollisionVertices','Get collision vertices for an asset by ObjectRecord.id. assetId ObjectRecord.id (maps to AssetPhysicalStaticRecord.asset_id) List of (x, y, z) tuples, or empty list if asset not found');
INSERT INTO "fts_docs" VALUES ('getAssetName','AssetRegistryWrapper::getAssetName','Get asset name by ObjectRecord.id. assetId ObjectRecord.id Asset name, or empty string if not found');
INSERT INTO "fts_docs" VALUES ('listAssets','AssetRegistryWrapper::listAssets','List all available asset IDs and names. List of (id, name) pairs');
INSERT INTO "fts_docs" VALUES ('AssetStaticState','msd_sim::AssetStaticState','Spawn-time static properties of a dynamic rigid body. Groups the quantities that are set once at construction and do not change per-frame: mass and surface material properties. Mirrors the transfer-layer AssetInertialStaticRecord for clean domain-persistence mapping. Ticket:\n 0056a_collision_force_transfer_records');
INSERT INTO "fts_docs" VALUES ('toRecord','msd_sim::AssetStaticState::toRecord','Convert to a transfer record for database persistence. bodyId The instance ID of the owning AssetInertial Transfer record with body_id, mass, restitution, friction');
INSERT INTO "fts_docs" VALUES ('fromRecord','msd_sim::AssetStaticState::fromRecord','Reconstruct from a transfer record. record The transfer record to reconstruct from AssetStaticState with all fields populated');
INSERT INTO "fts_docs" VALUES ('BaseGeometry','msd_assets::BaseGeometry','Simple 3D geometry container storing a collection of vertices. This class represents pure geometry data - just a list of 3D coordinates. It contains no rendering logic or dependencies on graphics APIs. Rendering is handled by the msd-gui layer. Vertices are stored as triangulated mesh data, where each group of 3 vertices represents a triangle.');
INSERT INTO "fts_docs" VALUES ('BaseGeometry','msd_assets::BaseGeometry::BaseGeometry','Constructor from raw coordinate data. rawVertices Vector of 3D coordinates ( msd_sim::Vector3D ) objectId Unique identifier for the geometry For VisualGeometry (T= Vertex ): Computes normals and converts to Vertex format. For CollisionGeometry (T= msd_sim::Vector3D ): Stores raw vertices directly.');
INSERT INTO "fts_docs" VALUES ('BaseGeometry','msd_assets::BaseGeometry::BaseGeometry','Constructor from MeshRecord blob. record MeshRecord containing serialized vertex data objectId Unique identifier for the geometry Deserializes vertex data from the MeshRecord''s vertex_data blob. The blob must contain data in the correct format for type T: For VisualGeometry (T= Vertex ): blob contains Vertex structs (36 bytes) For CollisionGeometry (T= msd_sim::Vector3D ): blob contains msd_sim::Vector3d (24 bytes)');
INSERT INTO "fts_docs" VALUES ('getVertexCount','msd_assets::BaseGeometry::getVertexCount','Get number of vertices. Number of vertices in the cached vertex data');
INSERT INTO "fts_docs" VALUES ('serializeVertices','msd_assets::BaseGeometry::serializeVertices','Serialize geometry to binary BLOB for database storage. Binary representation of Coordinate array (x, y, z positions) BLOB format: [x1,y1,z1][x2,y2,z2]...[xN,yN,zN] Each Coordinate is 24 bytes: 3 doubles × 8 bytes Colors and normals are computed on-demand via toGUIVertices()');
INSERT INTO "fts_docs" VALUES ('getVertices','msd_assets::BaseGeometry::getVertices','Get cached GUI vertices (positions + normals, no color). Const reference to cached vertex data Lazily computes and caches vertex data on first access. Use toGUIVertices() if you need to apply colors.');
INSERT INTO "fts_docs" VALUES ('populateMeshRecord','msd_assets::BaseGeometry::populateMeshRecord','Populate MeshRecord with geometry data. record MeshRecord to populate Populates vertex_data and bounding box metadata. Note: Does not populate hull_data - use ConvexHull::serializeToBlob() separately.');
INSERT INTO "fts_docs" VALUES ('BodyEnergy','msd_sim::EnergyTracker::BodyEnergy','Per-body energy breakdown.');
INSERT INTO "fts_docs" VALUES ('total','msd_sim::EnergyTracker::BodyEnergy::total','Total mechanical energy for this body. linearKE + rotationalKE + potentialE [J]');
INSERT INTO "fts_docs" VALUES ('toRecord','msd_sim::EnergyTracker::BodyEnergy::toRecord','Convert to database record. frameId Frame ID for foreign key bodyId Stable body identifier EnergyRecord for database insertion');
INSERT INTO "fts_docs" VALUES ('BodyForces','msd_sim::ProjectedGaussSeidel::BodyForces','Per-body forces result (mirrors ConstraintSolver::BodyForces ).');
INSERT INTO "fts_docs" VALUES ('BoundingBox','msd_assets::BoundingBox','Bounding volume metadata for geometry.');
INSERT INTO "fts_docs" VALUES ('BoundingBox','msd_sim::ConvexHull::BoundingBox','Axis-aligned bounding box.');
INSERT INTO "fts_docs" VALUES ('CachedContact','msd_sim::CachedContact','Cached contact data for a single body pair. Stores the solved lambda values, contact normal, and contact point locations from the previous frame. Used for warm-starting the Active Set Method solver. Extended to track sliding contact state for friction direction alignment. Ticket:\n 0040d_contact_persistence_warm_starting Ticket:\n 0069_friction_velocity_reversal');
INSERT INTO "fts_docs" VALUES ('Camera3D','msd_gui::Camera3D','A 3D camera for rendering with perspective projection. This class references a ReferenceFrame and provides camera-specific functionality including view matrix and projection matrix computation for 3D rendering. It generates the Model-View-Projection (MVP) matrix needed by shaders. The camera uses a right-handed coordinate system with: X: right Y: up Z: forward (out of screen, opposite viewing direction) docs/designs/0005_camera_controller_sim/0005_camera_controller_sim.puml Ticket:\n 0005_camera_controller_sim');
INSERT INTO "fts_docs" VALUES ('frame_','msd_gui::Camera3D::frame_','Non-owning reference to camera''s reference frame.');
INSERT INTO "fts_docs" VALUES ('fovRadians_','msd_gui::Camera3D::fovRadians_','Vertical field of view in radians.');
INSERT INTO "fts_docs" VALUES ('aspectRatio_','msd_gui::Camera3D::aspectRatio_','Width/height ratio.');
INSERT INTO "fts_docs" VALUES ('nearPlane_','msd_gui::Camera3D::nearPlane_','Near clipping plane distance.');
INSERT INTO "fts_docs" VALUES ('farPlane_','msd_gui::Camera3D::farPlane_','Far clipping plane distance.');
INSERT INTO "fts_docs" VALUES ('Camera3D','msd_gui::Camera3D::Camera3D','Constructor with reference frame, field of view, and aspect ratio. referenceFrame Reference to external ReferenceFrame (non-owning) fovDegrees Vertical field of view in degrees (default: 60) aspectRatio Width/height ratio (default: 16/9) nearPlane Near clipping plane distance (default: 0.1) farPlane Far clipping plane distance (default: 100.0) NOTE: The provided ReferenceFrame must outlive this Camera3D instance. Typically the ReferenceFrame is owned by a Platform''s visual Object.');
INSERT INTO "fts_docs" VALUES ('getReferenceFrame','msd_gui::Camera3D::getReferenceFrame','Get the underlying reference frame. Reference to the camera''s reference frame');
INSERT INTO "fts_docs" VALUES ('getReferenceFrame','msd_gui::Camera3D::getReferenceFrame','Get the underlying reference frame (const version). Const reference to the camera''s reference frame');
INSERT INTO "fts_docs" VALUES ('setAspectRatio','msd_gui::Camera3D::setAspectRatio','Set the aspect ratio (width/height). aspectRatio New aspect ratio');
INSERT INTO "fts_docs" VALUES ('setFieldOfView','msd_gui::Camera3D::setFieldOfView','Set the field of view. fovDegrees Vertical field of view in degrees');
INSERT INTO "fts_docs" VALUES ('setClippingPlanes','msd_gui::Camera3D::setClippingPlanes','Set the near and far clipping planes. nearPlane Near clipping plane distance farPlane Far clipping plane distance');
INSERT INTO "fts_docs" VALUES ('getViewMatrix','msd_gui::Camera3D::getViewMatrix','Get the view matrix (transforms from world space to camera space). 4x4 view matrix in single precision (column-major)');
INSERT INTO "fts_docs" VALUES ('getProjectionMatrix','msd_gui::Camera3D::getProjectionMatrix','Get the projection matrix (perspective projection). 4x4 projection matrix in single precision (column-major)');
INSERT INTO "fts_docs" VALUES ('getMVPMatrix','msd_gui::Camera3D::getMVPMatrix','Get the combined Model-View-Projection matrix. modelMatrix Optional model matrix (default: identity) 4x4 MVP matrix in single precision (column-major)');
INSERT INTO "fts_docs" VALUES ('CollisionHandler','msd_sim::CollisionHandler','Orchestrates collision detection algorithms (GJK/EPA). Provides a unified interface for collision detection that: Runs GJK to detect intersection If collision detected, runs EPA to compute contact info Returns std::optional to indicate collision presence This abstraction allows future enhancements (broadphase, continuous collision detection, etc.) without changing callers. docs/designs/0027a_expanding_polytope_algorithm/0027a_expanding_polytope_algorithm.puml Ticket:\n 0027a_expanding_polytope_algorithm');
INSERT INTO "fts_docs" VALUES ('CollisionHandler','msd_sim::CollisionHandler::CollisionHandler','Construct handler with specified tolerance. epsilon Numerical tolerance for GJK/EPA (default: 1e-6)');
INSERT INTO "fts_docs" VALUES ('checkCollision','msd_sim::CollisionHandler::checkCollision','Check for collision between two physical assets. Runs GJK to detect intersection. If collision detected, runs EPA to compute penetration depth, contact normal, and contact point. assetA First physical asset assetB Second physical asset skipSATValidation If true, skip SAT validation of EPA result. Use when ContactCache confirms persistent contact with stable normal, making EPA failure unlikely. Ticket: 0053d_sat_fallback_cost_reduction std::nullopt if no collision, CollisionResult if collision');
INSERT INTO "fts_docs" VALUES ('computeSATMinPenetration','msd_sim::CollisionHandler::computeSATMinPenetration','Compute minimum penetration depth and direction using SAT. Ticket: 0047_face_contact_manifold_generation Iterates over all unique face normals of both hulls and computes the overlap (penetration depth) along each. Returns the minimum depth and the corresponding face normal. Used to validate and correct EPA results — EPA can produce wrong results at zero or near-zero penetration when the Minkowski difference origin is on the boundary.');
INSERT INTO "fts_docs" VALUES ('buildSATContact','msd_sim::CollisionHandler::buildSATContact','Build a CollisionResult from SAT data when EPA fails. Ticket: 0047_face_contact_manifold_generation When EPA picks the wrong face (depth wildly inconsistent with SAT), construct a valid contact using the SAT normal and depth with witness points from the support function.');
INSERT INTO "fts_docs" VALUES ('CollisionPair','msd_sim::CollisionPipeline::CollisionPair','Collision pair data from last execute() . Holds body indices, instance IDs, CollisionResult , and material coefficients for a single colliding pair. Data is valid from end of execute() until start of next execute() . collisions_ is owned by the pipeline and cleared at the start of each frame — no intermediate snapshot copy needed. Ticket:\n 0056b_collision_pipeline_data_extraction');
INSERT INTO "fts_docs" VALUES ('CollisionPipeline','msd_sim::CollisionPipeline','Orchestrates collision response pipeline with warm-starting and position correction. Extracts the collision detection, constraint creation, solver invocation, cache management, and position correction logic from WorldModel into a dedicated orchestrator class with independently testable phases. The pipeline executes the following phases: Collision Detection — O(n²) pairwise narrow-phase checks Contact Constraint Creation — Factory calls to build ContactConstraint objects Solver Input Assembly — Gathering states, masses, inertias 3.5. Warm-Starting — Query ContactCache for previous frame''s lambdas Constraint Solving — Active Set Method with initial lambda 4.5. Cache Update — Store solved lambdas in ContactCache Force Application — Apply solved constraint forces to inertial bodies Position Correction — Split-impulse penetration correction Design rationale: Separates concerns ( WorldModel manages simulation lifecycle, CollisionPipeline implements collision response algorithm), improves testability (each phase can be unit-tested independently), and enhances extensibility (easier to add broadphase culling or friction). Thread safety: Not thread-safe (contains mutable state in member vectors) Error handling: Empty asset spans handled gracefully (early return) Solver non-convergence propagated from ConstraintSolver No exceptions thrown for normal operation docs/designs/0044_collision_pipeline_integration/0044_collision_pipeline_integration.puml Ticket:\n 0044_collision_pipeline_integration');
INSERT INTO "fts_docs" VALUES ('CollisionPipeline','msd_sim::CollisionPipeline::CollisionPipeline','Construct collision pipeline with handler and solver references. collisionHandler Collision detection subsystem (GJK/EPA) constraintSolver Contact constraint solver (ASM/FrictionCone)');
INSERT INTO "fts_docs" VALUES ('execute','msd_sim::CollisionPipeline::execute','Execute full collision response pipeline. Performs: Collision detection (O(n²) pairwise narrow phase) Contact constraint creation via ContactConstraintFactory Solver input assembly (states, masses, inertias) 3.5. Warm-starting query from ContactCache Constraint solving with initial lambda (Active Set Method) 4.5. Cache update with solved lambdas Force application to inertial bodies Position correction via PositionCorrector Frame data is cleared at both the start and end of this method to prevent dangling references when the pipeline is idle between frames. inertialAssets Dynamic objects (non-owning span) environmentalAssets Static objects (non-owning span) dt Timestep [s]');
INSERT INTO "fts_docs" VALUES ('advanceFrame','msd_sim::CollisionPipeline::advanceFrame','Advance contact cache age by one frame. Must be called once per frame before execute() to increment cache age. This enables contact persistence tracking for warm-starting. Ticket:\n 0044_collision_pipeline_integration');
INSERT INTO "fts_docs" VALUES ('expireOldEntries','msd_sim::CollisionPipeline::expireOldEntries','Expire stale contact cache entries. Removes cached contacts older than maxAge frames. Typically called after advanceFrame() and before execute() each frame. maxAge Maximum age in frames (default: 10) Ticket:\n 0044_collision_pipeline_integration');
INSERT INTO "fts_docs" VALUES ('hadCollisions','msd_sim::CollisionPipeline::hadCollisions','Check if collisions occurred this frame. Returns true if collision detection found any colliding pairs. Used for energy tracking diagnostics. true if collisions occurred, false otherwise Ticket:\n 0044_collision_pipeline_integration');
INSERT INTO "fts_docs" VALUES ('getCollisions','msd_sim::CollisionPipeline::getCollisions','Get collision pairs from last execute() . Returns const reference to collision pairs detected during the most recent execute() call. Data is valid from end of execute() until start of next execute() . const reference to collision pair vector Ticket:\n 0056b_collision_pipeline_data_extraction');
INSERT INTO "fts_docs" VALUES ('getSolverData','msd_sim::CollisionPipeline::getSolverData','Get solver diagnostics from last execute() . const reference to solver diagnostic data Ticket:\n 0056b_collision_pipeline_data_extraction');
INSERT INTO "fts_docs" VALUES ('recordConstraints','msd_sim::CollisionPipeline::recordConstraints','Record constraint states to DataRecorder . Iterates all constraints (both ContactConstraint and FrictionConstraint ), calls constraint->recordState() with a DataRecorderVisitor , and buffers the typed records to the appropriate DAOs. Uses visitor pattern for type-safe dispatching without dynamic_cast. Each constraint builds its specific record (ContactConstraintRecord or FrictionConstraintRecord) and dispatches to visitor.visit(record). Must be called AFTER execute() and BEFORE clearEphemeralState() to ensure constraints are still alive. recorder DataRecorder instance to buffer records to frameId Frame ID for FK references in constraint records Thread safety: Not thread-safe (calls DataRecorder methods) Error handling: Exceptions from DAO operations propagate to caller DataRecorderVisitor Constraint::recordState() Ticket:\n 0057_contact_tangent_recording');
INSERT INTO "fts_docs" VALUES ('detectCollisions','msd_sim::CollisionPipeline::detectCollisions','Phase 1: Collision detection (O(n²) pairwise). Populates collisions_ member with detected collision pairs and their metadata (body indices, restitution). Performs: Inertial vs Inertial: O(n²) pairwise checks Inertial vs Environment: O(n*m) checks Early return if no collisions detected.');
INSERT INTO "fts_docs" VALUES ('createConstraints','msd_sim::CollisionPipeline::createConstraints','Phase 2: Create contact constraints from collision results. Populates constraints_ member via ContactConstraintFactory. One constraint per contact point in manifold. Early return if collisions_ is empty. inertialAssets Dynamic objects (non-owning span) environmentalAssets Static objects (non-owning span) dt Timestep [s]');
INSERT INTO "fts_docs" VALUES ('assembleSolverInput','msd_sim::CollisionPipeline::assembleSolverInput','Phase 3: Assemble solver input arrays. Populates states_, inverseMasses_, inverseInertias_, constraintPtrs_ from asset data in solver-compatible layout. Body indexing convention (preserved for solver compatibility): [0 .. numInertial-1] = inertial bodies [numInertial .. numInertial+numEnv-1] = environment bodies inertialAssets Dynamic objects (non-owning span) environmentalAssets Static objects (non-owning span) numBodies Total number of bodies (inertial + environmental)');
INSERT INTO "fts_docs" VALUES ('solveConstraintsWithWarmStart','msd_sim::CollisionPipeline::solveConstraintsWithWarmStart','Phase 4: Solve contact constraint system with warm-starting. Invokes ConstraintSolver::solve() with initial lambda from ContactCache for faster convergence on persistent contacts. dt Timestep [s] SolveResult with per-body forces Ticket:\n 0045_constraint_solver_unification');
INSERT INTO "fts_docs" VALUES ('correctPositions','msd_sim::CollisionPipeline::correctPositions','Phase 6: Position correction via split-impulse method. Corrects penetrating contacts using pseudo-velocities without injecting kinetic energy into real velocities. inertialAssets Dynamic objects (mutable span) environmentalAssets Static objects (non-owning span) numBodies Total body count (inertial + environmental)');
INSERT INTO "fts_docs" VALUES ('applyForces','msd_sim::CollisionPipeline::applyForces','Phase 5: Apply constraint forces to inertial bodies. Calls applyForce() and applyTorque() on each inertial asset. Skips environment bodies (infinite mass). Skips forces below threshold (1e-12) per current implementation. inertialAssets Dynamic objects (mutable span) solveResult Solver output with per-body forces Ticket:\n 0045_constraint_solver_unification');
INSERT INTO "fts_docs" VALUES ('clearEphemeralState','msd_sim::CollisionPipeline::clearEphemeralState','Clear ephemeral solver state (references, pointers, constraints). Clears vectors that hold references or pointers to external objects (states_, etc.) to prevent dangling references when assets are modified between frames. Also clears constraints. Does NOT clear collisions_ — those are value types (owned by pipeline) and are cleared at the start of the next execute() call. This allows WorldModel to read collision data between frames without an intermediate snapshot copy. Preserves capacity to avoid reallocation (NFR-1). Ticket: 0058_constraint_ownership_cleanup');
INSERT INTO "fts_docs" VALUES ('propagateSolvedLambdas','msd_sim::CollisionPipeline::propagateSolvedLambdas','Propagate solved normal lambdas to FrictionConstraints. After the solver runs, each FrictionConstraint needs the corresponding ContactConstraint ''s solved lambda so that recordState() can write the actual normal force value (in Newtons) for visualization. Ticket: 0057_contact_tangent_recording');
INSERT INTO "fts_docs" VALUES ('buildSolverView','msd_sim::CollisionPipeline::buildSolverView','Build solver view (all constraints as Constraint*). Generates a vector of raw pointers for ConstraintSolver::solve() . The view is temporary (not stored) and valid only within the calling scope. interleaved If true (friction active), returns [CC_0, FC_0, CC_1, FC_1, ...]. If false, returns all constraints in storage order. Vector of non-owning Constraint* pointers Ticket: 0058_constraint_ownership_cleanup');
INSERT INTO "fts_docs" VALUES ('buildContactView','msd_sim::CollisionPipeline::buildContactView','Build contact-only view (ContactConstraint* via dynamic_cast). Generates a vector of Constraint* pointers containing only ContactConstraint instances for PositionCorrector::correctPositions() . Filters allConstraints_ using dynamic_cast to extract only ContactConstraint instances. The view is temporary (not stored) and valid only within the calling scope. Vector of non-owning Constraint* pointers (ContactConstraints only) Ticket: 0058_constraint_ownership_cleanup');
INSERT INTO "fts_docs" VALUES ('findPairIndexForConstraint','msd_sim::CollisionPipeline::findPairIndexForConstraint','Map constraint index to collision pair index. Iterates pairRanges_ to find which collision pair owns the given constraint index. Used by recordConstraints() to extract body IDs. constraintIdx Index into allConstraints_ Index into collisions_ vector std::logic_error if constraint index not found in pairRanges_ Ticket: 0057_contact_tangent_recording');
INSERT INTO "fts_docs" VALUES ('CollisionResult','msd_sim::CollisionResult','Complete collision information for physics response with contact manifold. This struct is returned by EPA when a collision is detected. It does NOT contain an ''intersecting'' boolean because: CollisionHandler returns std::optional<CollisionResult> std::nullopt indicates no collision Presence of CollisionResult implies collision exists All coordinates are in world space. Contact normal points from object A toward object B. Breaking change (Ticket 0028_epa_witness_points): Replaced single contactPoint with contactPointA and contactPointB Witness points enable accurate torque calculation (τ = r × F) Breaking change (Ticket 0029_contact_manifold_generation): Replaced contactPointA/contactPointB with contacts array Added contactCount field for number of valid contacts [1, 4] Enables multi-point collision response for improved stability docs/designs/0027a_expanding_polytope_algorithm/0027a_expanding_polytope_algorithm.puml docs/designs/0028_epa_witness_points/0028_epa_witness_points.puml docs/designs/0029_contact_manifold_generation/0029_contact_manifold_generation.puml Ticket:\n 0027a_expanding_polytope_algorithm Ticket:\n 0028_epa_witness_points Ticket:\n 0029_contact_manifold_generation');
INSERT INTO "fts_docs" VALUES ('CollisionResultRecord','msd_transfer::CollisionResultRecord','Complete collision result record for a body pair at one frame. Captures collision geometry (normal, penetration depth) and a manifold of up to 4 contact points via a RepeatedField of ContactPointRecord . Body/frame context is stored here; individual ContactPointRecords are pure geometry sub-records. Ticket:\n 0056a_collision_force_transfer_records');
INSERT INTO "fts_docs" VALUES ('Config','msd_sim::DataRecorder::Config','Configuration for DataRecorder behavior.');
INSERT INTO "fts_docs" VALUES ('Config','msd_sim::PositionCorrector::Config','Configuration parameters for position correction.');
INSERT INTO "fts_docs" VALUES ('beta','msd_sim::PositionCorrector::Config::beta','Position correction factor [0, 1].');
INSERT INTO "fts_docs" VALUES ('slop','msd_sim::PositionCorrector::Config::slop','Penetration tolerance [m] (no correction below).');
INSERT INTO "fts_docs" VALUES ('maxIterations','msd_sim::PositionCorrector::Config::maxIterations','Maximum position correction iterations.');
INSERT INTO "fts_docs" VALUES ('Constraint','msd_sim::Constraint','Abstract base class for constraint definitions in Lagrangian mechanics. Defines the mathematical interface for arbitrary constraints C(q, t) that can be enforced via Lagrange multipliers. Each constraint implementation provides: Constraint function evaluation C(qA, qB, t) for two bodies Constraint Jacobian J = ∂C/∂q Optional time derivative ∂C/∂t Baumgarte stabilization parameters (α, β) Lagrange multiplier bounds (bilateral/unilateral/box-constrained) Body count and indices for solver dispatch Lagrange multiplier formulation: J·M⁻¹·Jᵀ·λ = -J·M⁻¹·F_ext - J̇·q̇ - α·C - β·Ċ F_constraint = Jᵀ·λ Unified Evaluation Signature: All constraints use a two-body signature evaluate(stateA, stateB, time). Single-body constraints ignore stateB. This eliminates LSP violations and enables polymorphic treatment of all constraint types. Convenience Overloads: Non-virtual convenience methods evaluate(state, time) and jacobian(state, time) delegate to the two-body virtual methods, passing state as both stateA and stateB. Jacobian Column Count: Single-body constraints ( bodyCount() == 1): dimension × 7 (position-level DOFs) Two-body constraints ( bodyCount() == 2): dimension × 12 (velocity-level DOFs) Thread safety: Implementations must be thread-safe for concurrent evaluation (read-only after construction). Error handling: Implementations may throw std::invalid_argument for invalid state or parameters. docs/designs/0043_constraint_hierarchy_refactor/0043_constraint_hierarchy_refactor.puml Ticket:\n 0043_constraint_hierarchy_refactor');
INSERT INTO "fts_docs" VALUES ('dimension','msd_sim::Constraint::dimension','Number of scalar constraint equations. Dimension of constraint vector C(q, t)');
INSERT INTO "fts_docs" VALUES ('evaluate','msd_sim::Constraint::evaluate','Evaluate constraint function C(qA, qB, t) for two bodies. Returns vector of constraint violations. For bilateral constraints, C = 0 is the target. For unilateral constraints, C ≥ 0 is the target. Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Constraint violation vector (dimension × 1) std::invalid_argument if state is invalid');
INSERT INTO "fts_docs" VALUES ('evaluate','msd_sim::Constraint::evaluate','Convenience overload for single-body constraints. Delegates to evaluate(state, state, time). Non-virtual. state Current inertial state time Simulation time [s] Constraint violation vector (dimension × 1)');
INSERT INTO "fts_docs" VALUES ('jacobian','msd_sim::Constraint::jacobian','Compute constraint Jacobian J = ∂C/∂q for two bodies. Returns partial derivatives of constraint function w.r.t. position-level or velocity-level DOFs (depending on bodyCount): Single-body ( bodyCount() == 1): dimension × 7 (X: 3, Q: 4) Two-body ( bodyCount() == 2): dimension × 12 (v_A: 3, ω_A: 3, v_B: 3, ω_B: 3) Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Jacobian matrix (dimension × 7 or dimension × 12) std::invalid_argument if state is invalid');
INSERT INTO "fts_docs" VALUES ('jacobian','msd_sim::Constraint::jacobian','Convenience overload for single-body constraints. Delegates to jacobian(state, state, time). Non-virtual. state Current inertial state time Simulation time [s] Jacobian matrix (dimension × 7)');
INSERT INTO "fts_docs" VALUES ('partialTimeDerivative','msd_sim::Constraint::partialTimeDerivative','Compute constraint time derivative ∂C/∂t (optional). Returns partial derivative of constraint w.r.t. explicit time dependence. For time-independent constraints, this returns a zero vector. Default implementation: zero vector (no explicit time dependence) state Current inertial state time Simulation time [s] Time derivative vector (dimension × 1)');
INSERT INTO "fts_docs" VALUES ('alpha','msd_sim::Constraint::alpha','Baumgarte stabilization position error gain. Used in stabilization term: -α·C Higher values increase correction strength but may cause instability. Position error gain α [1/s²]');
INSERT INTO "fts_docs" VALUES ('beta','msd_sim::Constraint::beta','Baumgarte stabilization velocity error gain. Used in stabilization term: -β·Ċ Higher values increase damping but may cause stiffness. Velocity error gain β [1/s]');
INSERT INTO "fts_docs" VALUES ('setAlpha','msd_sim::Constraint::setAlpha','Set Baumgarte position error gain. alpha New position error gain α [1/s²]');
INSERT INTO "fts_docs" VALUES ('setBeta','msd_sim::Constraint::setBeta','Set Baumgarte velocity error gain. beta New velocity error gain β [1/s]');
INSERT INTO "fts_docs" VALUES ('lambdaBounds','msd_sim::Constraint::lambdaBounds','Get Lagrange multiplier bounds. Specifies the lower and upper bounds on the constraint''s Lagrange multiplier: Bilateral constraints: (-∞, +∞) Unilateral constraints: (0, +∞) Box-constrained: (lo, hi) LambdaBounds struct with lower and upper fields');
INSERT INTO "fts_docs" VALUES ('isActive','msd_sim::Constraint::isActive','Check if constraint is active. Determines whether the constraint should be enforced at the given state. Default implementation returns true (always active). stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] true if constraint should be enforced');
INSERT INTO "fts_docs" VALUES ('bodyCount','msd_sim::Constraint::bodyCount','Number of bodies involved in this constraint. Single-body constraints ( UnitQuaternionConstraint , DistanceConstraint ) return 1. Two-body constraints ( ContactConstraint , FrictionConstraint ) return 2. 1 for single-body, 2 for two-body');
INSERT INTO "fts_docs" VALUES ('bodyAIndex','msd_sim::Constraint::bodyAIndex','Get body A index in the solver''s body list. Single-body constraints use this to identify their target body. Two-body constraints use this for the first body. Index of body A (0-based)');
INSERT INTO "fts_docs" VALUES ('bodyBIndex','msd_sim::Constraint::bodyBIndex','Get body B index in the solver''s body list. Unused for single-body constraints (conventionally set to 0). Two-body constraints use this for the second body. Index of body B (0-based)');
INSERT INTO "fts_docs" VALUES ('typeName','msd_sim::Constraint::typeName','Constraint type identifier for debugging/logging. Human-readable constraint type name');
INSERT INTO "fts_docs" VALUES ('recordState','msd_sim::Constraint::recordState','Record constraint state via visitor pattern. Builds a typed constraint record (ContactConstraintRecord, FrictionConstraintRecord, etc.) and dispatches to the visitor via overload resolution. The visitor decides what to do with the record (e.g., buffer to DataRecorder DAO). Enables compile-time type-safe constraint recording without dynamic_cast or std::any_cast. New constraint types extend ConstraintRecordVisitor with a new visit() overload. visitor Visitor that processes the typed constraint record bodyAId Persistent ID of body A for database FK reference bodyBId Persistent ID of body B for database FK reference (ignored for single-body) msd_transfer::ConstraintRecordVisitor msd_sim::DataRecorderVisitor');
INSERT INTO "fts_docs" VALUES ('Constraint','msd_sim::Constraint::Constraint','Protected constructor for subclasses. bodyAIndex Index of body A in solver body list (default 0) bodyBIndex Index of body B in solver body list (default 0) alpha Baumgarte position error gain (default 10.0) beta Baumgarte velocity error gain (default 10.0)');
INSERT INTO "fts_docs" VALUES ('ConstraintData','msd_sim::NLoptFrictionSolver::ConstraintData','Data passed to constraint function.');
INSERT INTO "fts_docs" VALUES ('contactIndex','msd_sim::NLoptFrictionSolver::ConstraintData::contactIndex','Which contact (0..C-1).');
INSERT INTO "fts_docs" VALUES ('mu','msd_sim::NLoptFrictionSolver::ConstraintData::mu','Friction coefficient for this contact.');
INSERT INTO "fts_docs" VALUES ('ConstraintIslandBuilder','msd_sim::ConstraintIslandBuilder','Partitions constraints into independent contact islands via union-find. Uses union-find (disjoint set) to partition a flat constraint list into independent connected components. Two bodies are connected if they share at least one constraint. Environment bodies (index >= numInertialBodies) are intentionally excluded from connectivity: two inertial bodies touching the same floor remain in separate islands, because environment bodies have infinite mass and are unperturbed by contacts. This is a pure orchestration utility for CollisionPipeline . It produces island subsets that are passed to ConstraintSolver::solve() individually, reducing the effective mass matrix from O((3C)³) global to O(Σᵢ (3Cᵢ)³) per-island. Complexity: O(n · α(n)) where α is the inverse Ackermann function (effectively O(n) total for all operations). Thread safety: Stateless static utility — safe to call from any thread. Error handling: Returns empty vector for empty input. No exceptions thrown. docs/designs/0071a_constraint_solver_scalability/design.md docs/designs/0071a_constraint_solver_scalability/0071a_constraint_solver_scalability.puml Ticket:\n 0071a_constraint_solver_scalability');
INSERT INTO "fts_docs" VALUES ('buildIslands','msd_sim::ConstraintIslandBuilder::buildIslands','Partition constraints into independent contact islands. Implements union-find over inertial body indices to determine connected components. Environment bodies (index >= numInertialBodies) do NOT create connectivity between inertial bodies — two cubes touching the same floor form two separate islands because the floor has infinite mass and cannot transmit impulses between them. The constraint ordering within each island preserves the relative order from the input list, which maintains the CC-before-paired-FC interleaving required by ConstraintSolver . constraints All constraints for the current frame (non-owning pointers) numInertialBodies Number of inertial (dynamic) bodies. Environment body indices satisfy: bodyIndex >= numInertialBodies. List of independent islands. Each island contains its constraint subset and all unique body indices (including environment indices) referenced by those constraints. Returns empty vector if constraints is empty.');
INSERT INTO "fts_docs" VALUES ('ConstraintPool','msd_sim::ConstraintPool','Per-frame typed free-list pool for constraint objects. Maintains two contiguous backing stores — one for ContactConstraint , one for FrictionConstraint . After the first frame the backing vectors have grown to their high-water mark; subsequent reset() calls clear the vectors without releasing capacity, achieving zero heap allocation for constraint objects in steady state. Implementation note: Uses reserve() + emplace_back() + clear() rather than resize() + assignment because ContactConstraint and FrictionConstraint have no default constructors. clear() calls trivial virtual destructors (no owned resources) and preserves capacity, so subsequent emplace_back() calls reuse the allocated memory. Pointer stability: Pointers returned by allocate*() are valid until the next reset() call. Callers must not store pointers across frames. Frame lifecycle (pointer safety guarantee): reset() — clear counts, preserve capacity allocate*() batch — all emplace_back calls for this frame Solver, position correction, recording — read-only pointer usage Next frame — goto 1 There is no interleaving of grow and use within a frame. When the vector must grow (first frame or new high-water mark), all pointers already stored in allConstraints_ from this frame would be invalidated — but because all allocations happen in the createConstraints() batch before any pointer is stored, this is safe. Extensibility: New constraint types (joints, limits) add a new typed backing vector and a corresponding allocate*() method. No changes are needed to existing allocation paths. Thread safety: Not thread-safe (single-threaded physics loop assumed). docs/designs/0071g_constraint_pool_allocation/design.md Ticket:\n 0071g_constraint_pool_allocation');
INSERT INTO "fts_docs" VALUES ('allocateContact','msd_sim::ConstraintPool::allocateContact','Construct a ContactConstraint in-pool and return a pointer to it. Grows the backing vector on first call or when capacity is exceeded. After the first frame, capacity is sufficient and no allocation occurs. Pointer to the constructed ContactConstraint . Valid until next reset() .');
INSERT INTO "fts_docs" VALUES ('allocateFriction','msd_sim::ConstraintPool::allocateFriction','Construct a FrictionConstraint in-pool and return a pointer. Grows the backing vector on first call or when capacity is exceeded. After the first frame, capacity is sufficient and no allocation occurs. Pointer to the constructed FrictionConstraint . Valid until next reset() .');
INSERT INTO "fts_docs" VALUES ('reset','msd_sim::ConstraintPool::reset','Reset all constraint pools for the next frame. Calls clear() on both backing vectors: destructs all active constraints but preserves allocated capacity. After the first frame, subsequent emplace_back() calls reuse existing capacity with zero heap allocation. All previously returned pointers become invalid after this call.');
INSERT INTO "fts_docs" VALUES ('reserveContacts','msd_sim::ConstraintPool::reserveContacts','Pre-reserve capacity for ContactConstraints this frame. Call this before any allocateContact() calls within a frame to ensure the backing vector will not reallocate during the allocation batch. When capacity >= n no reallocation occurs, so returned pointers remain valid for the entire frame. n Total number of ContactConstraints expected this frame');
INSERT INTO "fts_docs" VALUES ('reserveFriction','msd_sim::ConstraintPool::reserveFriction','Pre-reserve capacity for FrictionConstraints this frame. Call this before any allocateFriction() calls within a frame. n Total number of FrictionConstraints expected this frame');
INSERT INTO "fts_docs" VALUES ('contactCount','msd_sim::ConstraintPool::contactCount','Number of active ContactConstraints in the pool.');
INSERT INTO "fts_docs" VALUES ('frictionCount','msd_sim::ConstraintPool::frictionCount','Number of active FrictionConstraints in the pool.');
INSERT INTO "fts_docs" VALUES ('ConstraintRecordVisitor','msd_transfer::ConstraintRecordVisitor','Visitor interface for type-safe constraint record dispatching. This interface enables polymorphic constraint recording without dynamic_cast or std::any. Each concrete constraint type calls the appropriate visit() overload, and the compiler enforces that all constraint types are handled. To add a new constraint type: Add new visit(const NewConstraintRecord&) overload to this interface Implement the overload in all concrete visitors (e.g., DataRecorderVisitor) The constraint calls visitor.visit(record) in its recordState() method Compiler will catch missing visit() implementations at build time.');
INSERT INTO "fts_docs" VALUES ('visit','msd_transfer::ConstraintRecordVisitor::visit','Visit a contact constraint record. record The contact constraint state to process');
INSERT INTO "fts_docs" VALUES ('visit','msd_transfer::ConstraintRecordVisitor::visit','Visit a friction constraint record. record The friction constraint state to process');
INSERT INTO "fts_docs" VALUES ('ConstraintSolver','msd_sim::ConstraintSolver','Computes Lagrange multipliers for arbitrary constraint systems. Dispatches between: Active Set Method (ASM): exact LCP, O(k^3), used when numRows <= kASMThreshold Projected Gauss-Seidel (PGS): approximate, O(n) per sweep, used for large islands Uses constraint flattening to expand multi-row constraints ( FrictionConstraint dim=2) into per-row entries for the friction system. Ticket:\n 0031_generalized_lagrange_constraints Ticket:\n 0052d_solver_integration_ecos_removal Ticket:\n 0073_hybrid_pgs_large_islands');
INSERT INTO "fts_docs" VALUES ('RowType','msd_sim::ConstraintSolver::RowType','Row type for flattened constraints.');
INSERT INTO "fts_docs" VALUES ('kASMThreshold','msd_sim::ConstraintSolver::kASMThreshold','Threshold for ASM vs PGS dispatch. Islands with total Jacobian rows <= kASMThreshold use exact ASM. Islands with numRows > kASMThreshold use PGS. Ticket: 0073_hybrid_pgs_large_islands');
INSERT INTO "fts_docs" VALUES ('flat_','msd_sim::ConstraintSolver::flat_','Reused flat constraint representation.');
INSERT INTO "fts_docs" VALUES ('flatEffectiveMass_','msd_sim::ConstraintSolver::flatEffectiveMass_','Reused (3C x 3C) effective mass matrix.');
INSERT INTO "fts_docs" VALUES ('solve','msd_sim::ConstraintSolver::solve','Solve contact constraint system. Detects friction constraints and dispatches to either ASM (no friction) or FrictionConeSolver (with friction). For the friction path, constraints are flattened from [CC, FC, CC, FC, ...] to [n, t1, t2, n, t1, t2, ...] rows before assembly.');
INSERT INTO "fts_docs" VALUES ('flattenConstraints','msd_sim::ConstraintSolver::flattenConstraints','Flatten interleaved [CC, FC, CC, FC, ...] into per-row entries. Expands each FrictionConstraint (dim=2) into two separate 1x12 rows. ContactConstraint (dim=1) produces one row. Output ordering is [n_0, t1_0, t2_0, n_1, t1_1, t2_1, ...] for the friction cone solver. Ticket:\n 0052d_solver_integration_ecos_removal');
INSERT INTO "fts_docs" VALUES ('buildFrictionSpec','msd_sim::ConstraintSolver::buildFrictionSpec','Build FrictionSpec from flattened constraint metadata. Ticket:\n 0052d_solver_integration_ecos_removal');
INSERT INTO "fts_docs" VALUES ('assembleFlatEffectiveMass','msd_sim::ConstraintSolver::assembleFlatEffectiveMass','Assemble effective mass matrix from flattened constraints.');
INSERT INTO "fts_docs" VALUES ('assembleFlatRHS','msd_sim::ConstraintSolver::assembleFlatRHS','Assemble RHS vector from flattened constraints.');
INSERT INTO "fts_docs" VALUES ('extractBodyForcesFlat','msd_sim::ConstraintSolver::extractBodyForcesFlat','Extract per-body forces from flat lambda (no negative-lambda skip). Unlike extractBodyForces() , this does NOT skip negative lambda values because friction forces can be negative (pushing in negative tangent direction). Ticket:\n 0052d_solver_integration_ecos_removal');
INSERT INTO "fts_docs" VALUES ('populateFlatConstraints_','msd_sim::ConstraintSolver::populateFlatConstraints_','Populate flat_ workspace in-place (clears and refills without reallocation). Non-static variant used by solve() to reuse member vector buffers across frames. Ticket:\n 0071f_solver_workspace_reuse');
INSERT INTO "fts_docs" VALUES ('assembleFlatEffectiveMassInPlace_','msd_sim::ConstraintSolver::assembleFlatEffectiveMassInPlace_','Populate flatEffectiveMass_ workspace in-place (resize-only semantics). Non-static variant used by solve() to reuse the matrix buffer across frames. Ticket:\n 0071f_solver_workspace_reuse');
INSERT INTO "fts_docs" VALUES ('ContactCache','msd_sim::ContactCache','Contact cache for warm-starting the constraint solver. Maps body pairs to their previous frame''s solved contact data (lambda values, contact normals, contact points). When contacts persist between frames, the solver starts from the previous lambda, requiring only small corrections. When contacts change significantly (normal rotation >15°), the cache is invalidated. Cache keying uses a symmetric body pair key: (min(id_A, id_B), max(id_A, id_B)) to ensure body order independence. Thread safety: Not thread-safe (single-threaded simulation) Ticket:\n 0040d_contact_persistence_warm_starting');
INSERT INTO "fts_docs" VALUES ('getWarmStart','msd_sim::ContactCache::getWarmStart','Look up cached lambdas for a body pair. Matches current contact points to cached contact points by proximity (nearest-neighbor within threshold). Returns reordered lambdas matching current contact ordering. Unmatched contacts get lambda = 0. Invalidates cache entry if contact normal changed >15 degrees. bodyA Body A identifier bodyB Body B identifier currentNormal Current frame contact normal currentPoints Current frame contact midpoints Cached lambdas reordered to match current contacts, or empty if no valid cache entry exists');
INSERT INTO "fts_docs" VALUES ('update','msd_sim::ContactCache::update','Store solved lambdas for a body pair. Overwrites any existing entry for this body pair. Resets age to 0 (freshly updated). bodyA Body A identifier bodyB Body B identifier normal Contact normal for this frame lambdas Solved lambda values points Contact midpoints for this frame');
INSERT INTO "fts_docs" VALUES ('expireOldEntries','msd_sim::ContactCache::expireOldEntries','Remove entries older than maxAge frames. Called once per frame after advanceFrame() . Entries that have not been refreshed (via update() ) for maxAge frames are removed. maxAge Maximum frames without refresh before expiry (default: 10)');
INSERT INTO "fts_docs" VALUES ('advanceFrame','msd_sim::ContactCache::advanceFrame','Increment age of all entries. Call once per frame at the end of updateCollisions(). Entries refreshed via update() in the current frame will have age 0; others will increment.');
INSERT INTO "fts_docs" VALUES ('hasEntry','msd_sim::ContactCache::hasEntry','Check if cache has a valid entry for a body pair. Lightweight check without performing full warm-start computation. Returns true if the body pair has a cached entry that has not expired. Does NOT check normal alignment — caller should use this only to determine if a persistent contact exists. bodyA Body A identifier bodyB Body B identifier true if a cache entry exists for this body pair Ticket:\n 0053d_sat_fallback_cost_reduction');
INSERT INTO "fts_docs" VALUES ('updateSlidingState','msd_sim::ContactCache::updateSlidingState','Update sliding friction state for a contact pair. Detects sustained sliding based on tangent velocity magnitude and updates the sliding direction. Increments sliding frame count if velocity above threshold, resets to zero otherwise. bodyA Body A identifier bodyB Body B identifier tangentVelocity Relative tangent velocity at contact [m/s] velocityThreshold Minimum velocity to qualify as sliding [m/s] (default: 0.01) Ticket:\n 0069_friction_velocity_reversal');
INSERT INTO "fts_docs" VALUES ('getSlidingState','msd_sim::ContactCache::getSlidingState','Query sliding friction state for a contact pair. Returns sliding direction and whether sliding mode is active (age >= 3, velocity sustained). bodyA Body A identifier bodyB Body B identifier minFrames Minimum consecutive frames to activate sliding mode (default: 3) {slidingDirection, isActive} pair. slidingDirection is nullopt if not sliding. Ticket:\n 0069_friction_velocity_reversal');
INSERT INTO "fts_docs" VALUES ('clear','msd_sim::ContactCache::clear','Clear all cached data.');
INSERT INTO "fts_docs" VALUES ('size','msd_sim::ContactCache::size','Number of cached body pair entries.');
INSERT INTO "fts_docs" VALUES ('makeKey','msd_sim::ContactCache::makeKey','Create symmetric key from body pair. (min(a,b), max(a,b))');
INSERT INTO "fts_docs" VALUES ('ContactConstraint','msd_sim::ContactConstraint','Non-penetration unilateral constraint for a single contact point. Implements the contact constraint C(q) = (x_B - x_A) · n ≥ 0 where: x_A, x_B are contact points on bodies A and B (world space) n is the contact normal (A → B, unit length) Each ContactConstraint has dimension() = 1 (one scalar constraint per contact point). A CollisionResult with contactCount = 4 produces 4 ContactConstraint instances. This follows the math formulation Section 2.5 and provides better stability for resting contacts than a centroid approximation. Design decisions: Pre-computed lever arms: r_A and r_B computed once at construction Stores pre-impact velocity: Relative normal velocity at impact time captured for restitution RHS term Baumgarte parameters: Uses Error Reduction Parameter (ERP) formulation standard in physics engines. Default: ERP = 0.2 (equivalent to α_accel ≈ 781 [1/s²] at 60 FPS). Validated by Prototype P1 parameter sweep. CRITICAL: Restitution formula uses v_target = -e · v_pre (not -(1+e)·v_pre). The constraint RHS for PGS is b = -(1+e) · J·q̇⁻, but the target velocity is -e·v_pre. See P2 Debug Findings for details. Thread safety: Immutable after construction; thread-safe for concurrent reads Error handling: Constructor validates normal is unit length, penetration >= 0, restitution in [0, 1] docs/designs/0032_contact_constraint_refactor/0032_contact_constraint_refactor.puml prototypes/0032_contact_constraint_refactor/p1_pgs_convergence/Debug_Findings.md prototypes/0032_contact_constraint_refactor/p2_energy_conservation/Debug_Findings.md Ticket:\n 0032_contact_constraint_refactor');
INSERT INTO "fts_docs" VALUES ('ContactConstraint','msd_sim::ContactConstraint::ContactConstraint','Construct a contact constraint for a single contact point. bodyAIndex Index of body A in the solver body list bodyBIndex Index of body B in the solver body list normal Contact normal (A → B, unit length) contactPointA Contact point on A''s surface (world space) [m] contactPointB Contact point on B''s surface (world space) [m] penetrationDepth Overlap distance [m] (positive when penetrating) comA Center of mass of body A (world space) [m] comB Center of mass of body B (world space) [m] restitution Coefficient of restitution [0, 1] preImpactRelVelNormal Pre-impact relative normal velocity [m/s] std::invalid_argument if normal is not unit length (within 1e-6) std::invalid_argument if penetration < 0 std::invalid_argument if restitution not in [0, 1]');
INSERT INTO "fts_docs" VALUES ('dimension','msd_sim::ContactConstraint::dimension','Number of scalar constraint equations. Dimension of constraint vector C(q, t)');
INSERT INTO "fts_docs" VALUES ('evaluate','msd_sim::ContactConstraint::evaluate','Evaluate constraint function C(qA, qB, t) for two bodies. Returns vector of constraint violations. For bilateral constraints, C = 0 is the target. For unilateral constraints, C ≥ 0 is the target. Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Constraint violation vector (dimension × 1) std::invalid_argument if state is invalid');
INSERT INTO "fts_docs" VALUES ('jacobian','msd_sim::ContactConstraint::jacobian','Compute constraint Jacobian J = ∂C/∂q for two bodies. Returns partial derivatives of constraint function w.r.t. position-level or velocity-level DOFs (depending on bodyCount): Single-body ( bodyCount() == 1): dimension × 7 (X: 3, Q: 4) Two-body ( bodyCount() == 2): dimension × 12 (v_A: 3, ω_A: 3, v_B: 3, ω_B: 3) Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Jacobian matrix (dimension × 7 or dimension × 12) std::invalid_argument if state is invalid');
INSERT INTO "fts_docs" VALUES ('isActive','msd_sim::ContactConstraint::isActive','Check if constraint is active. Determines whether the constraint should be enforced at the given state. Default implementation returns true (always active). stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] true if constraint should be enforced');
INSERT INTO "fts_docs" VALUES ('lambdaBounds','msd_sim::ContactConstraint::lambdaBounds','Get Lagrange multiplier bounds. Specifies the lower and upper bounds on the constraint''s Lagrange multiplier: Bilateral constraints: (-∞, +∞) Unilateral constraints: (0, +∞) Box-constrained: (lo, hi) LambdaBounds struct with lower and upper fields');
INSERT INTO "fts_docs" VALUES ('bodyCount','msd_sim::ContactConstraint::bodyCount','Number of bodies involved in this constraint. Single-body constraints ( UnitQuaternionConstraint , DistanceConstraint ) return 1. Two-body constraints ( ContactConstraint , FrictionConstraint ) return 2. 1 for single-body, 2 for two-body');
INSERT INTO "fts_docs" VALUES ('typeName','msd_sim::ContactConstraint::typeName','Constraint type identifier for debugging/logging. Human-readable constraint type name');
INSERT INTO "fts_docs" VALUES ('recordState','msd_sim::ContactConstraint::recordState','Record constraint state via visitor pattern. Builds a typed constraint record (ContactConstraintRecord, FrictionConstraintRecord, etc.) and dispatches to the visitor via overload resolution. The visitor decides what to do with the record (e.g., buffer to DataRecorder DAO). Enables compile-time type-safe constraint recording without dynamic_cast or std::any_cast. New constraint types extend ConstraintRecordVisitor with a new visit() overload. visitor Visitor that processes the typed constraint record bodyAId Persistent ID of body A for database FK reference bodyBId Persistent ID of body B for database FK reference (ignored for single-body) msd_transfer::ConstraintRecordVisitor msd_sim::DataRecorderVisitor');
INSERT INTO "fts_docs" VALUES ('ContactConstraintRecord','msd_transfer::ContactConstraintRecord','Transfer record for contact constraint state. Records the geometry and parameters of a contact constraint after constraint creation. Used for debugging constraint solver behavior and validating contact detection. Note: All vector fields (normal, lever arms) are Vector3DRecord (directions), not CoordinateRecord (points), to avoid globalToLocal overload issues.');
INSERT INTO "fts_docs" VALUES ('body_a_id','msd_transfer::ContactConstraintRecord::body_a_id','ID of body A in the contact pair.');
INSERT INTO "fts_docs" VALUES ('body_b_id','msd_transfer::ContactConstraintRecord::body_b_id','ID of body B in the contact pair.');
INSERT INTO "fts_docs" VALUES ('normal','msd_transfer::ContactConstraintRecord::normal','Contact normal in world space (unit vector pointing from B to A).');
INSERT INTO "fts_docs" VALUES ('lever_arm_a','msd_transfer::ContactConstraintRecord::lever_arm_a','Lever arm from body A''s center of mass to contact point.');
INSERT INTO "fts_docs" VALUES ('lever_arm_b','msd_transfer::ContactConstraintRecord::lever_arm_b','Lever arm from body B''s center of mass to contact point.');
INSERT INTO "fts_docs" VALUES ('penetration_depth','msd_transfer::ContactConstraintRecord::penetration_depth','Penetration depth at constraint creation (meters).');
INSERT INTO "fts_docs" VALUES ('restitution','msd_transfer::ContactConstraintRecord::restitution','Coefficient of restitution for this contact.');
INSERT INTO "fts_docs" VALUES ('pre_impact_rel_vel_normal','msd_transfer::ContactConstraintRecord::pre_impact_rel_vel_normal','Pre-impact relative velocity projected onto normal (m/s).');
INSERT INTO "fts_docs" VALUES ('frame','msd_transfer::ContactConstraintRecord::frame','Foreign key to simulation frame.');
INSERT INTO "fts_docs" VALUES ('ContactPoint','msd_sim::ContactPoint','A single contact pair within a collision manifold. Stores contact locations on both object surfaces in world space, along with the penetration depth at this specific contact point. Simple POD struct with value semantics. docs/designs/0029_contact_manifold_generation/0029_contact_manifold_generation.puml docs/designs/0040a-per-contact-penetration-depth/0040a-per-contact-penetration-depth.puml Ticket:\n 0029_contact_manifold_generation Ticket:\n 0040a_per_contact_penetration_depth');
INSERT INTO "fts_docs" VALUES ('ContactPointRecord','msd_transfer::ContactPointRecord','Per-contact-point geometry sub-record. Pure geometry record storing contact locations on both bodies. Body/frame context lives in the parent CollisionResultRecord . Replaces ContactRecord which had body IDs, frame FK, and contact_index baked in as a standalone per-row record. Ticket:\n 0056a_collision_force_transfer_records');
INSERT INTO "fts_docs" VALUES ('ConvexHull','msd_sim::ConvexHull','Represents a 3D convex hull for collision detection. This class wraps Qhull functionality to compute convex hulls from point clouds or geometry objects. It provides the minimal data required for collision detection algorithms ( GJK , EPA , etc.). Key features: Construct from point clouds or msd_assets::Geometry objects Access to hull vertices and facets Point containment testing Support for geometric intersection operations Axis-aligned bounding box for broad-phase collision detection Note: For inertial properties (mass, centroid, moment of inertia), use AssetInertial which contains a ConvexHull along with physics properties.');
INSERT INTO "fts_docs" VALUES ('ConvexHull','msd_sim::ConvexHull::ConvexHull','Default constructor - creates an empty hull.');
INSERT INTO "fts_docs" VALUES ('ConvexHull','msd_sim::ConvexHull::ConvexHull','Construct convex hull from a point cloud. Computes the convex hull of the given points using Qhull. Duplicate and interior points are automatically removed. points Vector of 3D coordinates std::runtime_error if points are degenerate or Qhull fails');
INSERT INTO "fts_docs" VALUES ('ConvexHull','msd_sim::ConvexHull::ConvexHull','Create convex hull from msd_assets::Geometry object. Extracts all vertices from the geometry and computes their convex hull. geometry Geometry object to create hull from ConvexHull of the geometry''s vertices std::runtime_error if geometry is empty or degenerate');
INSERT INTO "fts_docs" VALUES ('getVertices','msd_sim::ConvexHull::getVertices','Get all vertices of the convex hull. Returns only the vertices that form the hull boundary (not interior points). Vector of hull vertex coordinates');
INSERT INTO "fts_docs" VALUES ('getFacets','msd_sim::ConvexHull::getFacets','Get all facets of the convex hull. Each facet is a triangle with vertex indices and normal vector. Vector of triangular facets');
INSERT INTO "fts_docs" VALUES ('getFacetAlignedWith','msd_sim::ConvexHull::getFacetAlignedWith','Get the facet most aligned with a given direction. normal Direction to compare against Reference to the facet with greatest dot product');
INSERT INTO "fts_docs" VALUES ('getFacetsAlignedWith','msd_sim::ConvexHull::getFacetsAlignedWith','Get all facets aligned with a given direction within tolerance. Returns all facets whose alignment (dot product with normal) is within tolerance of the maximum alignment. Useful for contact manifold generation when multiple coplanar facets may contribute to the contact. normal Direction to compare against tolerance How close to max alignment to include (default: 1e-6) Vector of references to aligned facets');
INSERT INTO "fts_docs" VALUES ('getVertexCount','msd_sim::ConvexHull::getVertexCount','Get the number of vertices in the hull. Number of vertices');
INSERT INTO "fts_docs" VALUES ('getFacetCount','msd_sim::ConvexHull::getFacetCount','Get the number of facets in the hull. Number of triangular facets');
INSERT INTO "fts_docs" VALUES ('getVolume','msd_sim::ConvexHull::getVolume','Get the volume enclosed by the convex hull. Volume is computed by Qhull during hull construction. Volume in cubic units');
INSERT INTO "fts_docs" VALUES ('getSurfaceArea','msd_sim::ConvexHull::getSurfaceArea','Get the surface area of the convex hull. Surface area is computed by Qhull during hull construction. Surface area in square units');
INSERT INTO "fts_docs" VALUES ('getCentroid','msd_sim::ConvexHull::getCentroid','Get the geometric centroid of the convex hull. The centroid is the center of mass assuming uniform density. Computed during hull construction using tetrahedron decomposition. Centroid coordinate');
INSERT INTO "fts_docs" VALUES ('contains','msd_sim::ConvexHull::contains','Test if a point is contained within the convex hull. Uses the half-space representation: a point is inside if it''s on the negative side of all facet planes. point Point to test epsilon Tolerance for numerical precision (default: 1e-6) true if point is inside or on the boundary, false otherwise');
INSERT INTO "fts_docs" VALUES ('signedDistance','msd_sim::ConvexHull::signedDistance','Compute signed distance from a point to the hull surface. Negative distance means the point is inside the hull. Positive distance means the point is outside. point Point to compute distance from Signed distance to hull surface');
INSERT INTO "fts_docs" VALUES ('getBoundingBox','msd_sim::ConvexHull::getBoundingBox','Get the axis-aligned bounding box of the convex hull. The bounding box is computed directly by Qhull during hull construction. Bounding box containing minimum and maximum corners');
INSERT INTO "fts_docs" VALUES ('isValid','msd_sim::ConvexHull::isValid','Check if the hull is valid (non-degenerate). true if hull has volume > 0, false otherwise');
INSERT INTO "fts_docs" VALUES ('findClosestEdge','msd_sim::ConvexHull::findClosestEdge','Find the edge of the convex hull closest to a given point in hull-local space. Iterates all unique edges (vertex pairs from facet definitions) and returns the one with minimum distance to the query point. point Query point in hull-local space Edge with start and end coordinates in hull-local space Ticket:\n 0040c_edge_contact_manifold');
INSERT INTO "fts_docs" VALUES ('computeHull','msd_sim::ConvexHull::computeHull','Internal template method to compute the convex hull using Qhull. Accepts any vector-like type that provides x(), y(), z() accessors, such as msd_sim::Vector3D or msd_sim::Coordinate . VectorType Type with x(), y(), z() methods returning doubles points Input point cloud std::runtime_error if Qhull computation fails');
INSERT INTO "fts_docs" VALUES ('extractHullData','msd_sim::ConvexHull::extractHullData','Extract vertices and facets from Qhull result. qh Qhull state structure');
INSERT INTO "fts_docs" VALUES ('computeCentroid','msd_sim::ConvexHull::computeCentroid','Compute and cache the geometric centroid. The centroid is the center of mass assuming uniform density. Uses tetrahedron decomposition for accurate volume-weighted calculation. Called during hull construction.');
INSERT INTO "fts_docs" VALUES ('Coordinate','msd_sim::Coordinate','3D spatial coordinate (position in space) Inherits from msd_sim::Vector3D via Vec3DBase for full matrix operation support. Provides semantic x/y/z accessors and transfer object support. Memory footprint: 24 bytes (same as msd_sim::Vector3D )');
INSERT INTO "fts_docs" VALUES ('CoordinateRecord','msd_transfer::CoordinateRecord','Database record for a 3D spatial coordinate. Stores the x, y, z components of an msd_sim::Coordinate as individual scalar doubles for human-readable database inspection and queryability.');
INSERT INTO "fts_docs" VALUES ('DatabaseWrapper','DatabaseWrapper','Python wrapper for cpp_sqlite::Database with read-only queries. Provides generic select_all() and select_by_id() methods that work with any record type exposed in record_bindings.cpp . For FK-based queries (select_by_frame, select_by_body), uses raw SQL via Database::select<T>().');
INSERT INTO "fts_docs" VALUES ('DataRecorder','msd_sim::DataRecorder','Orchestrates background recording of simulation data to SQLite database. DataRecorder operates on a dedicated background thread, periodically flushing buffered records to disk. Record submission from the simulation thread is thread-safe via cpp_sqlite''s double-buffered DAOs. Architecture: Simulation thread calls recordFrame() to create timestamped frames Simulation thread calls getDAO<T>() .addToBuffer(record) for per-frame data Recorder thread wakes periodically to flush all buffers via transaction Destructor ensures all pending records are written before shutdown docs/designs/0038_simulation_data_recorder/0038_simulation_data_recorder.puml Ticket:\n 0038_simulation_data_recorder');
INSERT INTO "fts_docs" VALUES ('DataRecorder','msd_sim::DataRecorder::DataRecorder','Construct DataRecorder and start background thread. Opens database, initializes SimulationFrameRecord DAO first (for FK integrity), and starts recorder thread. config Configuration for flush behavior and database path std::runtime_error if database path is invalid or cannot be opened Ticket:\n 0038_simulation_data_recorder');
INSERT INTO "fts_docs" VALUES ('~DataRecorder','msd_sim::DataRecorder::~DataRecorder','Destructor flushes all pending records and joins thread. Calls flush() explicitly before allowing jthread to join automatically. Ensures no data loss on shutdown. Ticket:\n 0038_simulation_data_recorder');
INSERT INTO "fts_docs" VALUES ('recordFrame','msd_sim::DataRecorder::recordFrame','Create new simulation frame with timestamp. Pre-assigns frame ID atomically, creates SimulationFrameRecord with simulation time and wall-clock time, adds to buffer. Returns the pre-assigned frame ID for FK references in child records. Thread-safe: Uses atomic nextFrameId_ for ID assignment and mutex-protected addToBuffer(). simulationTime Current simulation time [seconds] Pre-assigned frame ID for FK references Ticket:\n 0038_simulation_data_recorder');
INSERT INTO "fts_docs" VALUES ('getDAO','msd_sim::DataRecorder::getDAO','Get DAO for adding records (thread-safe addToBuffer). Delegates to database_-> getDAO<T>() . DAOs are created on first access and managed by Database. All DAOs support thread-safe addToBuffer(). T Record type (must inherit from BaseTransferObject) Reference to DAO for type T Ticket:\n 0038_simulation_data_recorder');
INSERT INTO "fts_docs" VALUES ('flush','msd_sim::DataRecorder::flush','Explicit flush of all pending records. Thread-safe: Acquires flushMutex_ to prevent concurrent flushes with recorder thread. Wraps database_->flushAllDAOs() in transaction for performance. Ticket:\n 0038_simulation_data_recorder');
INSERT INTO "fts_docs" VALUES ('getDatabase','msd_sim::DataRecorder::getDatabase','Access database for queries (const only). Provides read-only access to database for verification/testing. Write access should only occur through recorder mechanisms. Const reference to database Ticket:\n 0038_simulation_data_recorder');
INSERT INTO "fts_docs" VALUES ('recordInertialStates','msd_sim::DataRecorder::recordInertialStates','Record inertial states for all assets in a frame. Iterates assets, calls toRecord(), sets FK fields (body_id, frame_id), and buffers records via DAO. Thread-safe: Uses mutex-protected DAO::addToBuffer(). frameId Foreign key to SimulationFrameRecord assets Span of inertial assets to record Ticket:\n 0056j_domain_aware_data_recorder');
INSERT INTO "fts_docs" VALUES ('recordBodyEnergies','msd_sim::DataRecorder::recordBodyEnergies','Record per-body energy for all assets in a frame. Computes body energy from inertial state, mass, inertia tensor, and potential energy fields. Buffers EnergyRecord for each asset. Thread-safe: Uses mutex-protected DAO::addToBuffer(). frameId Foreign key to SimulationFrameRecord assets Span of inertial assets to record potentials Span of potential energy fields for energy calculation Ticket:\n 0056j_domain_aware_data_recorder');
INSERT INTO "fts_docs" VALUES ('recordSystemEnergy','msd_sim::DataRecorder::recordSystemEnergy','Record system-level energy summary for a frame. Records total system energy (KE + PE), energy change from previous frame, and collision active flag. Thread-safe: Uses mutex-protected DAO::addToBuffer(). frameId Foreign key to SimulationFrameRecord energy System energy summary (total, KE, PE breakdown) previousTotal Total energy from previous frame for delta calculation collisionActive Whether collision was active this frame Ticket:\n 0056j_domain_aware_data_recorder');
INSERT INTO "fts_docs" VALUES ('recordCollisions','msd_sim::DataRecorder::recordCollisions','Record collision results for a frame. Iterates collision pairs, calls toRecord(), sets FK fields, and buffers CollisionResultRecord for each collision. Thread-safe: Uses mutex-protected DAO::addToBuffer(). frameId Foreign key to SimulationFrameRecord pipeline CollisionPipeline instance (for accessing collision pairs) Ticket:\n 0056j_domain_aware_data_recorder');
INSERT INTO "fts_docs" VALUES ('recordSolverDiagnostics','msd_sim::DataRecorder::recordSolverDiagnostics','Record solver diagnostics for a frame. Records constraint solver convergence metrics (iterations, residual, constraint count, contact count). Thread-safe: Uses mutex-protected DAO::addToBuffer(). frameId Foreign key to SimulationFrameRecord pipeline CollisionPipeline instance (for accessing solver data) Ticket:\n 0056j_domain_aware_data_recorder');
INSERT INTO "fts_docs" VALUES ('recordStaticAsset','msd_sim::DataRecorder::recordStaticAsset','Record static asset properties at spawn time. Records immutable asset properties (mass, restitution, friction) linked by body_id foreign key. Called when asset is spawned into WorldModel . Thread-safe: Uses mutex-protected DAO::addToBuffer(). asset Inertial asset to record static properties for Ticket:\n 0056j_domain_aware_data_recorder');
INSERT INTO "fts_docs" VALUES ('recorderThreadMain','msd_sim::DataRecorder::recorderThreadMain','Recorder thread main loop. Sleeps for flushInterval_, then acquires flushMutex_ and flushes all DAOs in a transaction. Continues until stop_token is requested. stopToken Token for clean shutdown signaling Ticket:\n 0038_simulation_data_recorder');
INSERT INTO "fts_docs" VALUES ('DataRecorderVisitor','msd_sim::DataRecorderVisitor','Concrete visitor that buffers constraint records to DataRecorder DAOs. Implements the ConstraintRecordVisitor interface to enable type-safe constraint state recording without dynamic_cast or std::any_cast. Each visit() method receives a typed constraint record, sets the frame FK, and buffers it to the appropriate DAO. Usage: DataRecorderVisitor visitor{recorder, frameId}; constraint->recordState(visitor, bodyAId, bodyBId); // Dispatches to appropriate visit() Thread safety: Not thread-safe (caller must ensure DataRecorder thread safety) Error handling: Exceptions from DAO operations propagate to caller msd_transfer::ConstraintRecordVisitor DataRecorder');
INSERT INTO "fts_docs" VALUES ('DataRecorderVisitor','msd_sim::DataRecorderVisitor::DataRecorderVisitor','Construct visitor wrapping DataRecorder and frame ID. recorder DataRecorder instance to buffer records to frameId Frame ID for FK references');
INSERT INTO "fts_docs" VALUES ('visit','msd_sim::DataRecorderVisitor::visit','Visit contact constraint record. Sets frame FK and buffers record to ContactConstraintRecord DAO. record Contact constraint state to buffer');
INSERT INTO "fts_docs" VALUES ('visit','msd_sim::DataRecorderVisitor::visit','Visit friction constraint record. Sets frame FK and buffers record to FrictionConstraintRecord DAO. record Friction constraint state to buffer');
INSERT INTO "fts_docs" VALUES ('DistanceConstraint','msd_sim::DistanceConstraint','Fixed distance constraint from origin (single-object example). Maintains the constraint C(X) = |X|² - d² = 0 to keep an object at a fixed distance d from the origin. This is a simplified single-object constraint demonstrating the constraint framework. Multi-object distance constraints (between two objects) are deferred to future ticket 0032. Mathematical formulation: Constraint : C(X) = |X|² - d² = 0 (scalar constraint) Jacobian: J = 2·X^T (1×3 row vector w.r.t. position components) Time derivative: ∂C/∂t = 0 (time-independent) Use cases: Orbital mechanics: fixed orbital radius Pendulum: fixed rod length Tethered objects: cable length constraint Thread safety: Thread-safe for concurrent evaluation after construction Error handling: Throws std::invalid_argument if targetDistance <= 0 docs/designs/0043_constraint_hierarchy_refactor/0043_constraint_hierarchy_refactor.puml Ticket:\n 0043_constraint_hierarchy_refactor');
INSERT INTO "fts_docs" VALUES ('DistanceConstraint','msd_sim::DistanceConstraint::DistanceConstraint','Construct constraint with target distance from origin. targetDistance Desired distance from origin [m] bodyAIndex Index of body in solver body list (default: 0) alpha Position error gain [1/s²] (default: 10.0) beta Velocity error gain [1/s] (default: 10.0) std::invalid_argument if targetDistance <= 0');
INSERT INTO "fts_docs" VALUES ('dimension','msd_sim::DistanceConstraint::dimension','Number of scalar constraint equations. Dimension of constraint vector C(q, t)');
INSERT INTO "fts_docs" VALUES ('evaluate','msd_sim::DistanceConstraint::evaluate','Evaluate constraint function C(qA, qB, t) for two bodies. Returns vector of constraint violations. For bilateral constraints, C = 0 is the target. For unilateral constraints, C ≥ 0 is the target. Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Constraint violation vector (dimension × 1) std::invalid_argument if state is invalid');
INSERT INTO "fts_docs" VALUES ('jacobian','msd_sim::DistanceConstraint::jacobian','Compute constraint Jacobian J = ∂C/∂q for two bodies. Returns partial derivatives of constraint function w.r.t. position-level or velocity-level DOFs (depending on bodyCount): Single-body ( bodyCount() == 1): dimension × 7 (X: 3, Q: 4) Two-body ( bodyCount() == 2): dimension × 12 (v_A: 3, ω_A: 3, v_B: 3, ω_B: 3) Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Jacobian matrix (dimension × 7 or dimension × 12) std::invalid_argument if state is invalid');
INSERT INTO "fts_docs" VALUES ('partialTimeDerivative','msd_sim::DistanceConstraint::partialTimeDerivative','Compute constraint time derivative ∂C/∂t (optional). Returns partial derivative of constraint w.r.t. explicit time dependence. For time-independent constraints, this returns a zero vector. Default implementation: zero vector (no explicit time dependence) state Current inertial state time Simulation time [s] Time derivative vector (dimension × 1)');
INSERT INTO "fts_docs" VALUES ('lambdaBounds','msd_sim::DistanceConstraint::lambdaBounds','Get Lagrange multiplier bounds. Specifies the lower and upper bounds on the constraint''s Lagrange multiplier: Bilateral constraints: (-∞, +∞) Unilateral constraints: (0, +∞) Box-constrained: (lo, hi) LambdaBounds struct with lower and upper fields');
INSERT INTO "fts_docs" VALUES ('typeName','msd_sim::DistanceConstraint::typeName','Constraint type identifier for debugging/logging. Human-readable constraint type name');
INSERT INTO "fts_docs" VALUES ('recordState','msd_sim::DistanceConstraint::recordState','Record constraint state via visitor pattern. Builds a typed constraint record (ContactConstraintRecord, FrictionConstraintRecord, etc.) and dispatches to the visitor via overload resolution. The visitor decides what to do with the record (e.g., buffer to DataRecorder DAO). Enables compile-time type-safe constraint recording without dynamic_cast or std::any_cast. New constraint types extend ConstraintRecordVisitor with a new visit() overload. visitor Visitor that processes the typed constraint record bodyAId Persistent ID of body A for database FK reference bodyBId Persistent ID of body B for database FK reference (ignored for single-body) msd_transfer::ConstraintRecordVisitor msd_sim::DataRecorderVisitor');
INSERT INTO "fts_docs" VALUES ('getTargetDistance','msd_sim::DistanceConstraint::getTargetDistance','Get target distance from origin. Target distance [m]');
INSERT INTO "fts_docs" VALUES ('evaluate','msd_sim::DistanceConstraint::evaluate','Convenience overload for single-body constraints. Delegates to evaluate(state, state, time). Non-virtual. state Current inertial state time Simulation time [s] Constraint violation vector (dimension × 1)');
INSERT INTO "fts_docs" VALUES ('jacobian','msd_sim::DistanceConstraint::jacobian','Convenience overload for single-body constraints. Delegates to jacobian(state, state, time). Non-virtual. state Current inertial state time Simulation time [s] Jacobian matrix (dimension × 7)');
INSERT INTO "fts_docs" VALUES ('Edge','msd_sim::ConvexHull::Edge','Represents an edge of the convex hull as a pair of vertex coordinates. Ticket:\n 0040c_edge_contact_manifold');
INSERT INTO "fts_docs" VALUES ('EnergyRecord','msd_transfer::EnergyRecord','Database record for per-body energy values. Stores computed energy components for a single rigid body at a given simulation frame. Uses ForeignKey<AssetInertialStaticRecord> for body identification and ForeignKey<SimulationFrameRecord> for temporal association with the recording frame. Energy components: linear_ke: Linear kinetic energy KE = 0.5 * m * v^2 [J] rotational_ke: Rotational kinetic energy KE = 0.5 * omega^T * I_world * omega [J] potential_e: Gravitational potential energy PE = -m * (g . r) [J] total_e: Total mechanical energy E = KE_lin + KE_rot + PE [J] msd_sim::EnergyTracker Ticket:\n 0039a_energy_tracking_diagnostic_infrastructure Ticket:\n 0056i_static_asset_recording_and_fk');
INSERT INTO "fts_docs" VALUES ('EnergyTracker','msd_sim::EnergyTracker','Energy computation utility for rigid body diagnostics. Provides static methods to compute kinetic and potential energy for individual bodies and the entire system. Used by WorldModel to record energy data for collision debugging and anomaly detection. CRITICAL: Rotational kinetic energy uses world-frame inertia tensor: KE_rot = 0.5 * omega^T * I_world * omega where I_world = R * I_body * R^T Using body-frame inertia with world-frame angular velocity produces chaotic-looking energy even when physics are correct. Ticket:\n 0039a_energy_tracking_diagnostic_infrastructure');
INSERT INTO "fts_docs" VALUES ('computeBodyEnergy','msd_sim::EnergyTracker::computeBodyEnergy','Compute energy for a single rigid body. state Current kinematic state mass Body mass [kg] bodyInertia Inertia tensor in body frame [kg*m^2] potentialEnergies Potential energy fields to evaluate BodyEnergy with all energy components');
INSERT INTO "fts_docs" VALUES ('computeSystemEnergy','msd_sim::EnergyTracker::computeSystemEnergy','Compute total system energy across all bodies. bodies All inertial assets in the simulation potentialEnergies Potential energy fields to evaluate SystemEnergy with aggregated energy values');
INSERT INTO "fts_docs" VALUES ('isEnergyInjection','msd_sim::EnergyTracker::isEnergyInjection','Check if energy change exceeds tolerance (anomaly detection). Uses the larger of relative and absolute tolerance: Relative: relativeTolerance * |currentEnergy| Absolute: absoluteTolerance Energy increase beyond tolerance indicates energy injection (anomaly). Energy decrease is allowed (dissipation is physical). currentEnergy Current total system energy [J] previousEnergy Previous frame total system energy [J] relativeTolerance Relative tolerance (default 1e-6) absoluteTolerance Absolute tolerance [J] (default 1e-9) true if energy increased beyond tolerance');
INSERT INTO "fts_docs" VALUES ('Engine','msd_sim::Engine','Top-level simulation orchestrator. Coordinates asset loading (via AssetRegistry), world management (via WorldModel ), and physics simulation updates. Provides the primary entry point for spawning objects into the simulation and stepping time forward. Also exposed to Python as msd_reader.Engine via the pybind11 EngineWrapper (see msd-pybind/src/engine_bindings.cpp ). Not thread-safe — single-threaded simulation assumed.');
INSERT INTO "fts_docs" VALUES ('Engine','msd_sim::Engine::Engine','Construct an Engine from an assets database path. dbPath Path to the SQLite assets database (created by generate_assets) std::runtime_error if the database cannot be opened');
INSERT INTO "fts_docs" VALUES ('update','msd_sim::Engine::update','Advance the simulation to the given absolute time. simTime Absolute simulation time (not a delta). Pass increasing values on each call (e.g. 16ms, 32ms, 48ms for 60 FPS).');
INSERT INTO "fts_docs" VALUES ('spawnInertialObject','msd_sim::Engine::spawnInertialObject','Spawn an inertial object with custom mass, restitution, and friction. Ticket:\n 0062a_extend_test_asset_generator assetName Name of asset in registry position World position orientation World orientation mass Mass in kilograms [kg] coefficientOfRestitution Elasticity [0, 1] (0=inelastic, 1=elastic) frictionCoefficient Friction coefficient [0, inf) Reference to spawned inertial object std::runtime_error if asset not found or has no collision geometry std::invalid_argument if mass <= 0 std::invalid_argument if coefficientOfRestitution not in [0, 1] std::invalid_argument if frictionCoefficient < 0');
INSERT INTO "fts_docs" VALUES ('spawnEnvironmentObject','msd_sim::Engine::spawnEnvironmentObject','Spawn a static environment object from an asset. assetName Name of asset in registry position World position orientation World orientation Reference to spawned environment object Environment objects are static (immovable) and participate in collision detection. Dynamic objects will bounce off them.');
INSERT INTO "fts_docs" VALUES ('spawnPlayerPlatform','msd_sim::Engine::spawnPlayerPlatform','Spawn a player-controlled platform with visual object. assetName Name of visual asset position Initial position orientation Initial orientation Platform ID Creates a Platform with InputControlAgent and links it to a visual Object in WorldModel . Sets this platform as the player platform for input commands.');
INSERT INTO "fts_docs" VALUES ('setPlayerInputCommands','msd_sim::Engine::setPlayerInputCommands','Set input commands for the player platform. commands Input commands from GUI Propagates input commands to the player platform''s InputControlAgent . If no player platform exists, this method does nothing.');
INSERT INTO "fts_docs" VALUES ('getAssetRegistry','msd_sim::Engine::getAssetRegistry','Get access to the asset registry. Reference to the asset registry used by this engine');
INSERT INTO "fts_docs" VALUES ('getWorldModel','msd_sim::Engine::getWorldModel','Get access to the world model. Reference to world model');
INSERT INTO "fts_docs" VALUES ('EngineWrapper','EngineWrapper','Python wrapper for msd_sim::Engine . Converts C++ types (Coordinate, AngularCoordinate, Eigen quaternions) to Python-native dicts/tuples internally. No Eigen type casters are exposed. Follows the DatabaseWrapper / AssetRegistryWrapper pattern: all conversion happens inside the C++ wrapper so the Python API stays simple. Ticket:\n 0072a_engine_pybind_bindings');
INSERT INTO "fts_docs" VALUES ('EngineWrapper','EngineWrapper::EngineWrapper','Construct an Engine from an assets database path. dbPath Path to assets.db (created by generate_assets) std::runtime_error if database cannot be opened');
INSERT INTO "fts_docs" VALUES ('spawnInertialObject','EngineWrapper::spawnInertialObject','Spawn a dynamic inertial object into the simulation. assetName Name of the asset in the registry x y z World position [m] pitch roll yaw Initial orientation [rad] mass Mass [kg] restitution Coefficient of restitution [0, 1] friction Friction coefficient [0, inf) dict with "instance_id" and "asset_id" std::runtime_error if asset not found or has no collision geometry');
INSERT INTO "fts_docs" VALUES ('spawnEnvironmentObject','EngineWrapper::spawnEnvironmentObject','Spawn a static environment object into the simulation. assetName Name of the asset in the registry x y z World position [m] pitch roll yaw Initial orientation [rad] dict with "instance_id" and "asset_id" std::runtime_error if asset not found or has no collision geometry');
INSERT INTO "fts_docs" VALUES ('update','EngineWrapper::update','Set the current simulation time (absolute, not delta). The underlying WorldModel::update(simTime) receives the absolute simulation time, not a delta. The caller is responsible for tracking cumulative time and passing an increasing value on each call. Example (60 FPS): for i in range(1, 61): engine.update(i * 16) # 16ms, 32ms, 48ms, ... milliseconds Absolute simulation time [ms]');
INSERT INTO "fts_docs" VALUES ('getFrameState','EngineWrapper::getFrameState','Get the current simulation state for all bodies (inertial and environment). Returns the simulation time plus the state of every asset spawned into the world. Inertial (dynamic) bodies appear first, followed by environment (static) bodies. Each entry includes an is_environment flag so that downstream consumers can distinguish body types without additional metadata. Environment bodies have zeroed velocity and angular_velocity fields because they are immovable by definition. dict with: "simulation_time": float (seconds) "states": list of dicts each containing: "body_id": int "asset_id": int "position": {"x": float, "y": float, "z": float} "velocity": {"x": float, "y": float, "z": float} "orientation": {"w": float, "x": float, "y": float, "z": float} "angular_velocity": {"x": float, "y": float, "z": float} "is_environment": bool (false for inertial, true for environment) Ticket:\n 0072e_live_simulation_cleanup (FR-1)');
INSERT INTO "fts_docs" VALUES ('listAssets','EngineWrapper::listAssets','List all assets available in the registry. List of (asset_id, asset_name) tuples');
INSERT INTO "fts_docs" VALUES ('getCollisionVertices','EngineWrapper::getCollisionVertices','Get the collision hull vertices for an asset by ID. assetId ObjectRecord.id (asset type identifier) List of (x, y, z) tuples, empty if asset not found');
INSERT INTO "fts_docs" VALUES ('EPA','msd_sim::EPA','Expanding Polytope Algorithm ( EPA ) for contact information extraction. EPA computes penetration depth, contact normal, and contact point from a GJK terminating simplex. When GJK detects an intersection, EPA expands the terminating simplex (tetrahedron containing the origin) into a polytope until the closest face to the origin is found, yielding complete collision data. Algorithm steps: Initialize polytope from GJK simplex (4 vertices, 4 triangular faces) Find closest face to origin Query support point in direction of face normal If new point within tolerance, found closest face → terminate Else, remove visible faces, build horizon edges, add new faces Repeat until convergence Contact extraction: Contact normal = closest face normal (normalized, A→B) Penetration depth = distance from origin to closest face Contact point = barycentric centroid of closest face docs/designs/0027a_expanding_polytope_algorithm/0027a_expanding_polytope_algorithm.puml Ticket:\n 0027a_expanding_polytope_algorithm');
INSERT INTO "fts_docs" VALUES ('EPA','msd_sim::EPA::EPA','Construct EPA solver for two physical assets. assetA First physical asset (includes hull and reference frame) assetB Second physical asset (includes hull and reference frame) epsilon Numerical tolerance for convergence (default: 1e-6)');
INSERT INTO "fts_docs" VALUES ('computeContactInfo','msd_sim::EPA::computeContactInfo','Compute contact information from GJK terminating simplex. Assumes simplex contains the origin ( GJK returned true). Expands polytope iteratively until closest face found within tolerance. simplex GJK terminating simplex (4 vertices in Minkowski space) maxIterations Maximum expansion iterations (default: 64) CollisionResult with penetration depth, normal, contact point. If EPA does not fully converge, returns the best approximation from the closest polytope face found so far. std::invalid_argument if simplex size != 4');
INSERT INTO "fts_docs" VALUES ('EPAEdge','msd_sim::EPA::EPAEdge','Edge in polytope for horizon construction.');
INSERT INTO "fts_docs" VALUES ('ExternalForce','msd_sim::ExternalForce','A single external force contribution applied to a rigid body. Stores the linear force, resulting torque, and the world-space application point. Multiple ExternalForce entries are collected per frame; use accumulate() to compute the net result.');
INSERT INTO "fts_docs" VALUES ('toRecord','msd_sim::ExternalForce::toRecord','Convert to a transfer record for database persistence.');
INSERT INTO "fts_docs" VALUES ('fromRecord','msd_sim::ExternalForce::fromRecord','Reconstruct from a transfer record.');
INSERT INTO "fts_docs" VALUES ('accumulate','msd_sim::ExternalForce::accumulate','Sum all individual forces into a single net result. forces Vector of individual force contributions ExternalForce with summed force/torque and mean application point');
INSERT INTO "fts_docs" VALUES ('ExternalForceRecord','msd_transfer::ExternalForceRecord','Database record bundling force and torque as composed sub-records. Groups a ForceVectorRecord and TorqueVectorRecord into a single composite record. Used by AssetDynamicStateRecord to represent the external force/torque accumulator for a rigid body. msd_sim::ExternalForce');
INSERT INTO "fts_docs" VALUES ('FaceIntegrals','msd_sim::inertial_calculations::FaceIntegrals','Face integrals computed over 3D surface. Ticket:\n 0026_mirtich_inertia_tensor');
INSERT INTO "fts_docs" VALUES ('Facet','msd_sim::Facet','Represents a triangular facet of the convex hull. Each facet stores indices into the hull''s vertex array, along with the outward-facing normal vector.');
INSERT INTO "fts_docs" VALUES ('FlattenedConstraints','msd_sim::ConstraintSolver::FlattenedConstraints','Flattened constraint representation: one Jacobian row per entry.');
INSERT INTO "fts_docs" VALUES ('ForceVector','msd_sim::ForceVector','3D force vector type [N] with transfer object support Thin wrapper around Vec3DBase providing: Full Eigen matrix operation compatibility fromRecord/toRecord for database serialization std::format support Memory footprint: 24 bytes (same as Eigen::Vector3d)');
INSERT INTO "fts_docs" VALUES ('ForceVectorRecord','msd_transfer::ForceVectorRecord','Database record for a 3D force vector [N]. Stores the x, y, z components of an msd_sim::ForceVector as individual scalar doubles for human-readable database inspection and queryability.');
INSERT INTO "fts_docs" VALUES ('FrictionConstraint','msd_sim::FrictionConstraint','Friction constraint for two-body contact (two tangential constraint rows). Implements tangential friction constraints for a contact point using two orthogonal tangent directions. Each FrictionConstraint has dimension() = 2 (one row per tangent). Constraint formulation: C_t1(q) = relative tangential velocity in t1 direction C_t2(q) = relative tangential velocity in t2 direction Jacobian J_ti = [ti^T, (rA×ti)^T, -ti^T, -(rB×ti)^T] ∈ R^(1×12) Box constraints (Coulomb cone projection): -μ/√2 · λn ≤ λt1 ≤ μ/√2 · λn -μ/√2 · λn ≤ λt2 ≤ μ/√2 · λn √2 factor distributes circular cone into two orthogonal box constraints Design notes: Tangent basis computed once at construction via TangentBasis::computeTangentBasis() Friction coefficient μ stored (combined from materials, computed externally) Normal force λn updated each solver iteration via setNormalLambda() Follows same 12-DOF Jacobian structure as ContactConstraint (direct angular velocity) Mathematical formulation: docs/designs/0035_friction_constraints/M2-friction-jacobian.md Thread safety: Immutable after construction except setNormalLambda() (not thread-safe) Error handling: Constructor validates normal unit length, mu in [0, ∞) Constraint ContactConstraint docs/designs/0035a_tangent_basis_and_friction_constraint/0035a_tangent_basis_and_friction_constraint.puml Ticket:\n 0035a_tangent_basis_and_friction_constraint');
INSERT INTO "fts_docs" VALUES ('FrictionConstraint','msd_sim::FrictionConstraint::FrictionConstraint','Construct friction constraint for a contact point. bodyAIndex Index of body A in solver body list bodyBIndex Index of body B in solver body list normal Contact normal (A → B, unit length) contactPointA Contact point on A''s surface (world space) [m] contactPointB Contact point on B''s surface (world space) [m] comA Center of mass of body A (world space) [m] comB Center of mass of body B (world space) [m] frictionCoefficient Combined friction coefficient μ [0, ∞) std::invalid_argument if normal is not unit length (within 1e-6) std::invalid_argument if frictionCoefficient < 0 Thread safety: Not thread-safe during construction Complexity: O(1) - computes tangent basis and lever arms once');
INSERT INTO "fts_docs" VALUES ('dimension','msd_sim::FrictionConstraint::dimension','Number of scalar constraint equations (always 2 for friction). 2 (one row for t1 direction, one row for t2 direction)');
INSERT INTO "fts_docs" VALUES ('evaluate','msd_sim::FrictionConstraint::evaluate','Evaluate tangential relative velocities at contact point. Computes: C(0) = v_rel · t1 (relative velocity in first tangent direction) C(1) = v_rel · t2 (relative velocity in second tangent direction) where v_rel = (vA + ωA × rA) - (vB + ωB × rB) stateA Inertial state of body A stateB Inertial state of body B time Simulation time [s] (unused for friction) 2×1 vector of tangential relative velocities [m/s]');
INSERT INTO "fts_docs" VALUES ('jacobian','msd_sim::FrictionConstraint::jacobian','Compute two-body Jacobian for friction constraints. Returns 2×12 matrix: Row 0: J_t1 = [t1^T, (rA×t1)^T, -t1^T, -(rB×t1)^T] Row 1: J_t2 = [t2^T, (rA×t2)^T, -t2^T, -(rB×t2)^T] Each row has structure: [v_A (3), ω_A (3), v_B (3), ω_B (3)] stateA Inertial state of body A (unused, pre-computed geometry) stateB Inertial state of body B (unused, pre-computed geometry) time Simulation time [s] (unused for friction) 2×12 Jacobian matrix');
INSERT INTO "fts_docs" VALUES ('isActive','msd_sim::FrictionConstraint::isActive','Check if friction constraint is active. Friction is active when: Normal contact force λn > 0 (contact is active) Friction coefficient μ > 0 (non-zero friction) stateA Inertial state of body A (unused for activation check) stateB Inertial state of body B (unused for activation check) time Simulation time [s] (unused for activation check) true if friction should be enforced');
INSERT INTO "fts_docs" VALUES ('lambdaBounds','msd_sim::FrictionConstraint::lambdaBounds','Get Lagrange multiplier bounds. Specifies the lower and upper bounds on the constraint''s Lagrange multiplier: Bilateral constraints: (-∞, +∞) Unilateral constraints: (0, +∞) Box-constrained: (lo, hi) LambdaBounds struct with lower and upper fields');
INSERT INTO "fts_docs" VALUES ('bodyCount','msd_sim::FrictionConstraint::bodyCount','Number of bodies involved in this constraint. Single-body constraints ( UnitQuaternionConstraint , DistanceConstraint ) return 1. Two-body constraints ( ContactConstraint , FrictionConstraint ) return 2. 1 for single-body, 2 for two-body');
INSERT INTO "fts_docs" VALUES ('typeName','msd_sim::FrictionConstraint::typeName','Constraint type identifier for debugging/logging. Human-readable constraint type name');
INSERT INTO "fts_docs" VALUES ('recordState','msd_sim::FrictionConstraint::recordState','Record constraint state via visitor pattern. Builds a typed constraint record (ContactConstraintRecord, FrictionConstraintRecord, etc.) and dispatches to the visitor via overload resolution. The visitor decides what to do with the record (e.g., buffer to DataRecorder DAO). Enables compile-time type-safe constraint recording without dynamic_cast or std::any_cast. New constraint types extend ConstraintRecordVisitor with a new visit() overload. visitor Visitor that processes the typed constraint record bodyAId Persistent ID of body A for database FK reference bodyBId Persistent ID of body B for database FK reference (ignored for single-body) msd_transfer::ConstraintRecordVisitor msd_sim::DataRecorderVisitor');
INSERT INTO "fts_docs" VALUES ('setNormalLambda','msd_sim::FrictionConstraint::setNormalLambda','Update normal contact force for friction bound computation. Called by solver each iteration to update friction bounds based on current normal force. Must be called before getFrictionBounds() . normalLambda Normal contact force λn from ContactConstraint [N] Thread safety: Not thread-safe (mutates internal state)');
INSERT INTO "fts_docs" VALUES ('setSlidingMode','msd_sim::FrictionConstraint::setSlidingMode','Enable sliding friction mode with aligned tangent basis. Overrides the tangent basis to align t1 with -slidingDirection (opposing motion), with t2 perpendicular to both t1 and the contact normal. This ensures lambda_t1 directly corresponds to deceleration along the sliding direction. When sliding mode is active, lambda_t1 bounds are made unilateral (>= 0) by the NLopt solver to prevent friction from accelerating in the sliding direction. slidingDirection Unit sliding direction (world frame) Thread safety: Not thread-safe (mutates tangent basis) Ticket:\n 0069_friction_velocity_reversal');
INSERT INTO "fts_docs" VALUES ('setTangentLambdas','msd_sim::FrictionConstraint::setTangentLambdas','Set solved tangent force magnitudes for recording. Called after solver completes to store the actual tangent friction forces (in Newtons) for database recording and visualization. t1Lambda Solved tangent1 force [N] t2Lambda Solved tangent2 force [N]');
INSERT INTO "fts_docs" VALUES ('getFrictionBounds','msd_sim::FrictionConstraint::getFrictionBounds','Get friction force bounds for box-constrained LCP. Returns bounds for friction forces in both tangent directions: Lower bound: -μ/√2 · λn Upper bound: +μ/√2 · λn The √2 factor distributes the circular Coulomb cone into two orthogonal box constraints (inscribed square approximation). {lower_bound, upper_bound} pair [N] Thread safety: Not thread-safe if setNormalLambda() called concurrently Precondition: setNormalLambda() must have been called with valid λn');
INSERT INTO "fts_docs" VALUES ('getTangent1','msd_sim::FrictionConstraint::getTangent1','Get first tangent direction (world space). Unit tangent vector t1');
INSERT INTO "fts_docs" VALUES ('getTangent2','msd_sim::FrictionConstraint::getTangent2','Get second tangent direction (world space). Unit tangent vector t2');
INSERT INTO "fts_docs" VALUES ('getFrictionCoefficient','msd_sim::FrictionConstraint::getFrictionCoefficient','Get friction coefficient. Combined friction coefficient μ');
INSERT INTO "fts_docs" VALUES ('isSlidingMode','msd_sim::FrictionConstraint::isSlidingMode','Check if constraint is in sliding mode. true if sliding mode is active Ticket:\n 0069_friction_velocity_reversal');
INSERT INTO "fts_docs" VALUES ('FrictionConstraintRecord','msd_transfer::FrictionConstraintRecord','Transfer record for friction constraint state. Records the tangent basis and parameters of a friction constraint after constraint creation. Enables visualization of contact frames (normal + two orthogonal tangents) and debugging of friction force magnitudes. Note: All vector fields (normal, tangents, lever arms) are Vector3DRecord (directions), not CoordinateRecord (points), to avoid globalToLocal overload issues when transforming between reference frames.');
INSERT INTO "fts_docs" VALUES ('body_a_id','msd_transfer::FrictionConstraintRecord::body_a_id','ID of body A in the contact pair.');
INSERT INTO "fts_docs" VALUES ('body_b_id','msd_transfer::FrictionConstraintRecord::body_b_id','ID of body B in the contact pair.');
INSERT INTO "fts_docs" VALUES ('normal','msd_transfer::FrictionConstraintRecord::normal','Contact normal in world space (unit vector pointing from B to A).');
INSERT INTO "fts_docs" VALUES ('tangent1','msd_transfer::FrictionConstraintRecord::tangent1','First tangent direction in world space (unit vector orthogonal to normal).');
INSERT INTO "fts_docs" VALUES ('tangent2','msd_transfer::FrictionConstraintRecord::tangent2','Second tangent direction in world space (unit vector orthogonal to normal and tangent1).');
INSERT INTO "fts_docs" VALUES ('lever_arm_a','msd_transfer::FrictionConstraintRecord::lever_arm_a','Lever arm from body A''s center of mass to contact point.');
INSERT INTO "fts_docs" VALUES ('lever_arm_b','msd_transfer::FrictionConstraintRecord::lever_arm_b','Lever arm from body B''s center of mass to contact point.');
INSERT INTO "fts_docs" VALUES ('friction_coefficient','msd_transfer::FrictionConstraintRecord::friction_coefficient','Coefficient of friction (Coulomb friction model).');
INSERT INTO "fts_docs" VALUES ('normal_lambda','msd_transfer::FrictionConstraintRecord::normal_lambda','Normal force magnitude (lambda from constraint solver).');
INSERT INTO "fts_docs" VALUES ('tangent1_lambda','msd_transfer::FrictionConstraintRecord::tangent1_lambda','Tangent1 force magnitude (lambda from constraint solver, Newtons).');
INSERT INTO "fts_docs" VALUES ('tangent2_lambda','msd_transfer::FrictionConstraintRecord::tangent2_lambda','Tangent2 force magnitude (lambda from constraint solver, Newtons).');
INSERT INTO "fts_docs" VALUES ('frame','msd_transfer::FrictionConstraintRecord::frame','Foreign key to simulation frame.');
INSERT INTO "fts_docs" VALUES ('FrictionSpec','msd_sim::FrictionSpec','Friction specification for the cone solver (replaces FrictionConeSpec). Lightweight data structure carrying per-contact friction coefficients and optional tangent1 lower bounds for sliding mode. Ticket:\n 0052b_cone_projection_and_linear_algebra Ticket:\n 0069_friction_velocity_reversal');
INSERT INTO "fts_docs" VALUES ('FullTransformInstanceData','msd_gui::FullTransformInstanceData','Instance data for PositionRotation3DColorTransform shader (full transform rendering). Ticket:\n 0002_remove_rotation_from_gpu Stores full 4x4 model matrix, color, and geometry index for each instance. Size: 96 bytes (80 bytes data + 16 bytes padding for 16-byte alignment)');
INSERT INTO "fts_docs" VALUES ('FullTransformShaderPolicy','msd_gui::FullTransformShaderPolicy','Shader policy for PositionRotation3DColorTransform shader. Ticket:\n 0002_remove_rotation_from_gpu docs/designs/modularize-gpu-shader-system/modularize-gpu-shader-system.puml Provides configuration for full transform rendering with 4x4 model matrices. Uses PositionRotation3DColorTransform.vert shader which supports translation and rotation. Thread safety: All methods are const and stateless (thread-safe)');
INSERT INTO "fts_docs" VALUES ('getVertexAttributes','msd_gui::FullTransformShaderPolicy::getVertexAttributes','Get SDL GPU vertex attribute configuration. Vector of vertex attributes for pipeline creation Configures: Location 0-2: Per-vertex attributes (position, color, normal) from buffer slot 0 Location 3-6: Per-instance model matrix (4x vec4) from buffer slot 1 Location 7: Per-instance color from buffer slot 1 Location 8: Per-instance geometry index from buffer slot 1');
INSERT INTO "fts_docs" VALUES ('getVertexBufferDescriptions','msd_gui::FullTransformShaderPolicy::getVertexBufferDescriptions','Get vertex buffer descriptions for both per-vertex and per-instance data. Vector of buffer descriptions (2 elements: vertex buffer, instance buffer)');
INSERT INTO "fts_docs" VALUES ('buildInstanceData','msd_gui::FullTransformShaderPolicy::buildInstanceData','Build instance data from simulation object. object Source object containing transform, color, and geometry reference geometryNameToIndex Mapping from geometry names to registry indices Serialized instance data ready for GPU upload Extracts full transform (4x4 matrix), color, and geometry index from object.');
INSERT INTO "fts_docs" VALUES ('getVertexShaderFile','msd_gui::FullTransformShaderPolicy::getVertexShaderFile','Get vertex shader filename. Shader filename (without path or backend extension)');
INSERT INTO "fts_docs" VALUES ('getFragmentShaderFile','msd_gui::FullTransformShaderPolicy::getFragmentShaderFile','Get fragment shader filename. Shader filename (without path or backend extension)');
INSERT INTO "fts_docs" VALUES ('getInstanceDataSize','msd_gui::FullTransformShaderPolicy::getInstanceDataSize','Get size of instance data structure. Size in bytes (96 bytes for FullTransformInstanceData )');
INSERT INTO "fts_docs" VALUES ('getVertexInputState','msd_gui::FullTransformShaderPolicy::getVertexInputState','Get complete vertex input state for pipeline creation. Vertex input state combining attributes and buffer descriptions Note: Returned structure contains pointers to internal vectors. The policy object must remain alive while the returned state is in use.');
INSERT INTO "fts_docs" VALUES ('createModelMatrix','msd_gui::FullTransformShaderPolicy::createModelMatrix','Create 4x4 model matrix from reference frame. transform Reference frame containing position and orientation Column-major 4x4 transformation matrix');
INSERT INTO "fts_docs" VALUES ('GeometryFactory','msd_assets::GeometryFactory','Factory class for creating common 3D geometric shapes. Provides static template methods to generate MeshRecord or CollisionMeshRecord objects for standard shapes. All geometries are triangulated and centered at the origin. Usage: auto cube = GeometryFactory::createCube<msd_transfer::MeshRecord> (1.0); auto collisionCube = GeometryFactory::createCube<msd_transfer::CollisionMeshRecord> (1.0);');
INSERT INTO "fts_docs" VALUES ('createCube','msd_assets::GeometryFactory::createCube','Create a cube centered at origin. Creates a cube with side length ''size'', triangulated into 12 triangles (2 per face, 6 faces). Vertices are ordered for proper rendering. The cube extends from -size/2 to +size/2 in all dimensions. T Either MeshRecord or CollisionMeshRecord size Side length of the cube MeshRecord object containing 36 vertices (12 triangles × 3 vertices)');
INSERT INTO "fts_docs" VALUES ('createCubeWireframe','msd_assets::GeometryFactory::createCubeWireframe','Create a wireframe cube (edges only) centered at origin. Creates vertices for the 12 edges of a cube, useful for line rendering. Returns pairs of vertices representing each edge. T Either MeshRecord or CollisionMeshRecord size Side length of the cube MeshRecord object containing 24 vertices (12 edges × 2 vertices)');
INSERT INTO "fts_docs" VALUES ('createPyramid','msd_assets::GeometryFactory::createPyramid','Create a pyramid centered at origin. Creates a pyramid with a square base and apex, triangulated. T Either MeshRecord or CollisionMeshRecord baseSize Side length of the square base height Height of the pyramid MeshRecord object containing pyramid vertices');
INSERT INTO "fts_docs" VALUES ('getCubeCorners','msd_assets::GeometryFactory::getCubeCorners','Helper to create the 8 corner vertices of a cube. size Side length of the cube Array of 8 corner coordinates');
INSERT INTO "fts_docs" VALUES ('verticesToMeshRecord','msd_assets::GeometryFactory::verticesToMeshRecord','Convert vertices to CollisionMeshRecord. Creates a CollisionMeshRecord with hull_data BLOB and bounding box from vertices. vertices Vector of 3D coordinates representing collision hull CollisionMeshRecord with populated hull_data and bounding volume');
INSERT INTO "fts_docs" VALUES ('GeometryInfo','msd_gui::GeometryInfo','Geometry registry entry tracking a geometry type''s location within the unified vertex buffer. Ticket:\n 0001_link-gui-sim-object');
INSERT INTO "fts_docs" VALUES ('GJK','msd_sim::GJK','GJK (Gilbert-Johnson-Keerthi) collision detection algorithm. The GJK algorithm efficiently detects collision between convex shapes by iteratively constructing a simplex in Minkowski difference space that attempts to contain the origin. https://computerwebsite.net/writing/gjk Key insight: Two convex shapes A and B intersect if and only if their Minkowski difference (A ⊖ B) contains the origin. This class maintains the algorithm state (simplex and search direction) as it iterates toward a solution. It works with AssetPhysical objects to support collision detection between objects with arbitrary world-space transformations. docs/designs/0022_gjk_asset_physical_transform/0022_gjk_asset_physical_transform.puml Ticket:\n 0022_gjk_asset_physical_transform');
INSERT INTO "fts_docs" VALUES ('GJK','msd_sim::GJK::GJK','Construct a GJK solver for two physical assets with transformations. assetA First physical asset (includes collision hull and reference frame) assetB Second physical asset (includes collision hull and reference frame) epsilon Numerical tolerance for convergence (default: 1e-6)');
INSERT INTO "fts_docs" VALUES ('intersects','msd_sim::GJK::intersects','Test if the two assets intersect in world space. maxIterations Maximum iterations before giving up (default: 64) true if the assets intersect, false otherwise');
INSERT INTO "fts_docs" VALUES ('getSimplex','msd_sim::GJK::getSimplex','Get the terminating simplex for EPA input. intersects() must have been called and returned true. Behavior is undefined if called before intersects() or after intersects() returned false. Const reference to simplex vertices (4 vertices forming a tetrahedron in Minkowski space that contains the origin)');
INSERT INTO "fts_docs" VALUES ('updateSimplex','msd_sim::GJK::updateSimplex','Update simplex and search direction. true if origin is contained in simplex (collision detected)');
INSERT INTO "fts_docs" VALUES ('handleLine','msd_sim::GJK::handleLine','Handle line simplex case (2 points).');
INSERT INTO "fts_docs" VALUES ('handleTriangle','msd_sim::GJK::handleTriangle','Handle triangle simplex case (3 points).');
INSERT INTO "fts_docs" VALUES ('handleTetrahedron','msd_sim::GJK::handleTetrahedron','Handle tetrahedron simplex case (4 points).');
INSERT INTO "fts_docs" VALUES ('sameDirection','msd_sim::GJK::sameDirection','Check if point is in the same direction as direction vector.');
INSERT INTO "fts_docs" VALUES ('GPUManager','msd_gui::GPUManager','Templated GPU manager for SDL GPU rendering with configurable shader policies. ShaderPolicy Shader policy type (e.g., PositionOnlyShaderPolicy , FullTransformShaderPolicy ) Ticket:\n 0002_remove_rotation_from_gpu docs/designs/modularize-gpu-shader-system/modularize-gpu-shader-system.puml Manages GPU device, pipeline, buffers, and rendering for instanced 3D objects. The shader policy determines vertex attributes, instance data layout, and shader files. Thread safety: Not thread-safe - all operations must occur on the main thread.');
INSERT INTO "fts_docs" VALUES ('GPUManager','msd_gui::GPUManager::GPUManager','Construct a GPUManager with camera reference frame. window SDL window reference (non-owning) cameraFrame Reference frame for camera (non-owning) basePath Base path for shader files NOTE: The provided ReferenceFrame must outlive this GPUManager instance. Typically the ReferenceFrame is owned by a Platform''s visual Object. Ticket:\n 0005_camera_controller_sim');
INSERT INTO "fts_docs" VALUES ('GravityPotential','msd_sim::GravityPotential','Uniform gravitational field potential energy. Implements V = m * g * z where z is the vertical position component. The gravitational vector g is typically (0, 0, -9.81) in z-up convention. Uniform gravity produces constant force F = m*g but no torque (orientation-independent). docs/designs/0030_lagrangian_quaternion_physics/0030_lagrangian_quaternion_physics.puml Ticket:\n 0030_lagrangian_quaternion_physics');
INSERT INTO "fts_docs" VALUES ('GravityPotential','msd_sim::GravityPotential::GravityPotential','Construct gravitational field with specified acceleration vector. gravityVector Gravitational acceleration [m/s²], e.g. (0, 0, -9.81)');
INSERT INTO "fts_docs" VALUES ('computeForce','msd_sim::GravityPotential::computeForce','Compute linear force from potential energy gradient. state Current inertial state mass Object mass [kg] Generalized force F = -∂V/∂X [N]');
INSERT INTO "fts_docs" VALUES ('computeTorque','msd_sim::GravityPotential::computeTorque','Compute torque from potential energy gradient. state Current inertial state inertia Inertia tensor in world frame [kg·m²] Generalized torque τ = -∂V/∂Q [N·m]');
INSERT INTO "fts_docs" VALUES ('computeEnergy','msd_sim::GravityPotential::computeEnergy','Compute potential energy. state Current inertial state mass Object mass [kg] Potential energy V [J]');
INSERT INTO "fts_docs" VALUES ('InertialState','msd_sim::InertialState','Complete kinematic state representation with 7-state quaternion formulation. State vector: (X, Q, Ẋ, Q̇) with 14 components total. Contains position, velocity, and acceleration for both linear and angular motion. Uses quaternion representation for orientation to eliminate gimbal lock singularities. Quaternion rate Q̇ is stored directly for efficiency (avoids ω→Q̇ conversion every step). Conversion formulas: Q̇ → ω: ω = 2 * Q̄ ⊗ Q̇ (where Q̄ is conjugate) ω → Q̇: Q̇ = ½ * Q ⊗ [0, ω] docs/designs/0030_lagrangian_quaternion_physics/0030_lagrangian_quaternion_physics.puml Ticket:\n 0030_lagrangian_quaternion_physics');
INSERT INTO "fts_docs" VALUES ('getAngularVelocity','msd_sim::InertialState::getAngularVelocity','Convert quaternion rate to angular velocity. Angular velocity ω in world frame [rad/s] Formula: ω = 2 * Q̄ ⊗ Q̇ where Q̄ is the conjugate quaternion (w, -x, -y, -z)');
INSERT INTO "fts_docs" VALUES ('setAngularVelocity','msd_sim::InertialState::setAngularVelocity','Set angular velocity (converts to quaternion rate). omega Angular velocity in world frame [rad/s] Formula: Q̇ = ½ * Q ⊗ [0, ω]');
INSERT INTO "fts_docs" VALUES ('getEulerAngles','msd_sim::InertialState::getEulerAngles','Get Euler angles from quaternion (deprecated, for backward compatibility). Euler angles extracted from current quaternion Deprecated Use quaternion representation directly. Euler angles have gimbal lock. Extracts ZYX Euler angles from quaternion using Eigen''s conversion. Warning: This conversion is ambiguous near gimbal lock (pitch ≈ ±90°).');
INSERT INTO "fts_docs" VALUES ('toRecord','msd_sim::InertialState::toRecord','Convert InertialState to a database record. Transfer record containing all state data');
INSERT INTO "fts_docs" VALUES ('omegaToQuaternionRate','msd_sim::InertialState::omegaToQuaternionRate','Convert angular velocity to quaternion rate. omega Angular velocity in world frame [rad/s] Q Current quaternion orientation Quaternion rate Q̇ Formula: Q̇ = ½ * Q ⊗ [0, ω]');
INSERT INTO "fts_docs" VALUES ('quaternionRateToOmega','msd_sim::InertialState::quaternionRateToOmega','Convert quaternion rate to angular velocity. Qdot Quaternion rate Q Current quaternion orientation Angular velocity ω in world frame [rad/s] Formula: ω = 2 * Q̄ ⊗ Q̇');
INSERT INTO "fts_docs" VALUES ('fromRecord','msd_sim::InertialState::fromRecord','Create InertialState from a database record. record The transfer record containing state data Reconstructed InertialState');
INSERT INTO "fts_docs" VALUES ('InertialStateRecord','msd_transfer::InertialStateRecord','Database record for complete kinematic state. Stores the 14-component state vector (X, Q, Ẋ, Q̇) plus acceleration for an msd_sim::InertialState . Uses composition of existing record types for each member. Components: position: 3D spatial coordinate [m] velocity: Linear velocity [m/s] acceleration: Linear acceleration [m/s²] orientation: Unit quaternion (w, x, y, z) quaternionRate: Quaternion time derivative Q̇ angularAcceleration: Angular acceleration [rad/s²] body: Foreign key to AssetInertialStaticRecord for body identification frame: Foreign key to SimulationFrameRecord for timestamping msd_sim::InertialState Ticket:\n 0038_simulation_data_recorder Ticket:\n 0056i_static_asset_recording_and_fk');
INSERT INTO "fts_docs" VALUES ('InputBinding','msd_gui::InputBinding','Binds a key to an action with specified input mode. Encapsulates the binding logic separate from state tracking. The shouldTrigger() method implements mode-specific logic (continuous, once, interval). Thread safety: Not thread-safe (assumes single-threaded execution)');
INSERT INTO "fts_docs" VALUES ('InputBinding','msd_gui::InputBinding::InputBinding','Construct an input binding. key SDL keycode to bind mode Input mode (Continuous, TriggerOnce, Interval, PressAndHold) action Function to execute when triggered interval Interval duration for Interval mode (default: 0ms)');
INSERT INTO "fts_docs" VALUES ('getKey','msd_gui::InputBinding::getKey','Get the bound key. SDL keycode');
INSERT INTO "fts_docs" VALUES ('getMode','msd_gui::InputBinding::getMode','Get the input mode. Input mode enum');
INSERT INTO "fts_docs" VALUES ('shouldTrigger','msd_gui::InputBinding::shouldTrigger','Check if binding should trigger given current input state. state Current input state True if binding should execute Implements mode-specific trigger logic: Continuous: Returns true every frame while key is held TriggerOnce: Returns true only on justPressed Interval: Returns true at fixed intervals while key is held PressAndHold: Returns true on key release');
INSERT INTO "fts_docs" VALUES ('execute','msd_gui::InputBinding::execute','Execute the bound action. Note: No exceptions are caught; action execution failure propagates.');
INSERT INTO "fts_docs" VALUES ('InputCommands','msd_sim::InputCommands','Plain data structure representing current input command state. This struct is the bridge between msd-gui (input source) and msd-sim (consumer). It decouples input representation from simulation logic. Boolean flags indicate command state; velocity/force calculation happens in the agent. Extensible for future commands (attack, interact, etc.). Thread safety: Value type (safe to copy)');
INSERT INTO "fts_docs" VALUES ('reset','msd_sim::InputCommands::reset','Reset all commands to false.');
INSERT INTO "fts_docs" VALUES ('InputControlAgent','msd_sim::InputControlAgent','Agent implementation that translates InputCommands into InertialState updates. Implements the BaseAgent interface to fit cleanly into the simulation architecture. Separates input commands from state update logic. Usage flow: GUI calls setInputCommands() with current input state Engine calls updateState() during simulation update Agent translates boolean commands into velocity/acceleration Thread safety: Not thread-safe');
INSERT INTO "fts_docs" VALUES ('InputControlAgent','msd_sim::InputControlAgent::InputControlAgent','Construct an input control agent. maxSpeed Maximum linear speed in m/s (default: 10.0) maxAngularSpeed Maximum angular speed in rad/s (default: 1.0)');
INSERT INTO "fts_docs" VALUES ('updateState','msd_sim::InputControlAgent::updateState','Update state based on current input commands. currentState Current kinematic state New desired kinematic state Translates boolean commands into velocity updates. Commands are directional (agent converts to velocity in object''s local frame).');
INSERT INTO "fts_docs" VALUES ('setInputCommands','msd_sim::InputControlAgent::setInputCommands','Set current input commands. commands Input commands from GUI Called from Engine when GUI updates input. Commands are stored and applied during the next updateState() call.');
INSERT INTO "fts_docs" VALUES ('getInputCommands','msd_sim::InputControlAgent::getInputCommands','Get current input commands. Const reference to input commands');
INSERT INTO "fts_docs" VALUES ('setMaxSpeed','msd_sim::InputControlAgent::setMaxSpeed','Set maximum linear speed. speed Maximum speed in m/s');
INSERT INTO "fts_docs" VALUES ('setMaxAngularSpeed','msd_sim::InputControlAgent::setMaxAngularSpeed','Set maximum angular speed. speed Maximum angular speed in rad/s');
INSERT INTO "fts_docs" VALUES ('getMaxSpeed','msd_sim::InputControlAgent::getMaxSpeed','Get maximum linear speed. Maximum speed in m/s');
INSERT INTO "fts_docs" VALUES ('getMaxAngularSpeed','msd_sim::InputControlAgent::getMaxAngularSpeed','Get maximum angular speed. Maximum angular speed in rad/s');
INSERT INTO "fts_docs" VALUES ('InputHandler','msd_gui::InputHandler','Manages collection of input bindings and processes them based on InputState . Central coordination point for input processing. Owns InputState (single source of truth) and evaluates all bindings to execute triggered actions. Thread safety: Not thread-safe');
INSERT INTO "fts_docs" VALUES ('addBinding','msd_gui::InputHandler::addBinding','Add an input binding. binding InputBinding to add to the collection');
INSERT INTO "fts_docs" VALUES ('removeBinding','msd_gui::InputHandler::removeBinding','Remove binding for a specific key. key SDL keycode to remove Removes the first binding matching the key. If multiple bindings exist for the same key, only the first is removed.');
INSERT INTO "fts_docs" VALUES ('clearBindings','msd_gui::InputHandler::clearBindings','Clear all bindings.');
INSERT INTO "fts_docs" VALUES ('handleSDLEvent','msd_gui::InputHandler::handleSDLEvent','Handle SDL event and update input state. event SDL event to process Processes SDL_EVENT_KEY_DOWN and SDL_EVENT_KEY_UP events to update the internal InputState . Other event types are ignored.');
INSERT INTO "fts_docs" VALUES ('update','msd_gui::InputHandler::update','Update frame timing and clear frame-specific flags. deltaTime Time elapsed since last update Advances the internal InputState time and clears justPressed flags. Call this once per frame after processing all SDL events.');
INSERT INTO "fts_docs" VALUES ('processInput','msd_gui::InputHandler::processInput','Process all bindings and execute triggered actions. Evaluates all bindings against the current InputState and executes actions for bindings that should trigger. Call this after update() .');
INSERT INTO "fts_docs" VALUES ('getInputState','msd_gui::InputHandler::getInputState','Get read-only access to the input state. Const reference to InputState');
INSERT INTO "fts_docs" VALUES ('InputState','msd_gui::InputState','Tracks the current state of all keyboard inputs. Provides centralized input state tracking with timestamp information for duration-based queries. Separates state tracking from input handling logic. Thread safety: Not thread-safe (single-threaded GUI operation assumed)');
INSERT INTO "fts_docs" VALUES ('updateKey','msd_gui::InputState::updateKey','Update the state of a key from SDL event. key The SDL keycode pressed True if key is pressed, false if released');
INSERT INTO "fts_docs" VALUES ('isKeyPressed','msd_gui::InputState::isKeyPressed','Query if a key is currently pressed. key The SDL keycode to query True if key is currently pressed');
INSERT INTO "fts_docs" VALUES ('isKeyJustPressed','msd_gui::InputState::isKeyJustPressed','Query if a key was just pressed this frame. key The SDL keycode to query True if key was pressed this frame (before update() clears it)');
INSERT INTO "fts_docs" VALUES ('isKeyHeld','msd_gui::InputState::isKeyHeld','Query if a key is held down. key The SDL keycode to query True if key is currently pressed This is currently equivalent to isKeyPressed, provided for semantic clarity');
INSERT INTO "fts_docs" VALUES ('getKeyHoldDuration','msd_gui::InputState::getKeyHoldDuration','Get the duration a key has been held. key The SDL keycode to query Duration in milliseconds (0 if key not pressed)');
INSERT INTO "fts_docs" VALUES ('update','msd_gui::InputState::update','Update frame timing and clear frame-specific flags. deltaTime Time elapsed since last update This advances the internal time and clears justPressed flags for all keys. Call this once per frame after processing all SDL events.');
INSERT INTO "fts_docs" VALUES ('reset','msd_gui::InputState::reset','Reset all key states. Clears all tracked key states and resets internal time to zero.');
INSERT INTO "fts_docs" VALUES ('Integrator','msd_sim::Integrator','Abstract interface for numerical integration of rigid body dynamics. Decouples the integration scheme from the physics computation, enabling: Swappable integrators (Euler, RK4, Verlet, etc.) Isolated testing of integration math WorldModel as pure orchestrator Ticket 0031 breaking change: Replaced QuaternionConstraint & with std::vector<Constraint*>& to support arbitrary constraint combinations. Thread safety: Implementations should be stateless and thread-safe docs/designs/0030_lagrangian_quaternion_physics/0030_lagrangian_quaternion_physics.puml docs/designs/0031_generalized_lagrange_constraints/0031_generalized_lagrange_constraints.puml Ticket:\n 0030_lagrangian_quaternion_physics Ticket:\n 0031_generalized_lagrange_constraints');
INSERT INTO "fts_docs" VALUES ('step','msd_sim::Integrator::step','Integrate state forward by one timestep. state Current inertial state (modified in place) force Net force in world frame [N] torque Net torque in world frame [N·m] mass Object mass [kg] inverseInertia Inverse inertia tensor in body frame [1/(kg·m²)] dt Timestep [s] Ticket 0045 breaking change: Removed constraints parameter. Quaternion normalization is now handled via state.orientation.normalize() instead of UnitQuaternionConstraint . Ticket:\n 0045_constraint_solver_unification');
INSERT INTO "fts_docs" VALUES ('Island','msd_sim::ConstraintIslandBuilder::Island','One independent contact island. An island is a connected component in the contact graph. All constraints in an island share at least one body with another constraint in the same island (via transitive connectivity). Bodies with no contacts do not appear in any island.');
INSERT INTO "fts_docs" VALUES ('constraints','msd_sim::ConstraintIslandBuilder::Island::constraints','Non-owning pointers into owning container.');
INSERT INTO "fts_docs" VALUES ('bodyIndices','msd_sim::ConstraintIslandBuilder::Island::bodyIndices','Unique body indices (inertial + environment).');
INSERT INTO "fts_docs" VALUES ('KeyState','msd_gui::KeyState','State information for a single key. Tracks whether a key is pressed, just pressed (this frame), and timing information for duration-based queries and interval-based triggers.');
INSERT INTO "fts_docs" VALUES ('LambdaBounds','msd_sim::LambdaBounds','Represents lower and upper bounds on a constraint''s Lagrange multiplier. LambdaBounds is a value type that encodes the multiplier bound semantics for different constraint types: Bilateral constraints: λ ∈ (-∞, +∞) — unconstrained multiplier Unilateral constraints: λ ∈ [0, +∞) — non-negative multiplier (inequalities) Box-constrained: λ ∈ [lo, hi] — bounded multiplier (friction cone) Factory methods provide semantic construction, and query methods enable solver dispatch without dynamic_cast. docs/designs/0043_constraint_hierarchy_refactor/0043_constraint_hierarchy_refactor.puml Ticket:\n 0043_constraint_hierarchy_refactor');
INSERT INTO "fts_docs" VALUES ('bilateral','msd_sim::LambdaBounds::bilateral','Create bilateral (equality) constraint bounds: λ ∈ (-∞, +∞). LambdaBounds with infinite range in both directions');
INSERT INTO "fts_docs" VALUES ('unilateral','msd_sim::LambdaBounds::unilateral','Create unilateral (inequality) constraint bounds: λ ∈ [0, +∞). LambdaBounds with non-negative range');
INSERT INTO "fts_docs" VALUES ('boxConstrained','msd_sim::LambdaBounds::boxConstrained','Create box-constrained bounds: λ ∈ [lo, hi]. lo Lower bound on multiplier hi Upper bound on multiplier LambdaBounds with custom range');
INSERT INTO "fts_docs" VALUES ('isBilateral','msd_sim::LambdaBounds::isBilateral','Check if this represents bilateral (equality) constraint bounds. true if λ ∈ (-∞, +∞)');
INSERT INTO "fts_docs" VALUES ('isUnilateral','msd_sim::LambdaBounds::isUnilateral','Check if this represents unilateral (inequality) constraint bounds. true if λ ∈ [0, +∞)');
INSERT INTO "fts_docs" VALUES ('isBoxConstrained','msd_sim::LambdaBounds::isBoxConstrained','Check if this represents box-constrained bounds. true if neither bilateral nor unilateral');
INSERT INTO "fts_docs" VALUES ('MaterialProperties','msd_sim::MaterialProperties','Surface material properties shared by inertial and environment assets. Consolidates coefficient of restitution and friction coefficient with validated setters, eliminating duplicated validation logic between AssetInertial and AssetEnvironment . Ticket:\n 0056a_collision_force_transfer_records');
INSERT INTO "fts_docs" VALUES ('setCoefficientOfRestitution','msd_sim::MaterialProperties::setCoefficientOfRestitution','Set the coefficient of restitution. e Coefficient of restitution [0, 1] std::invalid_argument if e not in [0, 1]');
INSERT INTO "fts_docs" VALUES ('setFrictionCoefficient','msd_sim::MaterialProperties::setFrictionCoefficient','Set the friction coefficient. mu Friction coefficient [0, inf) std::invalid_argument if mu < 0');
INSERT INTO "fts_docs" VALUES ('MaterialRecord','msd_transfer::MaterialRecord','Database record for rendering materials. Stores shader references and default material properties for rendering. Future extension point for PBR materials, textures, etc.');
INSERT INTO "fts_docs" VALUES ('MeshRecord','msd_transfer::MeshRecord','Database record for visual mesh geometry. Stores visual rendering mesh data (positions, normals, colors). This is a standalone table referenced by ObjectRecord .');
INSERT INTO "fts_docs" VALUES ('MinkowskiVertex','msd_sim::MinkowskiVertex','Minkowski difference vertex with witness point tracking. Used internally by EPA to maintain the association between Minkowski space points and their contributing surface points. This enables extraction of physical contact locations after EPA convergence. Ticket:\n 0028_epa_witness_points');
INSERT INTO "fts_docs" VALUES ('MotionController','msd_sim::MotionController','Encapsulates 3D motion control logic for simulation objects. Translates input commands into ReferenceFrame updates (translation and rotation). Replaces msd-gui::CameraController with simulation-appropriate implementation. Supports frame-rate independent movement through delta-time scaling. Movement is applied in the local coordinate frame of the provided ReferenceFrame . docs/designs/0005_camera_controller_sim/0005_camera_controller_sim.puml Ticket:\n 0005_camera_controller_sim Thread safety: Not thread-safe (modifies ReferenceFrame in place)');
INSERT INTO "fts_docs" VALUES ('MotionController','msd_sim::MotionController::MotionController','Construct a motion controller. rotSpeed Rotation speed in radians per second (default: 0.05 rad/s) moveSpeed Movement speed in units per second (default: 0.1 m/s)');
INSERT INTO "fts_docs" VALUES ('updateTransform','msd_sim::MotionController::updateTransform','Update a ReferenceFrame based on input commands. frame ReferenceFrame to update (non-owning reference) commands Input commands (boolean flags) deltaTime Time elapsed since last update (for frame-rate independence) Applies linear movement in local frame: moveForward: -Z local direction moveBackward: +Z local direction moveLeft: -X local direction moveRight: +X local direction moveUp: +Y local direction moveDown: -Y local direction Applies rotation: pitchUp: Increase pitch angle pitchDown: Decrease pitch angle yawLeft: Increase yaw angle yawRight: Decrease yaw angle All movements scaled by moveSpeed * sensitivity and deltaTime. All rotations scaled by rotSpeed and deltaTime.');
INSERT INTO "fts_docs" VALUES ('setMoveSpeed','msd_sim::MotionController::setMoveSpeed','Set movement speed. speed Units per second');
INSERT INTO "fts_docs" VALUES ('setRotationSpeed','msd_sim::MotionController::setRotationSpeed','Set rotation speed. speed Radians per second');
INSERT INTO "fts_docs" VALUES ('setSensitivity','msd_sim::MotionController::setSensitivity','Set input sensitivity multiplier. sensitivity Multiplier for input (default: 1.0)');
INSERT INTO "fts_docs" VALUES ('getMoveSpeed','msd_sim::MotionController::getMoveSpeed','Get movement speed. Units per second');
INSERT INTO "fts_docs" VALUES ('getRotationSpeed','msd_sim::MotionController::getRotationSpeed','Get rotation speed. Radians per second');
INSERT INTO "fts_docs" VALUES ('getSensitivity','msd_sim::MotionController::getSensitivity','Get input sensitivity. Sensitivity multiplier');
INSERT INTO "fts_docs" VALUES ('NLoptFrictionSolver','msd_sim::NLoptFrictionSolver','NLopt-based solver for the friction cone constrained QP. Solves: minimize f(lambda) = (1/2) lambda^T A lambda - b^T lambda subject to mu_i^2 * lambda_n_i^2 - lambda_t1_i^2 - lambda_t2_i^2 >= 0 (cone constraint) lambda_n_i >= 0 (non-penetration) Uses NLopt''s SLSQP (Sequential Quadratic Programming) by default for efficient handling of quadratic objectives with nonlinear constraints. Supports warm-starting from previous frame''s solution via ContactCache . docs/designs/0068_nlopt_friction_cone_solver/0068_nlopt_friction_cone_solver.puml Ticket:\n 0068b_nlopt_friction_solver_class');
INSERT INTO "fts_docs" VALUES ('Algorithm','msd_sim::NLoptFrictionSolver::Algorithm','Algorithm selection for NLopt.');
INSERT INTO "fts_docs" VALUES ('tolerance_','msd_sim::NLoptFrictionSolver::tolerance_','Convergence tolerance.');
INSERT INTO "fts_docs" VALUES ('max_iterations_','msd_sim::NLoptFrictionSolver::max_iterations_','Maximum iterations.');
INSERT INTO "fts_docs" VALUES ('algorithm_','msd_sim::NLoptFrictionSolver::algorithm_','NLopt algorithm.');
INSERT INTO "fts_docs" VALUES ('NLoptFrictionSolver','msd_sim::NLoptFrictionSolver::NLoptFrictionSolver','Construct with default settings (SLSQP, 1e-6 tolerance, 100 max iterations).');
INSERT INTO "fts_docs" VALUES ('NLoptFrictionSolver','msd_sim::NLoptFrictionSolver::NLoptFrictionSolver','Construct with specified algorithm. algo NLopt algorithm to use');
INSERT INTO "fts_docs" VALUES ('~NLoptFrictionSolver','msd_sim::NLoptFrictionSolver::~NLoptFrictionSolver','Default destructor.');
INSERT INTO "fts_docs" VALUES ('solve','msd_sim::NLoptFrictionSolver::solve','Solve the friction cone constrained QP. A Effective mass matrix (3C x 3C), symmetric positive definite b RHS vector (3C x 1) with restitution/velocity terms mu Per-contact friction coefficients (C entries). Invalid values (< 0) clamped to 0. lambda0 Warm-start vector (3C x 1). If empty or wrong size, cold start from zero. normalUpperBounds Per-contact upper bounds on normal impulses (C entries). If non-empty, constrains lambda_n_i <= normalUpperBounds[i]. Used to prevent the coupled QP from inflating normal impulses beyond non-penetration needs. tangent1LowerBounds Per-contact lower bounds on tangent1 impulses (C entries). If non-empty, constrains lambda_t1_i >= tangent1LowerBounds[i]. Used to prevent friction from reversing sliding direction (typically 0.0 for sliding mode, omitted for bilateral friction). Default: empty (bilateral). SolveResult with optimal lambda and diagnostics Ticket:\n 0069_friction_velocity_reversal');
INSERT INTO "fts_docs" VALUES ('setTolerance','msd_sim::NLoptFrictionSolver::setTolerance','Set convergence tolerance (default: 1e-6).');
INSERT INTO "fts_docs" VALUES ('setMaxIterations','msd_sim::NLoptFrictionSolver::setMaxIterations','Set maximum iterations (default: 100).');
INSERT INTO "fts_docs" VALUES ('setAlgorithm','msd_sim::NLoptFrictionSolver::setAlgorithm','Set NLopt algorithm (default: SLSQP).');
INSERT INTO "fts_docs" VALUES ('getTolerance','msd_sim::NLoptFrictionSolver::getTolerance','Get current tolerance.');
INSERT INTO "fts_docs" VALUES ('getMaxIterations','msd_sim::NLoptFrictionSolver::getMaxIterations','Get current max iterations.');
INSERT INTO "fts_docs" VALUES ('getAlgorithm','msd_sim::NLoptFrictionSolver::getAlgorithm','Get current algorithm.');
INSERT INTO "fts_docs" VALUES ('objective','msd_sim::NLoptFrictionSolver::objective','Objective function callback for NLopt: f(lambda) = (1/2) lambda^T A lambda - b^T lambda. lambda Current iterate (3C x 1) grad Output gradient (3C x 1): grad = A*lambda - b data Pointer to ObjectiveData struct Objective function value');
INSERT INTO "fts_docs" VALUES ('coneConstraint','msd_sim::NLoptFrictionSolver::coneConstraint','Cone constraint callback for contact i: c_i(lambda) = mu^2*n^2 - t1^2 - t2^2. Note: NLopt expects constraints as c(x) <= 0, so we negate to -c(x) <= 0 which is equivalent to c(x) >= 0. lambda Current iterate (3C x 1) grad Output gradient (3 x 1): [2*mu^2*n, -2*t1, -2*t2] data Pointer to ConstraintData struct Constraint value (negated for NLopt convention)');
INSERT INTO "fts_docs" VALUES ('ObjectiveData','msd_sim::NLoptFrictionSolver::ObjectiveData','Data passed to objective function.');
INSERT INTO "fts_docs" VALUES ('ObjectRecord','msd_transfer::ObjectRecord','Database record representing a complete object definition. This is the main record that ties together visual and collision geometry. It contains foreign keys to MeshRecord (visual) and CollisionMeshRecord (collision). Objects can have: Both visual and collision mesh (most common for physics objects) Only visual mesh (visual-only objects, no physics) Only collision mesh (invisible collision volumes)');
INSERT INTO "fts_docs" VALUES ('PhysicsTemplateRecord','msd_transfer::PhysicsTemplateRecord','Database record for complete physics object templates. Combines mesh reference (which contains both visual and collision data) and physical properties (mass, friction, etc.) into a reusable template for creating rigid body instances.');
INSERT INTO "fts_docs" VALUES ('Platform','msd_sim::Platform','Platform entity with kinematic state and agent control. Platform owns an agent that controls its state and optionally links to an Object in WorldModel for visual representation synchronization. Per AC7: Agent logic is placed in Platform (not Object) Per AC3: Each Platform has its own non-unique internal state Thread safety: Not thread-safe');
INSERT INTO "fts_docs" VALUES ('id_','msd_sim::Platform::id_','Platform ID.');
INSERT INTO "fts_docs" VALUES ('agent_','msd_sim::Platform::agent_','Agent controlling the platform.');
INSERT INTO "fts_docs" VALUES ('inertialAsset_','msd_sim::Platform::inertialAsset_','Optional reference to visual object in WorldModel .');
INSERT INTO "fts_docs" VALUES ('lastUpdateTime_','msd_sim::Platform::lastUpdateTime_','Last update time.');
INSERT INTO "fts_docs" VALUES ('motionController_','msd_sim::Platform::motionController_','Motion controller for transform updates.');
