INSERT INTO "fts_docs" VALUES ('PositionCorrector','msd_sim::PositionCorrector','Position-level contact correction using pseudo-velocities. Corrects penetration depth by computing position-level impulses that modify body positions and orientations without affecting real velocities. This is the position correction pass of the split impulse approach. Algorithm: For each contact, compute position-level bias: b_pos = (beta/dt) * max(depth - slop, 0) Build effective mass matrix A = J * M^-1 * J^T Solve A * lambda_pos = b_pos with lambda_pos >= 0 (using ASM) Compute pseudo-velocity: dv_pseudo = M^-1 * J^T * lambda_pos Apply as position change: dx = dv_pseudo * dt Discard pseudo-velocity (never becomes kinetic energy) Ticket:\n 0040b_split_impulse_position_correction');
INSERT INTO "fts_docs" VALUES ('bodyMInv_','msd_sim::PositionCorrector::bodyMInv_','Per-body 6x6 inverse mass matrix.');
INSERT INTO "fts_docs" VALUES ('activeIndices_','msd_sim::PositionCorrector::activeIndices_','ASM active constraint set.');
INSERT INTO "fts_docs" VALUES ('correctPositions','msd_sim::PositionCorrector::correctPositions','Correct body positions to resolve penetration (default config).');
INSERT INTO "fts_docs" VALUES ('correctPositions','msd_sim::PositionCorrector::correctPositions','Correct body positions to resolve penetration. Computes and applies position corrections for all active contacts. Only modifies position and orientation of bodies with non-zero inverse mass. Bodies with inverseMass == 0 (environment) are skipped. contactConstraints Active contact constraints with per-contact depth states Inertial states for all bodies (mutable for position updates) inverseMasses Per-body inverse mass [1/kg] (0 for static) inverseInertias Per-body inverse inertia tensors (world frame) numBodies Total bodies in solver (inertial + environment) numInertial Number of inertial (dynamic) bodies dt Timestep [s] config Position correction parameters');
