INSERT INTO "fts_docs" VALUES ('PotentialEnergy','msd_sim::PotentialEnergy','Abstract interface for environmental potential energy fields. This interface enables extensible potential energy computation for rigid body dynamics. Implementations compute generalized forces from energy gradients. Lagrangian formulation: L = T - V where T is kinetic energy, V is potential energy Generalized forces: F = -∂V/∂X (linear force from position gradient) τ = -∂V/∂Q (torque from orientation gradient) Note: These are ENVIRONMENTAL potentials (gravity, magnetic fields) that apply uniformly to all objects. Per-object forces (thrusters, springs) would be handled separately in AssetInertial . Thread safety: Read-only methods after construction (thread-safe) docs/designs/0030_lagrangian_quaternion_physics/0030_lagrangian_quaternion_physics.puml Ticket:\n 0030_lagrangian_quaternion_physics');
INSERT INTO "fts_docs" VALUES ('computeForce','msd_sim::PotentialEnergy::computeForce','Compute linear force from potential energy gradient. state Current inertial state mass Object mass [kg] Generalized force F = -∂V/∂X [N]');
INSERT INTO "fts_docs" VALUES ('computeTorque','msd_sim::PotentialEnergy::computeTorque','Compute torque from potential energy gradient. state Current inertial state inertia Inertia tensor in world frame [kg·m²] Generalized torque τ = -∂V/∂Q [N·m]');
INSERT INTO "fts_docs" VALUES ('computeEnergy','msd_sim::PotentialEnergy::computeEnergy','Compute potential energy. state Current inertial state mass Object mass [kg] Potential energy V [J]');
INSERT INTO "fts_docs" VALUES ('ProjectedGaussSeidel','msd_sim::ProjectedGaussSeidel','O(n)-per-sweep iterative LCP solver using Projected Gauss-Seidel. Used by ConstraintSolver as the solver backend for large constraint islands (numRows > kASMThreshold). PGS has O(n) cost per sweep and scales linearly with problem size, making it ~40x cheaper per sweep than a single ASM pivot at 160 constraints. Algorithm (Catto 2005): For each sweep, for each constraint row i: delta_i = (b_i - J_i * v_res) / A_ii using velocity-residual approach For normal rows: lambda_i = max(0, lambda_i + delta_i) For friction rows: solve both tangent components, then ball-project the 2D tangent vector onto the friction disk ||lambda_t|| <= mu * lambda_n Velocity-residual approach (O(n) workspace): v_res (6 * numBodies doubles) accumulates M^{-1} * J^T * lambda After each lambda update: v_res += M^{-1} * J_i^T * delta_lambda_i Off-diagonal contribution for row i: J_i * v_res Friction coupling (R1 from design review): PGS applies ball-projection directly on friction rows, bypassing FrictionConstraint::lambdaBounds() . The ball-projection cone (||lambda_t|| <= mu*lambda_n) is consistent with the decoupled solver from ticket 0070. setNormalLambda() is NOT called during PGS sweeps. docs/designs/0073_hybrid_pgs_large_islands/design.md Ticket:\n 0073_hybrid_pgs_large_islands');
INSERT INTO "fts_docs" VALUES ('kLinearDof','msd_sim::ProjectedGaussSeidel::kLinearDof','Linear velocity components per body.');
INSERT INTO "fts_docs" VALUES ('kAngularDof','msd_sim::ProjectedGaussSeidel::kAngularDof','Angular velocity components per body.');
INSERT INTO "fts_docs" VALUES ('kBodyDof','msd_sim::ProjectedGaussSeidel::kBodyDof','DOF per body (6).');
INSERT INTO "fts_docs" VALUES ('kTwoBodyDof','msd_sim::ProjectedGaussSeidel::kTwoBodyDof','DOF per two-body constraint (12).');
INSERT INTO "fts_docs" VALUES ('vRes_','msd_sim::ProjectedGaussSeidel::vRes_','Velocity residual workspace: v_res[kBodyDof*k .. kBodyDof*k+5] = accumulated M^{-1} * J^T * lambda for body k. Resized per solve() call.');
INSERT INTO "fts_docs" VALUES ('rows_','msd_sim::ProjectedGaussSeidel::rows_','Flattened per-row data for PGS sweep. Cleared and refilled each solve() .');
INSERT INTO "fts_docs" VALUES ('muPerContact_','msd_sim::ProjectedGaussSeidel::muPerContact_','Friction coefficient per contact (indexed by Normal row order). Cleared and refilled each solve() .');
INSERT INTO "fts_docs" VALUES ('diag_','msd_sim::ProjectedGaussSeidel::diag_','Diagonal effective-mass elements A_ii. Resized each solve() .');
INSERT INTO "fts_docs" VALUES ('b_','msd_sim::ProjectedGaussSeidel::b_','RHS vector b. Resized each solve() .');
INSERT INTO "fts_docs" VALUES ('lambda_','msd_sim::ProjectedGaussSeidel::lambda_','Constraint multiplier vector. Resized each solve() .');
INSERT INTO "fts_docs" VALUES ('solve','msd_sim::ProjectedGaussSeidel::solve','Solve mixed LCP using Projected Gauss-Seidel. Accepts an interleaved [CC, FC, CC, FC, ...] constraint list. Uses ConstraintSolver::flattenConstraints() to expand multi-row constraints into per-row entries, then performs PGS sweeps. Friction rows use ball-projection (not lambdaBounds() box bounds). setNormalLambda() is NOT called during PGS sweeps (bypassed by design). constraints Interleaved ContactConstraint and FrictionConstraint ptrs states Per-body kinematic state inverseMasses Per-body inverse mass (size = numBodies) inverseInertias Per-body inverse inertia tensor (size = numBodies) numBodies Number of bodies in the system dt Timestep [s] initialLambda Warm-start vector (same size as active rows); zeros if empty or wrong size. SolveResult with bodyForces, lambdas, iterations, converged, residual');
INSERT INTO "fts_docs" VALUES ('setMaxSweeps','msd_sim::ProjectedGaussSeidel::setMaxSweeps','Set maximum sweep count (default: 50).');
INSERT INTO "fts_docs" VALUES ('setConvergenceTolerance','msd_sim::ProjectedGaussSeidel::setConvergenceTolerance','Set convergence tolerance: early exit when max |delta_lambda| < tol (default: 1e-6)');
INSERT INTO "fts_docs" VALUES ('sweepOnce','msd_sim::ProjectedGaussSeidel::sweepOnce','Execute one Gauss-Seidel sweep using velocity-residual approach. Processes rows in flat order. When a Normal row is followed by two Tangent rows (standard friction pair), they are solved together with ball-projection. Updates vRes_ member in-place. rows Flattened per-row data muPerContact Friction coefficient per contact (indexed by contact) diag Diagonal effective-mass elements A_ii (size = numRows) b RHS vector (size = numRows) lambda In/out lambda vector updated in-place inverseMasses Per-body inverse mass inverseInertias Per-body inverse inertia max |delta_lambda| this sweep (for convergence check)');
INSERT INTO "fts_docs" VALUES ('updateVRes','msd_sim::ProjectedGaussSeidel::updateVRes','Update velocity residual after a lambda change on row rowIdx. vRes_ += M^{-1} * J_i^T * dLambda.');
INSERT INTO "fts_docs" VALUES ('ProjectionIntegrals','msd_sim::inertial_calculations::ProjectionIntegrals','Projection integrals computed over 2D polygon projection. Ticket:\n 0026_mirtich_inertia_tensor');
INSERT INTO "fts_docs" VALUES ('QuatDBase','msd_sim::detail::QuatDBase','CRTP base class for quaternion types. Wraps Eigen::Quaterniond via composition (not inheritance, since Eigen::Quaterniond is not a matrix type). Uses Eigen/Hamilton convention: q = w + xi + yj + zk Derived The derived type (CRTP pattern)');
INSERT INTO "fts_docs" VALUES ('QuaternionConstraint','msd_sim::QuaternionConstraint','Enforces unit quaternion constraint via Lagrange multipliers. Maintains the constraint g(Q) = QᵀQ - 1 = 0 using Baumgarte stabilization to correct drift accumulated during numerical integration. Constraint equations: Position: g(Q) = QᵀQ - 1 = 0 Velocity : ġ = 2QᵀQ̇ = 0 (Q̇ ⊥ Q) Baumgarte stabilization computes Lagrange multiplier as: λ = -α * g - β * ġ where α, β > 0 are tuning parameters. Ownership: Each AssetInertial owns its own QuaternionConstraint instance, since the constraint operates on per-object quaternion state. Thread safety: Not thread-safe (modifies quaternion state) docs/designs/0030_lagrangian_quaternion_physics/0030_lagrangian_quaternion_physics.puml Ticket:\n 0030_lagrangian_quaternion_physics');
INSERT INTO "fts_docs" VALUES ('QuaternionConstraint','msd_sim::QuaternionConstraint::QuaternionConstraint','Construct constraint with Baumgarte parameters. alpha Position error gain (default: 10.0) beta Velocity error gain (default: 10.0)');
INSERT INTO "fts_docs" VALUES ('enforceConstraint','msd_sim::QuaternionConstraint::enforceConstraint','Enforce unit quaternion constraint with Baumgarte stabilization. Modifies Q and Qdot to satisfy: Normalize Q to unit length Project Qdot onto tangent space (perpendicular to Q) Apply Baumgarte correction to reduce drift Q Quaternion to constrain (modified in place) Qdot Quaternion rate (modified in place)');
INSERT INTO "fts_docs" VALUES ('computeConstraintForce','msd_sim::QuaternionConstraint::computeConstraintForce','Compute constraint force for dynamics integration. Q Current quaternion Qdot Current quaternion rate Constraint force F_c = G^T * λ where G = ∂g/∂Q');
INSERT INTO "fts_docs" VALUES ('QuaternionD','msd_sim::QuaternionD','Quaternion type with transfer object support. Thin wrapper around Eigen::Quaterniond providing: Access to underlying Eigen quaternion via eigen() fromRecord/toRecord for database serialization std::format support Uses Eigen/Hamilton convention: q = w + xi + yj + zk Memory footprint: 32 bytes (same as Eigen::Quaterniond)');
INSERT INTO "fts_docs" VALUES ('QuaternionDRecord','msd_transfer::QuaternionDRecord','Database record for a quaternion (double precision). Stores the w, x, y, z components of an msd_sim::QuaternionD as individual scalar doubles for human-readable database inspection and queryability. Uses Eigen/Hamilton convention: q = w + xi + yj + zk where w is the scalar (real) part and (x, y, z) is the vector (imaginary) part.');
INSERT INTO "fts_docs" VALUES ('ReferenceFrame','msd_sim::ReferenceFrame','A reference frame for coordinate transformations. This class represents a reference frame that can be translated and rotated relative to a global frame. It uses AngularCoordinate (pitch, roll, yaw) for rotation specification and provides methods to transform coordinates between the global frame and the local frame. Rotation order: ZYX (yaw-pitch-roll) intrinsic rotations Roll: rotation around X-axis (component 1) Pitch: rotation around Y-axis (component 0) Yaw: rotation around Z-axis (component 2) docs/designs/0024_angular_coordinate/0024_angular_coordinate.puml Ticket:\n 0024_angular_coordinate');
INSERT INTO "fts_docs" VALUES ('origin_','msd_sim::ReferenceFrame::origin_','Origin of this frame in global coordinates.');
INSERT INTO "fts_docs" VALUES ('angular_','msd_sim::ReferenceFrame::angular_','Orientation angles (pitch, roll, yaw).');
INSERT INTO "fts_docs" VALUES ('ReferenceFrame','msd_sim::ReferenceFrame::ReferenceFrame','Default constructor - creates identity frame at origin.');
INSERT INTO "fts_docs" VALUES ('ReferenceFrame','msd_sim::ReferenceFrame::ReferenceFrame','Constructor with translation only. origin The origin of this frame in global coordinates');
INSERT INTO "fts_docs" VALUES ('ReferenceFrame','msd_sim::ReferenceFrame::ReferenceFrame','Constructor with translation and rotation. origin The origin of this frame in global coordinates angular The angular coordinate defining the rotation');
INSERT INTO "fts_docs" VALUES ('ReferenceFrame','msd_sim::ReferenceFrame::ReferenceFrame','Constructor from local X and Z axes (right-hand rule). Constructs a reference frame from two vectors representing the local X-axis (tangent direction) and Z-axis (normal direction). The Y-axis is computed using the cross product Y = Z × X to follow the right-hand rule. The input vectors do not need to be normalized or perfectly orthogonal - they will be processed as follows: Z is normalized (takes precedence as the primary/normal direction) X is orthogonalized against Z and normalized Y is computed as Z × X This is useful for constructing a local coordinate frame based on a surface normal (Z) and tangent direction (X), common in collision response. origin The origin of this frame in global coordinates xDirection Vector representing the local positive X-axis direction zDirection Vector representing the local positive Z-axis direction std::invalid_argument if either vector is zero or if vectors are parallel');
INSERT INTO "fts_docs" VALUES ('ReferenceFrame','msd_sim::ReferenceFrame::ReferenceFrame','Constructor with origin and quaternion orientation. Constructs a reference frame using a quaternion to specify orientation. The quaternion will be normalized internally for robustness. origin The origin of this frame in global coordinates quaternion The orientation as a unit quaternion (will be normalized)');
