INSERT INTO "fts_docs" VALUES ('extractEulerAngles','msd_sim::ReferenceFrame::extractEulerAngles','Extract Euler angles (ZYX convention) from a rotation matrix. Extracts pitch, roll, yaw angles from a rotation matrix using the ZYX intrinsic rotation convention (R = Rz(yaw) * Ry(pitch) * Rx(roll)). Handles gimbal lock at pitch = ±π/2. rotation The 3x3 rotation matrix to decompose AngularCoordinate containing (pitch, roll, yaw) in radians');
INSERT INTO "fts_docs" VALUES ('SATResult','msd_sim::CollisionHandler::SATResult','SAT result: minimum penetration depth and corresponding normal. Ticket: 0047_face_contact_manifold_generation');
INSERT INTO "fts_docs" VALUES ('SemiImplicitEulerIntegrator','msd_sim::SemiImplicitEulerIntegrator','Semi-implicit Euler integrator (symplectic). Integration order: Compute accelerations: a = F_ext / m, α = I^-1 * τ_ext Update velocities: v_new = v_old + a * dt Update positions: x_new = x_old + v_new * dt (uses NEW velocity) Integrate quaternion: Q_new = Q_old + Q̇ * dt Normalize quaternion (position-level drift correction) Properties: First-order accurate Symplectic (preserves phase space volume) Better energy conservation than explicit Euler Ticket 0045 breaking change: Removed constraint solving from integrator. Quaternion normalization is now handled via state.orientation.normalize() instead of UnitQuaternionConstraint . docs/designs/0030_lagrangian_quaternion_physics/0030_lagrangian_quaternion_physics.puml docs/designs/0045_constraint_solver_unification/design.md Ticket:\n 0030_lagrangian_quaternion_physics Ticket:\n 0045_constraint_solver_unification');
INSERT INTO "fts_docs" VALUES ('SemiImplicitEulerIntegrator','msd_sim::SemiImplicitEulerIntegrator::SemiImplicitEulerIntegrator','Construct integrator.');
INSERT INTO "fts_docs" VALUES ('step','msd_sim::SemiImplicitEulerIntegrator::step','Integrate state forward by one timestep. state Current inertial state (modified in place) force Net force in world frame [N] torque Net torque in world frame [N·m] mass Object mass [kg] inverseInertia Inverse inertia tensor in body frame [1/(kg·m²)] dt Timestep [s] Ticket 0045 breaking change: Removed constraints parameter. Quaternion normalization is now handled via state.orientation.normalize() instead of UnitQuaternionConstraint . Ticket:\n 0045_constraint_solver_unification');
INSERT INTO "fts_docs" VALUES ('SimulationFrameRecord','msd_transfer::SimulationFrameRecord','Database record for simulation frame timestamping. Each simulation frame has exactly one SimulationFrameRecord . Per-frame records ( InertialStateRecord , etc.) reference this frame via ForeignKey<SimulationFrameRecord> for temporal association. The id field is inherited from BaseTransferObject and serves as the primary key for frame identification. docs/designs/0038_simulation_data_recorder/0038_simulation_data_recorder.puml Ticket:\n 0038_simulation_data_recorder');
