INSERT INTO "fts_docs" VALUES ('STLLoader','msd_assets::STLLoader','Loader for STL (STereoLithography) 3D model files. Supports both binary and ASCII STL formats. Binary format is recommended for performance and file size. Binary STL format: 80-byte header (usually ignored) 4-byte unsigned int: triangle count For each triangle (50 bytes total): 12 bytes: normal vector (3 floats) 12 bytes: vertex 1 (3 floats) 12 bytes: vertex 2 (3 floats) 12 bytes: vertex 3 (3 floats) 2 bytes: attribute byte count (usually 0) ASCII STL format: Text-based format starting with "solid <name>" Each triangle defined with "facet normal" and three "vertex" lines Ends with "endsolid <name>"');
INSERT INTO "fts_docs" VALUES ('loadSTL','msd_assets::STLLoader::loadSTL','Load an STL file and create a MeshRecord. Automatically detects whether file is binary or ASCII format. filename Path to the STL file Unique pointer to MeshRecord if successful, nullptr on error');
INSERT INTO "fts_docs" VALUES ('loadBinarySTL','msd_assets::STLLoader::loadBinarySTL','Load binary STL file. Binary format is more compact and faster to parse than ASCII. filename Path to the binary STL file Unique pointer to MeshRecord if successful, nullptr on error');
INSERT INTO "fts_docs" VALUES ('loadASCIISTL','msd_assets::STLLoader::loadASCIISTL','Load ASCII STL file. ASCII format is human-readable but larger and slower to parse. filename Path to the ASCII STL file Unique pointer to MeshRecord if successful, nullptr on error');
INSERT INTO "fts_docs" VALUES ('readBinarySTLTriangles','msd_assets::STLLoader::readBinarySTLTriangles','Read raw triangle data from binary STL file. filename Path to the binary STL file Vector of triangles if successful, empty vector on error');
INSERT INTO "fts_docs" VALUES ('readASCIISTLTriangles','msd_assets::STLLoader::readASCIISTLTriangles','Read raw triangle data from ASCII STL file. filename Path to the ASCII STL file Vector of triangles if successful, empty vector on error');
INSERT INTO "fts_docs" VALUES ('isBinarySTL','msd_assets::STLLoader::isBinarySTL','Check if an STL file is binary format. Heuristic: checks if file starts with "solid " (ASCII) or not (binary). Also validates file size matches expected binary format. filename Path to the STL file true if binary format, false if ASCII or error');
INSERT INTO "fts_docs" VALUES ('trianglesToMeshRecord','msd_assets::STLLoader::trianglesToMeshRecord','Convert triangle data to MeshRecord. Creates a MeshRecord with vertex_data BLOB populated from triangle data. Each triangle contributes 3 vertices with positions, normals, and colors. triangles Vector of STL triangles MeshRecord object with populated vertex_data, vertex_count, and triangle_count');
INSERT INTO "fts_docs" VALUES ('validateBinarySTLSize','msd_assets::STLLoader::validateBinarySTLSize','Validate binary STL file size. File size should be: 80 (header) + 4 (count) + count * 50 (triangles) fileSize Size of file in bytes triangleCount Number of triangles from header true if file size is valid');
INSERT INTO "fts_docs" VALUES ('STLTriangle','msd_assets::STLTriangle','Data structure representing a single triangle from an STL file.');
INSERT INTO "fts_docs" VALUES ('normal','msd_assets::STLTriangle::normal','Triangle normal vector.');
INSERT INTO "fts_docs" VALUES ('vertex1','msd_assets::STLTriangle::vertex1','First vertex position.');
INSERT INTO "fts_docs" VALUES ('vertex2','msd_assets::STLTriangle::vertex2','Second vertex position.');
INSERT INTO "fts_docs" VALUES ('vertex3','msd_assets::STLTriangle::vertex3','Third vertex position.');
INSERT INTO "fts_docs" VALUES ('SupportResult','msd_sim::SupportResult','Result of Minkowski support query with witness tracking. Contains both the Minkowski difference point and the original support points on each object''s surface that contributed to it. All coordinates are in world space. Ticket:\n 0028_epa_witness_points');
INSERT INTO "fts_docs" VALUES ('SystemEnergy','msd_sim::EnergyTracker::SystemEnergy','System-level energy summary.');
INSERT INTO "fts_docs" VALUES ('total','msd_sim::EnergyTracker::SystemEnergy::total','Total system mechanical energy. totalLinearKE + totalRotationalKE + totalPotentialE [J]');
INSERT INTO "fts_docs" VALUES ('toRecord','msd_sim::EnergyTracker::SystemEnergy::toRecord','Convert to database record. frameId Frame ID for foreign key previous Previous frame''s system energy (for delta calculation) collisionActive Whether any collision was detected this frame SystemEnergyRecord for database insertion');
INSERT INTO "fts_docs" VALUES ('SystemEnergyRecord','msd_transfer::SystemEnergyRecord','Database record for system-level energy summary. Stores aggregated energy values across all rigid bodies for a given simulation frame. Includes energy change detection for anomaly identification during collision debugging. Fields: total_linear_ke: Sum of all body linear kinetic energies [J] total_rotational_ke: Sum of all body rotational kinetic energies [J] total_potential_e: Sum of all body potential energies [J] total_system_e: Total system mechanical energy [J] delta_e: Energy change from previous frame [J] energy_injection: 1 if delta_e exceeds tolerance (anomaly flag) collision_active: 1 if any collision detected this frame energy_injection and collision_active use uint32_t for SQLite compatibility (SQLite has no native boolean type). msd_sim::EnergyTracker Ticket:\n 0039a_energy_tracking_diagnostic_infrastructure');
INSERT INTO "fts_docs" VALUES ('TangentFrame','msd_sim::TangentFrame','Orthonormal tangent frame {t1, t2} for a contact normal. Represents the two orthonormal tangent directions perpendicular to a contact normal. Used by FrictionConstraint to define friction constraint directions. Invariants (enforced by TangentBasis::computeTangentBasis): ||t1|| = 1, ||t2|| = 1 (unit length) t1 · t2 = 0 (orthogonal) t1 · n = 0, t2 · n = 0 (perpendicular to normal) Thread safety: Value type, safe to copy across threads Error handling: Constructor validates unit length (throws std::invalid_argument if violated) docs/designs/0035a_tangent_basis_and_friction_constraint/0035a_tangent_basis_and_friction_constraint.puml Ticket:\n 0035a_tangent_basis_and_friction_constraint');
INSERT INTO "fts_docs" VALUES ('TangentFrame','msd_sim::TangentFrame::TangentFrame','Construct tangent frame from two tangent vectors. tangent1 First tangent direction (must be unit length) tangent2 Second tangent direction (must be unit length) std::invalid_argument if either tangent is not unit length (within 1e-6)');
INSERT INTO "fts_docs" VALUES ('TorqueVector','msd_sim::TorqueVector','3D torque vector type [N*m] with transfer object support Thin wrapper around Vec3DBase providing: Full Eigen matrix operation compatibility fromRecord/toRecord for database serialization std::format support Memory footprint: 24 bytes (same as Eigen::Vector3d)');
INSERT INTO "fts_docs" VALUES ('TorqueVectorRecord','msd_transfer::TorqueVectorRecord','Database record for a 3D torque vector [N*m]. Stores the x, y, z components of an msd_sim::TorqueVector as individual scalar doubles for human-readable database inspection and queryability.');
INSERT INTO "fts_docs" VALUES ('UnitQuaternionConstraint','msd_sim::UnitQuaternionConstraint','Unit quaternion normalization constraint using Lagrange multipliers. Maintains the constraint g(Q) = Q^T·Q - 1 = 0 to ensure quaternion remains normalized during numerical integration. This is a drop-in replacement for the deprecated QuaternionConstraint , reimplemented using the generalized constraint framework. Mathematical formulation: Constraint : C(Q) = Q^T·Q - 1 = 0 (scalar constraint) Jacobian: J = 2·Q^T (1×4 row vector w.r.t. quaternion components) Time derivative: ∂C/∂t = 0 (time-independent) Baumgarte stabilization: Position term: α·(Q^T·Q - 1) Velocity term: β·(2·Q^T·Q̇) Default parameters: α = 10.0, β = 10.0 (validated for dt ~ 0.016s) Thread safety: Thread-safe for concurrent evaluation after construction Error handling: No exceptions (all quaternion operations numerically stable) docs/designs/0043_constraint_hierarchy_refactor/0043_constraint_hierarchy_refactor.puml Ticket:\n 0043_constraint_hierarchy_refactor');
INSERT INTO "fts_docs" VALUES ('UnitQuaternionConstraint','msd_sim::UnitQuaternionConstraint::UnitQuaternionConstraint','Construct constraint with body index and Baumgarte parameters. bodyAIndex Index of body in solver body list (default: 0) alpha Position error gain [1/s²] (default: 10.0) beta Velocity error gain [1/s] (default: 10.0)');
INSERT INTO "fts_docs" VALUES ('dimension','msd_sim::UnitQuaternionConstraint::dimension','Number of scalar constraint equations. Dimension of constraint vector C(q, t)');
INSERT INTO "fts_docs" VALUES ('evaluate','msd_sim::UnitQuaternionConstraint::evaluate','Evaluate constraint function C(qA, qB, t) for two bodies. Returns vector of constraint violations. For bilateral constraints, C = 0 is the target. For unilateral constraints, C ≥ 0 is the target. Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Constraint violation vector (dimension × 1) std::invalid_argument if state is invalid');
INSERT INTO "fts_docs" VALUES ('jacobian','msd_sim::UnitQuaternionConstraint::jacobian','Compute constraint Jacobian J = ∂C/∂q for two bodies. Returns partial derivatives of constraint function w.r.t. position-level or velocity-level DOFs (depending on bodyCount): Single-body ( bodyCount() == 1): dimension × 7 (X: 3, Q: 4) Two-body ( bodyCount() == 2): dimension × 12 (v_A: 3, ω_A: 3, v_B: 3, ω_B: 3) Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Jacobian matrix (dimension × 7 or dimension × 12) std::invalid_argument if state is invalid');
INSERT INTO "fts_docs" VALUES ('partialTimeDerivative','msd_sim::UnitQuaternionConstraint::partialTimeDerivative','Compute constraint time derivative ∂C/∂t (optional). Returns partial derivative of constraint w.r.t. explicit time dependence. For time-independent constraints, this returns a zero vector. Default implementation: zero vector (no explicit time dependence) state Current inertial state time Simulation time [s] Time derivative vector (dimension × 1)');
INSERT INTO "fts_docs" VALUES ('lambdaBounds','msd_sim::UnitQuaternionConstraint::lambdaBounds','Get Lagrange multiplier bounds. Specifies the lower and upper bounds on the constraint''s Lagrange multiplier: Bilateral constraints: (-∞, +∞) Unilateral constraints: (0, +∞) Box-constrained: (lo, hi) LambdaBounds struct with lower and upper fields');
INSERT INTO "fts_docs" VALUES ('typeName','msd_sim::UnitQuaternionConstraint::typeName','Constraint type identifier for debugging/logging. Human-readable constraint type name');
INSERT INTO "fts_docs" VALUES ('recordState','msd_sim::UnitQuaternionConstraint::recordState','Record constraint state via visitor pattern. Builds a typed constraint record (ContactConstraintRecord, FrictionConstraintRecord, etc.) and dispatches to the visitor via overload resolution. The visitor decides what to do with the record (e.g., buffer to DataRecorder DAO). Enables compile-time type-safe constraint recording without dynamic_cast or std::any_cast. New constraint types extend ConstraintRecordVisitor with a new visit() overload. visitor Visitor that processes the typed constraint record bodyAId Persistent ID of body A for database FK reference bodyBId Persistent ID of body B for database FK reference (ignored for single-body) msd_transfer::ConstraintRecordVisitor msd_sim::DataRecorderVisitor');
INSERT INTO "fts_docs" VALUES ('evaluate','msd_sim::UnitQuaternionConstraint::evaluate','Convenience overload for single-body constraints. Delegates to evaluate(state, state, time). Non-virtual. state Current inertial state time Simulation time [s] Constraint violation vector (dimension × 1)');
INSERT INTO "fts_docs" VALUES ('jacobian','msd_sim::UnitQuaternionConstraint::jacobian','Convenience overload for single-body constraints. Delegates to jacobian(state, state, time). Non-virtual. state Current inertial state time Simulation time [s] Jacobian matrix (dimension × 7)');
INSERT INTO "fts_docs" VALUES ('Vec3DBase','msd_sim::detail::Vec3DBase','CRTP base class for 3D vector types. Provides common functionality for all 3D vector types by inheriting from Eigen::Vector3d. Derived types should use this as: struct MyVec3Type final : Vec3DBase<MyVec3Type> { ... }; Derived The derived type (CRTP pattern)');
INSERT INTO "fts_docs" VALUES ('Vec3FormatterBase','msd_sim::detail::Vec3FormatterBase','Shared formatter base for 3-component vector types. Provides parse() for [width][.precision][type] format specs and formatComponents() to emit "(c0, c1, c2)" output.');
INSERT INTO "fts_docs" VALUES ('Vec4DBase','msd_sim::detail::Vec4DBase','CRTP base class for 4D vector types. Provides common functionality for all 4D vector types by inheriting from Eigen::Vector4d. Derived types should use this as: struct MyVec4Type final : Vec4DBase<MyVec4Type> { ... }; Derived The derived type (CRTP pattern)');
INSERT INTO "fts_docs" VALUES ('Vec4FormatterBase','msd_sim::detail::Vec4FormatterBase','Shared formatter base for 4-component vector types. Provides parse() for [width][.precision][type] format specs and formatComponents() to emit "(c0, c1, c2, c3)" output.');
INSERT INTO "fts_docs" VALUES ('Vector3D','msd_sim::Vector3D','Generic 3D vector type with transfer object support. Thin wrapper around msd_sim::Vector3D providing: Full Eigen matrix operation compatibility fromRecord/toRecord for database serialization std::format support Use this type for generic 3D vector data that needs to be recorded/transferred. For semantic types (positions, velocities), prefer the domain-specific types like Coordinate . Memory footprint: 24 bytes (same as msd_sim::Vector3D )');
INSERT INTO "fts_docs" VALUES ('Vector3DRecord','msd_transfer::Vector3DRecord','Database record for a generic 3D vector. Stores the x, y, z components of an msd_sim::Vector3D as individual scalar doubles for human-readable database inspection and queryability. Use this record for generic 3D vector data. For domain-specific types (positions, velocities), use their respective records ( CoordinateRecord , etc.).');
INSERT INTO "fts_docs" VALUES ('Vector4D','msd_sim::Vector4D','Generic 4D vector type with transfer object support. Thin wrapper around Eigen::Vector4d providing: Full Eigen matrix operation compatibility fromRecord/toRecord for database serialization std::format support Commonly used for: Quaternions (w, x, y, z) Homogeneous coordinates (x, y, z, w) RGBA colors Memory footprint: 32 bytes (same as Eigen::Vector4d)');
INSERT INTO "fts_docs" VALUES ('Vector4DRecord','msd_transfer::Vector4DRecord','Database record for a generic 4D vector. Stores the x, y, z, w components of an msd_sim::Vector4D as individual scalar doubles for human-readable database inspection and queryability. Commonly used for: Quaternions (w, x, y, z ordering in physics) Homogeneous coordinates (x, y, z, w) RGBA colors');
INSERT INTO "fts_docs" VALUES ('Velocity','msd_sim::Velocity','3D velocity vector type [m/s] with transfer object support Thin wrapper around Vec3DBase providing: Full Eigen matrix operation compatibility fromRecord/toRecord for database serialization std::format support Memory footprint: 24 bytes (same as Eigen::Vector3d)');
INSERT INTO "fts_docs" VALUES ('VelocityRecord','msd_transfer::VelocityRecord','Database record for a 3D velocity vector [m/s]. Stores the x, y, z components of an msd_sim::Velocity as individual scalar doubles for human-readable database inspection and queryability.');
INSERT INTO "fts_docs" VALUES ('WorldModel','msd_sim::WorldModel','Container and manager for all simulation objects. WorldModel uses a unified storage approach with index-based iteration for efficient physics updates and collision detection. The WorldModel maintains: A single vector of all objects (graphical, inertial, environmental, boundary) Cached index lists for efficient iteration over specific object types Current simulation time Efficient iteration patterns: // Physics update - only iterate objects with physics for ( size_t idx : worldModel.getPhysicsObjectIndices()) { Object& obj = worldModel.getObject(idx); // Update physics... } // Collision detection - only iterate objects with collision hulls for ( size_t idx : worldModel.getCollisionObjectIndices()) { // Check collisions... } // Rendering - only iterate objects with visual geometry for ( size_t idx : worldModel.getRenderObjectIndices()) { // Render... }');
INSERT INTO "fts_docs" VALUES ('WorldModel','msd_sim::WorldModel::WorldModel','Construct WorldModel with default integrator and gravity. Initializes: SemiImplicitEulerIntegrator as default integrator GravityPotential with (0, 0, -9.81) m/s² as default potential Ticket:\n 0030_lagrangian_quaternion_physics');
INSERT INTO "fts_docs" VALUES ('spawnObject','msd_sim::WorldModel::spawnObject','Spawn a new object in the world. Adds the object to the world and updates internal index caches. object Object to add (uses move semantics) Index of added object');
INSERT INTO "fts_docs" VALUES ('spawnObject','msd_sim::WorldModel::spawnObject','Spawn a new object with specified mass. assetId Asset type identifier hull Collision hull for the object mass Mass in kilograms [kg] origin Initial reference frame Reference to the spawned object Ticket:\n 0039b_linear_collision_test_suite');
INSERT INTO "fts_docs" VALUES ('spawnObject','msd_sim::WorldModel::spawnObject','Spawn a new object with specified mass, restitution, and friction. Ticket:\n 0062a_extend_test_asset_generator assetId Asset type identifier hull Collision hull for the object mass Mass in kilograms [kg] origin Initial reference frame coefficientOfRestitution Elasticity [0, 1] (0=inelastic, 1=elastic) frictionCoefficient Friction coefficient [0, inf) Reference to the spawned object std::invalid_argument if mass <= 0 std::invalid_argument if coefficientOfRestitution not in [0, 1] std::invalid_argument if frictionCoefficient < 0');
INSERT INTO "fts_docs" VALUES ('spawnEnvironmentObject','msd_sim::WorldModel::spawnEnvironmentObject','Spawn a new static environment object in the world. Environment objects are static (immovable) and participate in collision detection but have no dynamics. Dynamic objects will bounce off them. assetId Asset type identifier hull Collision hull for the object origin Initial position and orientation Reference to the spawned environment object');
INSERT INTO "fts_docs" VALUES ('getInertialAssets','msd_sim::WorldModel::getInertialAssets','Get all objects (const).');
INSERT INTO "fts_docs" VALUES ('removeObject','msd_sim::WorldModel::removeObject','Remove object by index. Note: This invalidates indices > removed index. Consider marking objects for removal and cleaning up between frames. index Index of object to remove std::out_of_range if index is invalid');
