INSERT INTO "fts_docs" VALUES ('addPotentialEnergy','msd_sim::WorldModel::addPotentialEnergy','Add a potential energy field to the world. Potential energies compute generalized forces from energy gradients. Multiple potentials can be added and their forces are summed. energy Potential energy implementation (ownership transferred) Ticket:\n 0030_lagrangian_quaternion_physics');
