INSERT INTO "fts_docs" VALUES ('setIntegrator','msd_sim::WorldModel::setIntegrator','Set the numerical integrator for physics updates. The integrator handles the mathematical integration of equations of motion. Allows swapping integration schemes (Euler, RK4, etc.). integrator Integrator implementation (ownership transferred) Ticket:\n 0030_lagrangian_quaternion_physics');
