INSERT INTO "fts_docs" VALUES ('enableRecording','msd_sim::WorldModel::enableRecording','Enable simulation data recording to SQLite database. Creates a DataRecorder instance that operates on a background thread, periodically flushing buffered records. Recording begins immediately and continues until disableRecording() is called or WorldModel is destroyed. dbPath Path to SQLite database file (created if doesn''t exist) flushInterval How often to flush buffered records to disk std::runtime_error if database cannot be opened Ticket:\n 0038_simulation_data_recorder');
INSERT INTO "fts_docs" VALUES ('disableRecording','msd_sim::WorldModel::disableRecording','Disable simulation data recording. Flushes all pending records and stops the recorder thread. After this call, no more recording occurs until enableRecording() is called. Ticket:\n 0038_simulation_data_recorder');
INSERT INTO "fts_docs" VALUES ('updatePhysics','msd_sim::WorldModel::updatePhysics','Update physics for all dynamic objects. dt Time step in seconds');
INSERT INTO "fts_docs" VALUES ('updateCollisions','msd_sim::WorldModel::updateCollisions','Detect and resolve collisions using constraint-based approach. Creates transient contact constraints from collision results, solves them via Projected Gauss-Seidel (PGS), and applies constraint forces to bodies. dt Timestep [s] (needed for PGS solver force conversion) Ticket:\n 0032_contact_constraint_refactor');
INSERT INTO "fts_docs" VALUES ('recordCurrentFrame','msd_sim::WorldModel::recordCurrentFrame','Record current frame to database if recording is enabled. Thin orchestrator that delegates to DataRecorder domain-aware methods. Tracks previousSystemEnergy_ for delta calculation ( WorldModel state). Ticket:\n 0038_simulation_data_recorder Ticket:\n 0056j_domain_aware_data_recorder');
