INSERT INTO "members" VALUES (267,'classmsd__sim_1_1_collision_handler_1af8b884cb1ae586fd96b61a99df59f943',32,'function','checkCollision','msd_sim::CollisionHandler::checkCollision','std::optional< CollisionResult >','std::optional< CollisionResult > msd_sim::CollisionHandler::checkCollision','(const AssetPhysical &assetA, const AssetPhysical &assetB, bool skipSATValidation=false) const',NULL,56,'Check for collision between two physical assets.','Runs GJK to detect intersection. If collision detected, runs EPA to compute penetration depth, contact normal, and contact point. assetA First physical asset assetB Second physical asset skipSATValidation If true, skip SAT validation of EPA result. Use when ContactCache confirms persistent contact with stable normal, making EPA failure unlikely. Ticket: 0053d_sat_fallback_cost_reduction std::nullopt if no collision, CollisionResult if collision','public',0,1,0,0,0,0);
INSERT INTO "members" VALUES (268,'classmsd__sim_1_1_collision_handler_1a634b676c7563b27e97b0379e482118a1',32,'function','computeSATMinPenetration','msd_sim::CollisionHandler::computeSATMinPenetration','SATResult','CollisionHandler::SATResult msd_sim::CollisionHandler::computeSATMinPenetration','(const AssetPhysical &assetA, const AssetPhysical &assetB) const',NULL,82,'Compute minimum penetration depth and direction using SAT.','Ticket: 0047_face_contact_manifold_generation Iterates over all unique face normals of both hulls and computes the overlap (penetration depth) along each. Returns the minimum depth and the corresponding face normal. Used to validate and correct EPA results — EPA can produce wrong results at zero or near-zero penetration when the Minkowski difference origin is on the boundary.','private',0,1,0,0,0,0);
INSERT INTO "members" VALUES (269,'classmsd__sim_1_1_collision_handler_1ab19fe8f7df37d61cd2a1707ad61d53f2',32,'function','buildSATContact','msd_sim::CollisionHandler::buildSATContact','CollisionResult','CollisionResult msd_sim::CollisionHandler::buildSATContact','(const AssetPhysical &assetA, const AssetPhysical &assetB, const SATResult &sat) const',NULL,93,'Build a CollisionResult from SAT data when EPA fails.','Ticket: 0047_face_contact_manifold_generation When EPA picks the wrong face (depth wildly inconsistent with SAT), construct a valid contact using the SAT normal and depth with witness points from the support function.','private',0,1,0,0,0,0);
