INSERT INTO "members" VALUES (295,'classmsd__sim_1_1_collision_pipeline_1a558e1ae66f416ba992181f93bed241e1',34,'function','execute','msd_sim::CollisionPipeline::execute','void','void msd_sim::CollisionPipeline::execute','(std::span< AssetInertial > inertialAssets, std::span< const AssetEnvironment > environmentalAssets, double dt)',NULL,113,'Execute full collision response pipeline.','Performs: Collision detection (O(n²) pairwise narrow phase) Contact constraint creation via ContactConstraintFactory Solver input assembly (states, masses, inertias) 3.5. Warm-starting query from ContactCache Constraint solving with initial lambda (Active Set Method) 4.5. Cache update with solved lambdas Force application to inertial bodies Position correction via PositionCorrector Frame data is cleared at both the start and end of this method to prevent dangling references when the pipeline is idle between frames. inertialAssets Dynamic objects (non-owning span) environmentalAssets Static objects (non-owning span) dt Timestep [s]','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (296,'classmsd__sim_1_1_collision_pipeline_1aed3febda83c27dce21f884504dbe87d0',34,'function','advanceFrame','msd_sim::CollisionPipeline::advanceFrame','void','void msd_sim::CollisionPipeline::advanceFrame','()',NULL,125,'Advance contact cache age by one frame.','Must be called once per frame before execute() to increment cache age. This enables contact persistence tracking for warm-starting. Ticket:\n 0044_collision_pipeline_integration','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (297,'classmsd__sim_1_1_collision_pipeline_1a5d6071225ce9b82bfa5ad1f4017bb96d',34,'function','expireOldEntries','msd_sim::CollisionPipeline::expireOldEntries','void','void msd_sim::CollisionPipeline::expireOldEntries','(uint32_t maxAge=10)',NULL,136,'Expire stale contact cache entries.','Removes cached contacts older than maxAge frames. Typically called after advanceFrame() and before execute() each frame. maxAge Maximum age in frames (default: 10) Ticket:\n 0044_collision_pipeline_integration','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (298,'classmsd__sim_1_1_collision_pipeline_1a10f004116c3c7d4df17140e70d99dce0',34,'function','hadCollisions','msd_sim::CollisionPipeline::hadCollisions','bool','bool msd_sim::CollisionPipeline::hadCollisions','() const',NULL,147,'Check if collisions occurred this frame.','Returns true if collision detection found any colliding pairs. Used for energy tracking diagnostics. true if collisions occurred, false otherwise Ticket:\n 0044_collision_pipeline_integration','public',0,1,0,0,0,0);
INSERT INTO "members" VALUES (299,'classmsd__sim_1_1_collision_pipeline_1a16996c8f19dd4ed89f70f54d072c2faa',34,'function','getCollisions','msd_sim::CollisionPipeline::getCollisions','const std::vector< CollisionPair > &','const std::vector< CollisionPipeline::CollisionPair > & msd_sim::CollisionPipeline::getCollisions','() const',NULL,182,'Get collision pairs from last execute() .','Returns const reference to collision pairs detected during the most recent execute() call. Data is valid from end of execute() until start of next execute() . const reference to collision pair vector Ticket:\n 0056b_collision_pipeline_data_extraction','public',0,1,0,0,0,0);
INSERT INTO "members" VALUES (300,'classmsd__sim_1_1_collision_pipeline_1a9cf5c290c322e0b2c9bee28a0a9a4e0f',34,'function','getSolverData','msd_sim::CollisionPipeline::getSolverData','const SolverData &','const CollisionPipeline::SolverData & msd_sim::CollisionPipeline::getSolverData','() const',NULL,190,'Get solver diagnostics from last execute() .','const reference to solver diagnostic data Ticket:\n 0056b_collision_pipeline_data_extraction','public',0,1,0,0,0,0);
INSERT INTO "members" VALUES (301,'classmsd__sim_1_1_collision_pipeline_1a00bec9674b4999c9929bf5f4d44efac0',34,'function','recordConstraints','msd_sim::CollisionPipeline::recordConstraints','void','void msd_sim::CollisionPipeline::recordConstraints','(class DataRecorder &recorder, uint32_t frameId) const',NULL,216,'Record constraint states to DataRecorder .','Iterates all constraints (both ContactConstraint and FrictionConstraint ), calls constraint->recordState() with a DataRecorderVisitor , and buffers the typed records to the appropriate DAOs. Uses visitor pattern for type-safe dispatching without dynamic_cast. Each constraint builds its specific record (ContactConstraintRecord or FrictionConstraintRecord) and dispatches to visitor.visit(record). Must be called AFTER execute() and BEFORE clearEphemeralState() to ensure constraints are still alive. recorder DataRecorder instance to buffer records to frameId Frame ID for FK references in constraint records Thread safety: Not thread-safe (calls DataRecorder methods) Error handling: Exceptions from DAO operations propagate to caller DataRecorderVisitor Constraint::recordState() Ticket:\n 0057_contact_tangent_recording','public',0,1,0,0,0,0);
INSERT INTO "members" VALUES (302,'classmsd__sim_1_1_collision_pipeline_1ae41d7baac39f9f3b77fcce334fd5a9c7',34,'function','CollisionPipeline','msd_sim::CollisionPipeline::CollisionPipeline','','msd_sim::CollisionPipeline::CollisionPipeline','(const CollisionPipeline &)=delete',NULL,218,'','','public',0,0,0,0,0,0);
