INSERT INTO "members" VALUES (307,'classmsd__sim_1_1_collision_pipeline_1a557c2d8a87fcc7aae54a83eae23fe8fa',34,'function','detectCollisions','msd_sim::CollisionPipeline::detectCollisions','void','void msd_sim::CollisionPipeline::detectCollisions','(std::span< AssetInertial > inertialAssets, std::span< const AssetEnvironment > environmentalAssets)',NULL,239,'Phase 1: Collision detection (O(n²) pairwise).','Populates collisions_ member with detected collision pairs and their metadata (body indices, restitution). Performs: Inertial vs Inertial: O(n²) pairwise checks Inertial vs Environment: O(n*m) checks Early return if no collisions detected.','protected',0,0,0,0,0,0);
INSERT INTO "members" VALUES (308,'classmsd__sim_1_1_collision_pipeline_1ae1d88dbdd2174a60a50b7849ec08c97e',34,'function','createConstraints','msd_sim::CollisionPipeline::createConstraints','void','void msd_sim::CollisionPipeline::createConstraints','(std::span< AssetInertial > inertialAssets, std::span< const AssetEnvironment > environmentalAssets, double dt)',NULL,254,'Phase 2: Create contact constraints from collision results.','Populates constraints_ member via ContactConstraintFactory. One constraint per contact point in manifold. Early return if collisions_ is empty. inertialAssets Dynamic objects (non-owning span) environmentalAssets Static objects (non-owning span) dt Timestep [s]','protected',0,0,0,0,0,0);
INSERT INTO "members" VALUES (309,'classmsd__sim_1_1_collision_pipeline_1af52d28cbe71dbcc7da089a70b913d8e7',34,'function','assembleSolverInput','msd_sim::CollisionPipeline::assembleSolverInput','void','void msd_sim::CollisionPipeline::assembleSolverInput','(std::span< AssetInertial > inertialAssets, std::span< const AssetEnvironment > environmentalAssets, size_t numBodies)',NULL,272,'Phase 3: Assemble solver input arrays.','Populates states_, inverseMasses_, inverseInertias_, constraintPtrs_ from asset data in solver-compatible layout. Body indexing convention (preserved for solver compatibility): [0 .. numInertial-1] = inertial bodies [numInertial .. numInertial+numEnv-1] = environment bodies inertialAssets Dynamic objects (non-owning span) environmentalAssets Static objects (non-owning span) numBodies Total number of bodies (inertial + environmental)','protected',0,0,0,0,0,0);
INSERT INTO "members" VALUES (310,'classmsd__sim_1_1_collision_pipeline_1ad34f8f01ddfe426766a87d6d638aa572',34,'function','solveConstraintsWithWarmStart','msd_sim::CollisionPipeline::solveConstraintsWithWarmStart','ConstraintSolver::SolveResult','ConstraintSolver::SolveResult msd_sim::CollisionPipeline::solveConstraintsWithWarmStart','(double dt)',NULL,287,'Phase 4: Solve contact constraint system with warm-starting.','Invokes ConstraintSolver::solve() with initial lambda from ContactCache for faster convergence on persistent contacts. dt Timestep [s] SolveResult with per-body forces Ticket:\n 0045_constraint_solver_unification','protected',0,0,0,0,0,0);
INSERT INTO "members" VALUES (311,'classmsd__sim_1_1_collision_pipeline_1aa48b6fc1e3ea2e98ee65dadb3906cf4e',34,'function','correctPositions','msd_sim::CollisionPipeline::correctPositions','void','void msd_sim::CollisionPipeline::correctPositions','(std::span< AssetInertial > inertialAssets, std::span< const AssetEnvironment > environmentalAssets, size_t numBodies)',NULL,314,'Phase 6: Position correction via split-impulse method.','Corrects penetrating contacts using pseudo-velocities without injecting kinetic energy into real velocities. inertialAssets Dynamic objects (mutable span) environmentalAssets Static objects (non-owning span) numBodies Total body count (inertial + environmental)','protected',0,0,0,0,0,0);
INSERT INTO "members" VALUES (312,'classmsd__sim_1_1_collision_pipeline_1a330b282d3c744e068aa9e93c9954eba2',34,'function','applyForces','msd_sim::CollisionPipeline::applyForces','void','void msd_sim::CollisionPipeline::applyForces','(std::span< AssetInertial > inertialAssets, const ConstraintSolver::SolveResult &solveResult)',NULL,300,'Phase 5: Apply constraint forces to inertial bodies.','Calls applyForce() and applyTorque() on each inertial asset. Skips environment bodies (infinite mass). Skips forces below threshold (1e-12) per current implementation. inertialAssets Dynamic objects (mutable span) solveResult Solver output with per-body forces Ticket:\n 0045_constraint_solver_unification','protected',1,0,0,0,0,0);
INSERT INTO "members" VALUES (313,'classmsd__sim_1_1_collision_pipeline_1a8829aaac5dfbc102349fa2973c773cc5',34,'function','clearEphemeralState','msd_sim::CollisionPipeline::clearEphemeralState','void','void msd_sim::CollisionPipeline::clearEphemeralState','()',NULL,335,'Clear ephemeral solver state (references, pointers, constraints).','Clears vectors that hold references or pointers to external objects (states_, etc.) to prevent dangling references when assets are modified between frames. Also clears constraints. Does NOT clear collisions_ — those are value types (owned by pipeline) and are cleared at the start of the next execute() call. This allows WorldModel to read collision data between frames without an intermediate snapshot copy. Preserves capacity to avoid reallocation (NFR-1). Ticket: 0058_constraint_ownership_cleanup','private',0,0,0,0,0,0);
INSERT INTO "members" VALUES (314,'classmsd__sim_1_1_collision_pipeline_1a97327e2486df1137f42d0ce21da5ae32',34,'function','propagateSolvedLambdas','msd_sim::CollisionPipeline::propagateSolvedLambdas','void','void msd_sim::CollisionPipeline::propagateSolvedLambdas','(const ConstraintSolver::SolveResult &solveResult)',NULL,346,'Propagate solved normal lambdas to FrictionConstraints.','After the solver runs, each FrictionConstraint needs the corresponding ContactConstraint ''s solved lambda so that recordState() can write the actual normal force value (in Newtons) for visualization. Ticket: 0057_contact_tangent_recording','private',0,0,0,0,0,0);
INSERT INTO "members" VALUES (315,'classmsd__sim_1_1_collision_pipeline_1a61e1837aac05d5c81bd4754a61e8dd24',34,'function','buildSolverView','msd_sim::CollisionPipeline::buildSolverView','std::vector< Constraint * >','std::vector< Constraint * > msd_sim::CollisionPipeline::buildSolverView','(bool interleaved) const',NULL,361,'Build solver view (all constraints as Constraint*).','Generates a vector of raw pointers for ConstraintSolver::solve() . The view is temporary (not stored) and valid only within the calling scope. interleaved If true (friction active), returns [CC_0, FC_0, CC_1, FC_1, ...]. If false, returns all constraints in storage order. Vector of non-owning Constraint* pointers Ticket: 0058_constraint_ownership_cleanup','private',0,1,0,0,0,0);
INSERT INTO "members" VALUES (316,'classmsd__sim_1_1_collision_pipeline_1ae28a76d56bf02b1b7dc323d18f324ad6',34,'function','buildContactView','msd_sim::CollisionPipeline::buildContactView','std::vector< Constraint * >','std::vector< Constraint * > msd_sim::CollisionPipeline::buildContactView','() const',NULL,378,'Build contact-only view (ContactConstraint* via dynamic_cast).','Generates a vector of Constraint* pointers containing only ContactConstraint instances for PositionCorrector::correctPositions() . Filters allConstraints_ using dynamic_cast to extract only ContactConstraint instances. The view is temporary (not stored) and valid only within the calling scope. Vector of non-owning Constraint* pointers (ContactConstraints only) Ticket: 0058_constraint_ownership_cleanup','private',0,1,0,0,0,0);
INSERT INTO "members" VALUES (317,'classmsd__sim_1_1_collision_pipeline_1a767cf4dc84f61d27ab4de0d7d213297f',34,'function','findPairIndexForConstraint','msd_sim::CollisionPipeline::findPairIndexForConstraint','size_t','size_t msd_sim::CollisionPipeline::findPairIndexForConstraint','(size_t constraintIdx) const',NULL,392,'Map constraint index to collision pair index.','Iterates pairRanges_ to find which collision pair owns the given constraint index. Used by recordConstraints() to extract body IDs. constraintIdx Index into allConstraints_ Index into collisions_ vector std::logic_error if constraint index not found in pairRanges_ Ticket: 0057_contact_tangent_recording','private',0,1,0,0,0,0);
