INSERT INTO "members" VALUES (344,'classmsd__sim_1_1_constraint_1a57092b4621161a309ba3b6a168505ab8',39,'function','evaluate','msd_sim::Constraint::evaluate','Eigen::VectorXd','virtual Eigen::VectorXd msd_sim::Constraint::evaluate','(const InertialState &stateA, const InertialState &stateB, double time) const =0',NULL,87,'Evaluate constraint function C(qA, qB, t) for two bodies.','Returns vector of constraint violations. For bilateral constraints, C = 0 is the target. For unilateral constraints, C ≥ 0 is the target. Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Constraint violation vector (dimension × 1) std::invalid_argument if state is invalid','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (345,'classmsd__sim_1_1_constraint_1ac67ccd6a97f1453707c597589b383303',39,'function','evaluate','msd_sim::Constraint::evaluate','Eigen::VectorXd','Eigen::VectorXd msd_sim::Constraint::evaluate','(const InertialState &state, double time) const',NULL,100,'Convenience overload for single-body constraints.','Delegates to evaluate(state, state, time). Non-virtual. state Current inertial state time Simulation time [s] Constraint violation vector (dimension × 1)','public',0,1,0,0,1,0);
INSERT INTO "members" VALUES (346,'classmsd__sim_1_1_constraint_1a264daa05919aef635b43904b2d8c16cb',39,'function','jacobian','msd_sim::Constraint::jacobian','Eigen::MatrixXd','virtual Eigen::MatrixXd msd_sim::Constraint::jacobian','(const InertialState &stateA, const InertialState &stateB, double time) const =0',NULL,123,'Compute constraint Jacobian J = ∂C/∂q for two bodies.','Returns partial derivatives of constraint function w.r.t. position-level or velocity-level DOFs (depending on bodyCount): Single-body ( bodyCount() == 1): dimension × 7 (X: 3, Q: 4) Two-body ( bodyCount() == 2): dimension × 12 (v_A: 3, ω_A: 3, v_B: 3, ω_B: 3) Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Jacobian matrix (dimension × 7 or dimension × 12) std::invalid_argument if state is invalid','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (347,'classmsd__sim_1_1_constraint_1a639e05ee9325efa990c9b77d46e7f5ee',39,'function','jacobian','msd_sim::Constraint::jacobian','Eigen::MatrixXd','Eigen::MatrixXd msd_sim::Constraint::jacobian','(const InertialState &state, double time) const',NULL,136,'Convenience overload for single-body constraints.','Delegates to jacobian(state, state, time). Non-virtual. state Current inertial state time Simulation time [s] Jacobian matrix (dimension × 7)','public',0,1,0,0,1,0);
INSERT INTO "members" VALUES (348,'classmsd__sim_1_1_constraint_1aa5ba4f6a854c203cb56ef7e81be52929',39,'function','partialTimeDerivative','msd_sim::Constraint::partialTimeDerivative','Eigen::VectorXd','Eigen::VectorXd msd_sim::Constraint::partialTimeDerivative','(const InertialState &state, double time) const',NULL,154,'Compute constraint time derivative ∂C/∂t (optional).','Returns partial derivative of constraint w.r.t. explicit time dependence. For time-independent constraints, this returns a zero vector. Default implementation: zero vector (no explicit time dependence) state Current inertial state time Simulation time [s] Time derivative vector (dimension × 1)','public',0,1,0,1,0,0);
