INSERT INTO "members" VALUES (353,'classmsd__sim_1_1_constraint_1ac05e1b56c12bf506b079c778be82c712',39,'function','lambdaBounds','msd_sim::Constraint::lambdaBounds','LambdaBounds','virtual LambdaBounds msd_sim::Constraint::lambdaBounds','() const =0',NULL,213,'Get Lagrange multiplier bounds.','Specifies the lower and upper bounds on the constraint''s Lagrange multiplier: Bilateral constraints: (-∞, +∞) Unilateral constraints: (0, +∞) Box-constrained: (lo, hi) LambdaBounds struct with lower and upper fields','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (354,'classmsd__sim_1_1_constraint_1ace4f416b123a9839ad8d99c12fea957a',39,'function','isActive','msd_sim::Constraint::isActive','bool','virtual bool msd_sim::Constraint::isActive','(const InertialState &stateA, const InertialState &stateB, double time) const',NULL,226,'Check if constraint is active.','Determines whether the constraint should be enforced at the given state. Default implementation returns true (always active). stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] true if constraint should be enforced','public',0,1,0,1,1,0);
INSERT INTO "members" VALUES (355,'classmsd__sim_1_1_constraint_1a191356774acf0aedaab5bb4878ec4b11',39,'function','bodyCount','msd_sim::Constraint::bodyCount','int','virtual int msd_sim::Constraint::bodyCount','() const',NULL,244,'Number of bodies involved in this constraint.','Single-body constraints ( UnitQuaternionConstraint , DistanceConstraint ) return 1. Two-body constraints ( ContactConstraint , FrictionConstraint ) return 2. 1 for single-body, 2 for two-body','public',0,1,0,1,1,0);
