INSERT INTO "members" VALUES (359,'classmsd__sim_1_1_constraint_1acb3eacda502f4b3ed87d15282758dd9e',39,'function','recordState','msd_sim::Constraint::recordState','void','virtual void msd_sim::Constraint::recordState','(msd_transfer::ConstraintRecordVisitor &visitor, uint32_t bodyAId, uint32_t bodyBId) const =0',NULL,299,'Record constraint state via visitor pattern.','Builds a typed constraint record (ContactConstraintRecord, FrictionConstraintRecord, etc.) and dispatches to the visitor via overload resolution. The visitor decides what to do with the record (e.g., buffer to DataRecorder DAO). Enables compile-time type-safe constraint recording without dynamic_cast or std::any_cast. New constraint types extend ConstraintRecordVisitor with a new visit() overload. visitor Visitor that processes the typed constraint record bodyAId Persistent ID of body A for database FK reference bodyBId Persistent ID of body B for database FK reference (ignored for single-body) msd_transfer::ConstraintRecordVisitor msd_sim::DataRecorderVisitor','public',0,1,0,1,0,0);
