INSERT INTO "members" VALUES (367,'classmsd__sim_1_1_constraint_island_builder_1a98aab8ad053ebef40dad05247680a505',41,'function','buildIslands','msd_sim::ConstraintIslandBuilder::buildIslands','std::vector< Island >','std::vector< ConstraintIslandBuilder::Island > msd_sim::ConstraintIslandBuilder::buildIslands','(const std::vector< Constraint * > &constraints, size_t numInertialBodies)',NULL,78,'Partition constraints into independent contact islands.','Implements union-find over inertial body indices to determine connected components. Environment bodies (index >= numInertialBodies) do NOT create connectivity between inertial bodies — two cubes touching the same floor form two separate islands because the floor has infinite mass and cannot transmit impulses between them. The constraint ordering within each island preserves the relative order from the input list, which maintains the CC-before-paired-FC interleaving required by ConstraintSolver . constraints All constraints for the current frame (non-owning pointers) numInertialBodies Number of inertial (dynamic) bodies. Environment body indices satisfy: bodyIndex >= numInertialBodies. List of independent islands. Each island contains its constraint subset and all unique body indices (including environment indices) referenced by those constraints. Returns empty vector if constraints is empty.','public',1,0,0,0,0,0);
