INSERT INTO "members" VALUES (372,'classmsd__sim_1_1_constraint_pool_1a06abeae45ef6c79995a93bcdf04f7007',42,'function','allocateContact','msd_sim::ConstraintPool::allocateContact','ContactConstraint *','ContactConstraint * msd_sim::ConstraintPool::allocateContact','(size_t bodyAIndex, size_t bodyBIndex, const Coordinate &normal, const Coordinate &contactPointA, const Coordinate &contactPointB, double penetrationDepth, const Coordinate &comA, const Coordinate &comB, double restitution, double preImpactRelVelNormal)',NULL,70,'Construct a ContactConstraint in-pool and return a pointer to it.','Grows the backing vector on first call or when capacity is exceeded. After the first frame, capacity is sufficient and no allocation occurs. Pointer to the constructed ContactConstraint . Valid until next reset() .','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (373,'classmsd__sim_1_1_constraint_pool_1a20fd54f853f433c055c86876825eea7f',42,'function','allocateFriction','msd_sim::ConstraintPool::allocateFriction','FrictionConstraint *','FrictionConstraint * msd_sim::ConstraintPool::allocateFriction','(size_t bodyAIndex, size_t bodyBIndex, const Coordinate &normal, const Coordinate &contactPointA, const Coordinate &contactPointB, const Coordinate &comA, const Coordinate &comB, double frictionCoefficient)',NULL,90,'Construct a FrictionConstraint in-pool and return a pointer.','Grows the backing vector on first call or when capacity is exceeded. After the first frame, capacity is sufficient and no allocation occurs. Pointer to the constructed FrictionConstraint . Valid until next reset() .','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (374,'classmsd__sim_1_1_constraint_pool_1a38912b149ff16b36c10b96e016e74cb7',42,'function','reset','msd_sim::ConstraintPool::reset','void','void msd_sim::ConstraintPool::reset','()',NULL,108,'Reset all constraint pools for the next frame.','Calls clear() on both backing vectors: destructs all active constraints but preserves allocated capacity. After the first frame, subsequent emplace_back() calls reuse existing capacity with zero heap allocation. All previously returned pointers become invalid after this call.','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (375,'classmsd__sim_1_1_constraint_pool_1aaf4173451860fd70605d76f1bece0935',42,'function','reserveContacts','msd_sim::ConstraintPool::reserveContacts','void','void msd_sim::ConstraintPool::reserveContacts','(size_t n)',NULL,120,'Pre-reserve capacity for ContactConstraints this frame.','Call this before any allocateContact() calls within a frame to ensure the backing vector will not reallocate during the allocation batch. When capacity >= n no reallocation occurs, so returned pointers remain valid for the entire frame. n Total number of ContactConstraints expected this frame','public',0,0,0,0,0,0);
