INSERT INTO "members" VALUES (397,'classmsd__sim_1_1_constraint_solver_1adfe99a4566e4fab6109c73d02245a40e',44,'function','solve','msd_sim::ConstraintSolver::solve','SolveResult','ConstraintSolver::SolveResult msd_sim::ConstraintSolver::solve','(const std::vector< Constraint * > &contactConstraints, const std::vector< std::reference_wrapper< const InertialState > > &states, const std::vector< double > &inverseMasses, const std::vector< Eigen::Matrix3d > &inverseInertias, size_t numBodies, double dt, const std::optional< Eigen::VectorXd > &initialLambda=std::nullopt)',NULL,97,'Solve contact constraint system.','Detects friction constraints and dispatches to either ASM (no friction) or FrictionConeSolver (with friction). For the friction path, constraints are flattened from [CC, FC, CC, FC, ...] to [n, t1, t2, n, t1, t2, ...] rows before assembly.','public',0,0,0,0,0,0);
