INSERT INTO "members" VALUES (421,'classmsd__sim_1_1_contact_cache_1a26c904f6ede2de78359649b75a8d9158',45,'function','getWarmStart','msd_sim::ContactCache::getWarmStart','std::vector< double >','std::vector< double > msd_sim::ContactCache::getWarmStart','(uint32_t bodyA, uint32_t bodyB, const Vector3D &currentNormal, const std::vector< Coordinate > &currentPoints) const',NULL,84,'Look up cached lambdas for a body pair.','Matches current contact points to cached contact points by proximity (nearest-neighbor within threshold). Returns reordered lambdas matching current contact ordering. Unmatched contacts get lambda = 0. Invalidates cache entry if contact normal changed >15 degrees. bodyA Body A identifier bodyB Body B identifier currentNormal Current frame contact normal currentPoints Current frame contact midpoints Cached lambdas reordered to match current contacts, or empty if no valid cache entry exists','public',0,1,0,0,0,0);
INSERT INTO "members" VALUES (422,'classmsd__sim_1_1_contact_cache_1ac13833b3dc226fd4b5a43aab8b50bb06',45,'function','update','msd_sim::ContactCache::update','void','void msd_sim::ContactCache::update','(uint32_t bodyA, uint32_t bodyB, const Vector3D &normal, const std::vector< double > &lambdas, const std::vector< Coordinate > &points)',NULL,102,'Store solved lambdas for a body pair.','Overwrites any existing entry for this body pair. Resets age to 0 (freshly updated). bodyA Body A identifier bodyB Body B identifier normal Contact normal for this frame lambdas Solved lambda values points Contact midpoints for this frame','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (423,'classmsd__sim_1_1_contact_cache_1a1305a3bfb4456960e2d1419ebb61c910',45,'function','expireOldEntries','msd_sim::ContactCache::expireOldEntries','void','void msd_sim::ContactCache::expireOldEntries','(uint32_t maxAge=10)',NULL,116,'Remove entries older than maxAge frames.','Called once per frame after advanceFrame() . Entries that have not been refreshed (via update() ) for maxAge frames are removed. maxAge Maximum frames without refresh before expiry (default: 10)','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (424,'classmsd__sim_1_1_contact_cache_1ad0380fd72f0c4897fd0f817edc0982c9',45,'function','advanceFrame','msd_sim::ContactCache::advanceFrame','void','void msd_sim::ContactCache::advanceFrame','()',NULL,124,'Increment age of all entries.','Call once per frame at the end of updateCollisions(). Entries refreshed via update() in the current frame will have age 0; others will increment.','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (425,'classmsd__sim_1_1_contact_cache_1aa34a03227a47e393586b7f6932d8a5f9',45,'function','hasEntry','msd_sim::ContactCache::hasEntry','bool','bool msd_sim::ContactCache::hasEntry','(uint32_t bodyA, uint32_t bodyB) const',NULL,139,'Check if cache has a valid entry for a body pair.','Lightweight check without performing full warm-start computation. Returns true if the body pair has a cached entry that has not expired. Does NOT check normal alignment — caller should use this only to determine if a persistent contact exists. bodyA Body A identifier bodyB Body B identifier true if a cache entry exists for this body pair Ticket:\n 0053d_sat_fallback_cost_reduction','public',0,1,0,0,0,0);
INSERT INTO "members" VALUES (426,'classmsd__sim_1_1_contact_cache_1a6c209a538fb99f886d83056d8d6c7468',45,'function','updateSlidingState','msd_sim::ContactCache::updateSlidingState','void','void msd_sim::ContactCache::updateSlidingState','(uint32_t bodyA, uint32_t bodyB, const Vector3D &tangentVelocity, double velocityThreshold=0.01)',NULL,155,'Update sliding friction state for a contact pair.','Detects sustained sliding based on tangent velocity magnitude and updates the sliding direction. Increments sliding frame count if velocity above threshold, resets to zero otherwise. bodyA Body A identifier bodyB Body B identifier tangentVelocity Relative tangent velocity at contact [m/s] velocityThreshold Minimum velocity to qualify as sliding [m/s] (default: 0.01) Ticket:\n 0069_friction_velocity_reversal','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (427,'classmsd__sim_1_1_contact_cache_1a898ca6ec9f87230266ef402107024004',45,'function','getSlidingState','msd_sim::ContactCache::getSlidingState','std::pair< std::optional< Vector3D >, bool >','std::pair< std::optional< Vector3D >, bool > msd_sim::ContactCache::getSlidingState','(uint32_t bodyA, uint32_t bodyB, int minFrames=3) const',NULL,173,'Query sliding friction state for a contact pair.','Returns sliding direction and whether sliding mode is active (age >= 3, velocity sustained). bodyA Body A identifier bodyB Body B identifier minFrames Minimum consecutive frames to activate sliding mode (default: 3) {slidingDirection, isActive} pair. slidingDirection is nullopt if not sliding. Ticket:\n 0069_friction_velocity_reversal','public',0,1,0,0,0,0);
