INSERT INTO "members" VALUES (442,'classmsd__sim_1_1_contact_constraint_1ab18f1620dd29e0f1301fef44d7affcc8',46,'function','ContactConstraint','msd_sim::ContactConstraint::ContactConstraint','','msd_sim::ContactConstraint::ContactConstraint','(size_t bodyAIndex, size_t bodyBIndex, const Coordinate &normal, const Coordinate &contactPointA, const Coordinate &contactPointB, double penetrationDepth, const Coordinate &comA, const Coordinate &comB, double restitution, double preImpactRelVelNormal)',NULL,71,'Construct a contact constraint for a single contact point.','bodyAIndex Index of body A in the solver body list bodyBIndex Index of body B in the solver body list normal Contact normal (A → B, unit length) contactPointA Contact point on A''s surface (world space) [m] contactPointB Contact point on B''s surface (world space) [m] penetrationDepth Overlap distance [m] (positive when penetrating) comA Center of mass of body A (world space) [m] comB Center of mass of body B (world space) [m] restitution Coefficient of restitution [0, 1] preImpactRelVelNormal Pre-impact relative normal velocity [m/s] std::invalid_argument if normal is not unit length (within 1e-6) std::invalid_argument if penetration < 0 std::invalid_argument if restitution not in [0, 1]','public',0,0,0,0,0,0);
