INSERT INTO "members" VALUES (444,'classmsd__sim_1_1_contact_constraint_1a1483a21e66d4e747b447ec40525401d0',46,'function','dimension','msd_sim::ContactConstraint::dimension','int','int msd_sim::ContactConstraint::dimension','() const override',NULL,86,'Number of scalar constraint equations.','Dimension of constraint vector C(q, t)','public',0,1,0,1,1,0);
INSERT INTO "members" VALUES (445,'classmsd__sim_1_1_contact_constraint_1ad840de035a54a16bf2328b89942b47b3',46,'function','evaluate','msd_sim::ContactConstraint::evaluate','Eigen::VectorXd','Eigen::VectorXd msd_sim::ContactConstraint::evaluate','(const InertialState &stateA, const InertialState &stateB, double time) const override',NULL,91,'Evaluate constraint function C(qA, qB, t) for two bodies.','Returns vector of constraint violations. For bilateral constraints, C = 0 is the target. For unilateral constraints, C ≥ 0 is the target. Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Constraint violation vector (dimension × 1) std::invalid_argument if state is invalid','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (446,'classmsd__sim_1_1_contact_constraint_1a0284f237a7d2ae1a79888d8ee0113beb',46,'function','jacobian','msd_sim::ContactConstraint::jacobian','Eigen::MatrixXd','Eigen::MatrixXd msd_sim::ContactConstraint::jacobian','(const InertialState &stateA, const InertialState &stateB, double time) const override',NULL,96,'Compute constraint Jacobian J = ∂C/∂q for two bodies.','Returns partial derivatives of constraint function w.r.t. position-level or velocity-level DOFs (depending on bodyCount): Single-body ( bodyCount() == 1): dimension × 7 (X: 3, Q: 4) Two-body ( bodyCount() == 2): dimension × 12 (v_A: 3, ω_A: 3, v_B: 3, ω_B: 3) Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Jacobian matrix (dimension × 7 or dimension × 12) std::invalid_argument if state is invalid','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (447,'classmsd__sim_1_1_contact_constraint_1ae57e8cafa0f1cd74ba558e6c085b823b',46,'function','isActive','msd_sim::ContactConstraint::isActive','bool','bool msd_sim::ContactConstraint::isActive','(const InertialState &stateA, const InertialState &stateB, double time) const override',NULL,101,'Check if constraint is active.','Determines whether the constraint should be enforced at the given state. Default implementation returns true (always active). stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] true if constraint should be enforced','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (448,'classmsd__sim_1_1_contact_constraint_1a57c09ade7adcdbe11ce98515e2aafc2e',46,'function','lambdaBounds','msd_sim::ContactConstraint::lambdaBounds','LambdaBounds','LambdaBounds msd_sim::ContactConstraint::lambdaBounds','() const override',NULL,106,'Get Lagrange multiplier bounds.','Specifies the lower and upper bounds on the constraint''s Lagrange multiplier: Bilateral constraints: (-∞, +∞) Unilateral constraints: (0, +∞) Box-constrained: (lo, hi) LambdaBounds struct with lower and upper fields','public',0,1,0,1,1,0);
INSERT INTO "members" VALUES (449,'classmsd__sim_1_1_contact_constraint_1a733f3610c8abd0d6257b207d56bab076',46,'function','bodyCount','msd_sim::ContactConstraint::bodyCount','int','int msd_sim::ContactConstraint::bodyCount','() const override',NULL,111,'Number of bodies involved in this constraint.','Single-body constraints ( UnitQuaternionConstraint , DistanceConstraint ) return 1. Two-body constraints ( ContactConstraint , FrictionConstraint ) return 2. 1 for single-body, 2 for two-body','public',0,1,0,1,1,0);
INSERT INTO "members" VALUES (450,'classmsd__sim_1_1_contact_constraint_1a830bfa9314421d9c2c6f7f8583f246a8',46,'function','typeName','msd_sim::ContactConstraint::typeName','std::string','std::string msd_sim::ContactConstraint::typeName','() const override',NULL,116,'Constraint type identifier for debugging/logging.','Human-readable constraint type name','public',0,1,0,1,1,0);
INSERT INTO "members" VALUES (451,'classmsd__sim_1_1_contact_constraint_1a9669939c7221ee42cfab72edb1f7f619',46,'function','recordState','msd_sim::ContactConstraint::recordState','void','void msd_sim::ContactConstraint::recordState','(msd_transfer::ConstraintRecordVisitor &visitor, uint32_t bodyAId, uint32_t bodyBId) const override',NULL,122,'Record constraint state via visitor pattern.','Builds a typed constraint record (ContactConstraintRecord, FrictionConstraintRecord, etc.) and dispatches to the visitor via overload resolution. The visitor decides what to do with the record (e.g., buffer to DataRecorder DAO). Enables compile-time type-safe constraint recording without dynamic_cast or std::any_cast. New constraint types extend ConstraintRecordVisitor with a new visit() overload. visitor Visitor that processes the typed constraint record bodyAId Persistent ID of body A for database FK reference bodyBId Persistent ID of body B for database FK reference (ignored for single-body) msd_transfer::ConstraintRecordVisitor msd_sim::DataRecorderVisitor','public',0,1,0,1,0,0);
