INSERT INTO "members" VALUES (543,'classmsd__sim_1_1_data_recorder_1acd2f27b8b0b09e290f0bbad0ee7fd745',54,'function','getDAO','msd_sim::DataRecorder::getDAO','cpp_sqlite::DataAccessObject< T > &','cpp_sqlite::DataAccessObject< T > & msd_sim::DataRecorder::getDAO','()',NULL,129,'Get DAO for adding records (thread-safe addToBuffer).','Delegates to database_-> getDAO<T>() . DAOs are created on first access and managed by Database. All DAOs support thread-safe addToBuffer(). T Record type (must inherit from BaseTransferObject) Reference to DAO for type T Ticket:\n 0038_simulation_data_recorder','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (544,'classmsd__sim_1_1_data_recorder_1a7e74b31ec00a05f2201fa93eb4ee7194',54,'function','flush','msd_sim::DataRecorder::flush','void','void msd_sim::DataRecorder::flush','()',NULL,140,'Explicit flush of all pending records.','Thread-safe: Acquires flushMutex_ to prevent concurrent flushes with recorder thread. Wraps database_->flushAllDAOs() in transaction for performance. Ticket:\n 0038_simulation_data_recorder','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (545,'classmsd__sim_1_1_data_recorder_1aea73efe933d4a8647e9549533d3e0c97',54,'function','getDatabase','msd_sim::DataRecorder::getDatabase','const cpp_sqlite::Database &','const cpp_sqlite::Database & msd_sim::DataRecorder::getDatabase','() const',NULL,152,'Access database for queries (const only).','Provides read-only access to database for verification/testing. Write access should only occur through recorder mechanisms. Const reference to database Ticket:\n 0038_simulation_data_recorder','public',0,1,0,0,0,0);
INSERT INTO "members" VALUES (546,'classmsd__sim_1_1_data_recorder_1a1b4df40d856044b1f6c8648f1825b5a4',54,'function','recordInertialStates','msd_sim::DataRecorder::recordInertialStates','void','void msd_sim::DataRecorder::recordInertialStates','(uint32_t frameId, std::span< const AssetInertial > assets)',NULL,170,'Record inertial states for all assets in a frame.','Iterates assets, calls toRecord(), sets FK fields (body_id, frame_id), and buffers records via DAO. Thread-safe: Uses mutex-protected DAO::addToBuffer(). frameId Foreign key to SimulationFrameRecord assets Span of inertial assets to record Ticket:\n 0056j_domain_aware_data_recorder','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (547,'classmsd__sim_1_1_data_recorder_1ae5020c57d27a5b26965b1c74065da618',54,'function','recordBodyEnergies','msd_sim::DataRecorder::recordBodyEnergies','void','void msd_sim::DataRecorder::recordBodyEnergies','(uint32_t frameId, std::span< const AssetInertial > assets, std::span< const std::unique_ptr< PotentialEnergy > > potentials)',NULL,187,'Record per-body energy for all assets in a frame.','Computes body energy from inertial state, mass, inertia tensor, and potential energy fields. Buffers EnergyRecord for each asset. Thread-safe: Uses mutex-protected DAO::addToBuffer(). frameId Foreign key to SimulationFrameRecord assets Span of inertial assets to record potentials Span of potential energy fields for energy calculation Ticket:\n 0056j_domain_aware_data_recorder','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (548,'classmsd__sim_1_1_data_recorder_1a452792aa18f5d03b0acbcd16c1159e05',54,'function','recordSystemEnergy','msd_sim::DataRecorder::recordSystemEnergy','void','void msd_sim::DataRecorder::recordSystemEnergy','(uint32_t frameId, const EnergyTracker::SystemEnergy &energy, double previousTotal, bool collisionActive)',NULL,207,'Record system-level energy summary for a frame.','Records total system energy (KE + PE), energy change from previous frame, and collision active flag. Thread-safe: Uses mutex-protected DAO::addToBuffer(). frameId Foreign key to SimulationFrameRecord energy System energy summary (total, KE, PE breakdown) previousTotal Total energy from previous frame for delta calculation collisionActive Whether collision was active this frame Ticket:\n 0056j_domain_aware_data_recorder','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (549,'classmsd__sim_1_1_data_recorder_1acb8777fb3fba503135fddbe9d4307271',54,'function','recordCollisions','msd_sim::DataRecorder::recordCollisions','void','void msd_sim::DataRecorder::recordCollisions','(uint32_t frameId, const CollisionPipeline &pipeline)',NULL,225,'Record collision results for a frame.','Iterates collision pairs, calls toRecord(), sets FK fields, and buffers CollisionResultRecord for each collision. Thread-safe: Uses mutex-protected DAO::addToBuffer(). frameId Foreign key to SimulationFrameRecord pipeline CollisionPipeline instance (for accessing collision pairs) Ticket:\n 0056j_domain_aware_data_recorder','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (550,'classmsd__sim_1_1_data_recorder_1a1b0f94e7e0c26ceec1d4915037a2b9c0',54,'function','recordSolverDiagnostics','msd_sim::DataRecorder::recordSolverDiagnostics','void','void msd_sim::DataRecorder::recordSolverDiagnostics','(uint32_t frameId, const CollisionPipeline &pipeline)',NULL,240,'Record solver diagnostics for a frame.','Records constraint solver convergence metrics (iterations, residual, constraint count, contact count). Thread-safe: Uses mutex-protected DAO::addToBuffer(). frameId Foreign key to SimulationFrameRecord pipeline CollisionPipeline instance (for accessing solver data) Ticket:\n 0056j_domain_aware_data_recorder','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (551,'classmsd__sim_1_1_data_recorder_1aa57adadbe5bf3414b2d574f91ccadc98',54,'function','recordStaticAsset','msd_sim::DataRecorder::recordStaticAsset','void','void msd_sim::DataRecorder::recordStaticAsset','(const AssetInertial &asset)',NULL,255,'Record static asset properties at spawn time.','Records immutable asset properties (mass, restitution, friction) linked by body_id foreign key. Called when asset is spawned into WorldModel . Thread-safe: Uses mutex-protected DAO::addToBuffer(). asset Inertial asset to record static properties for Ticket:\n 0056j_domain_aware_data_recorder','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (552,'classmsd__sim_1_1_data_recorder_1a96922b74ea5d2e1585c9eaf8b2d9534f',54,'function','recorderThreadMain','msd_sim::DataRecorder::recorderThreadMain','void','void msd_sim::DataRecorder::recorderThreadMain','(std::stop_token stopToken)',NULL,268,'Recorder thread main loop.','Sleeps for flushInterval_, then acquires flushMutex_ and flushes all DAOs in a transaction. Continues until stop_token is requested. stopToken Token for clean shutdown signaling Ticket:\n 0038_simulation_data_recorder','private',0,0,0,0,0,0);
