INSERT INTO "members" VALUES (561,'classmsd__sim_1_1_distance_constraint_1a3f2d189c7a638c6eedc2406b7ac4cbb3',56,'function','dimension','msd_sim::DistanceConstraint::dimension','int','int msd_sim::DistanceConstraint::dimension','() const override',NULL,56,'Number of scalar constraint equations.','Dimension of constraint vector C(q, t)','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (562,'classmsd__sim_1_1_distance_constraint_1ad21529a17c86b043038cc6414c7601c4',56,'function','evaluate','msd_sim::DistanceConstraint::evaluate','Eigen::VectorXd','Eigen::VectorXd msd_sim::DistanceConstraint::evaluate','(const InertialState &stateA, const InertialState &stateB, double time) const override',NULL,59,'Evaluate constraint function C(qA, qB, t) for two bodies.','Returns vector of constraint violations. For bilateral constraints, C = 0 is the target. For unilateral constraints, C ≥ 0 is the target. Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Constraint violation vector (dimension × 1) std::invalid_argument if state is invalid','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (563,'classmsd__sim_1_1_distance_constraint_1af29a58e5f4dcd5f05ea78e7b9fa7e417',56,'function','jacobian','msd_sim::DistanceConstraint::jacobian','Eigen::MatrixXd','Eigen::MatrixXd msd_sim::DistanceConstraint::jacobian','(const InertialState &stateA, const InertialState &stateB, double time) const override',NULL,64,'Compute constraint Jacobian J = ∂C/∂q for two bodies.','Returns partial derivatives of constraint function w.r.t. position-level or velocity-level DOFs (depending on bodyCount): Single-body ( bodyCount() == 1): dimension × 7 (X: 3, Q: 4) Two-body ( bodyCount() == 2): dimension × 12 (v_A: 3, ω_A: 3, v_B: 3, ω_B: 3) Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Jacobian matrix (dimension × 7 or dimension × 12) std::invalid_argument if state is invalid','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (564,'classmsd__sim_1_1_distance_constraint_1a6f1f48e2e3d8d67485c3bed67a1a6620',56,'function','partialTimeDerivative','msd_sim::DistanceConstraint::partialTimeDerivative','Eigen::VectorXd','Eigen::VectorXd msd_sim::DistanceConstraint::partialTimeDerivative','(const InertialState &state, double time) const override',NULL,67,'Compute constraint time derivative ∂C/∂t (optional).','Returns partial derivative of constraint w.r.t. explicit time dependence. For time-independent constraints, this returns a zero vector. Default implementation: zero vector (no explicit time dependence) state Current inertial state time Simulation time [s] Time derivative vector (dimension × 1)','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (565,'classmsd__sim_1_1_distance_constraint_1ae33ff9d177b207fb03953bfa4126b68f',56,'function','lambdaBounds','msd_sim::DistanceConstraint::lambdaBounds','LambdaBounds','LambdaBounds msd_sim::DistanceConstraint::lambdaBounds','() const override',NULL,69,'Get Lagrange multiplier bounds.','Specifies the lower and upper bounds on the constraint''s Lagrange multiplier: Bilateral constraints: (-∞, +∞) Unilateral constraints: (0, +∞) Box-constrained: (lo, hi) LambdaBounds struct with lower and upper fields','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (566,'classmsd__sim_1_1_distance_constraint_1a72c4ea0b7111fc9be13a118d07065193',56,'function','typeName','msd_sim::DistanceConstraint::typeName','std::string','std::string msd_sim::DistanceConstraint::typeName','() const override',NULL,70,'Constraint type identifier for debugging/logging.','Human-readable constraint type name','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (567,'classmsd__sim_1_1_distance_constraint_1a77c1b8063f1bd2abb0724ea8e5fe518d',56,'function','recordState','msd_sim::DistanceConstraint::recordState','void','void msd_sim::DistanceConstraint::recordState','(msd_transfer::ConstraintRecordVisitor &visitor, uint32_t bodyAId, uint32_t bodyBId) const override',NULL,72,'Record constraint state via visitor pattern.','Builds a typed constraint record (ContactConstraintRecord, FrictionConstraintRecord, etc.) and dispatches to the visitor via overload resolution. The visitor decides what to do with the record (e.g., buffer to DataRecorder DAO). Enables compile-time type-safe constraint recording without dynamic_cast or std::any_cast. New constraint types extend ConstraintRecordVisitor with a new visit() overload. visitor Visitor that processes the typed constraint record bodyAId Persistent ID of body A for database FK reference bodyBId Persistent ID of body B for database FK reference (ignored for single-body) msd_transfer::ConstraintRecordVisitor msd_sim::DataRecorderVisitor','public',0,1,0,1,0,0);
