INSERT INTO "members" VALUES (585,'classmsd__sim_1_1_energy_tracker_1ac215bc3ebedcec1c77f7118b50faf68a',59,'function','isEnergyInjection','msd_sim::EnergyTracker::isEnergyInjection','bool','bool msd_sim::EnergyTracker::isEnergyInjection','(double currentEnergy, double previousEnergy, double relativeTolerance=1e-6, double absoluteTolerance=1e-9)',NULL,141,'Check if energy change exceeds tolerance (anomaly detection).','Uses the larger of relative and absolute tolerance: Relative: relativeTolerance * |currentEnergy| Absolute: absoluteTolerance Energy increase beyond tolerance indicates energy injection (anomaly). Energy decrease is allowed (dissipation is physical). currentEnergy Current total system energy [J] previousEnergy Previous frame total system energy [J] relativeTolerance Relative tolerance (default 1e-6) absoluteTolerance Absolute tolerance [J] (default 1e-9) true if energy increased beyond tolerance','public',1,0,0,0,0,0);
