INSERT INTO "members" VALUES (595,'classmsd__sim_1_1_engine_1ae8751b0c9c95dc031d410df5e5cd5e62',60,'function','spawnEnvironmentObject','msd_sim::Engine::spawnEnvironmentObject','const AssetEnvironment &','const AssetEnvironment & msd_sim::Engine::spawnEnvironmentObject','(const std::string &assetName, const Coordinate &position, const AngularCoordinate &orientation)',NULL,85,'Spawn a static environment object from an asset.','assetName Name of asset in registry position World position orientation World orientation Reference to spawned environment object Environment objects are static (immovable) and participate in collision detection. Dynamic objects will bounce off them.','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (596,'classmsd__sim_1_1_engine_1a22ee9782d295fc26e38eba8a0ec7998e',60,'function','spawnPlayerPlatform','msd_sim::Engine::spawnPlayerPlatform','uint32_t','uint32_t msd_sim::Engine::spawnPlayerPlatform','(const std::string &assetName, const Coordinate &position, const AngularCoordinate &orientation)',NULL,101,'Spawn a player-controlled platform with visual object.','assetName Name of visual asset position Initial position orientation Initial orientation Platform ID Creates a Platform with InputControlAgent and links it to a visual Object in WorldModel . Sets this platform as the player platform for input commands.','public',0,0,0,0,0,0);
