INSERT INTO "members" VALUES (605,'class_engine_wrapper_1adf3f5cbd3860f4aa6b8eb8559926464e',61,'function','update','EngineWrapper::update','void','void EngineWrapper::update','(int milliseconds)',NULL,123,'Set the current simulation time (absolute, not delta).','The underlying WorldModel::update(simTime) receives the absolute simulation time, not a delta. The caller is responsible for tracking cumulative time and passing an increasing value on each call. Example (60 FPS): for i in range(1, 61): engine.update(i * 16) # 16ms, 32ms, 48ms, ... milliseconds Absolute simulation time [ms]','public',0,0,0,0,1,0);
INSERT INTO "members" VALUES (606,'class_engine_wrapper_1a4914e00b37a15641a7bbde15a54542b8',61,'function','getFrameState','EngineWrapper::getFrameState','py::dict','py::dict EngineWrapper::getFrameState','()',NULL,152,'Get the current simulation state for all bodies (inertial and environment).','Returns the simulation time plus the state of every asset spawned into the world. Inertial (dynamic) bodies appear first, followed by environment (static) bodies. Each entry includes an is_environment flag so that downstream consumers can distinguish body types without additional metadata. Environment bodies have zeroed velocity and angular_velocity fields because they are immovable by definition. dict with: "simulation_time": float (seconds) "states": list of dicts each containing: "body_id": int "asset_id": int "position": {"x": float, "y": float, "z": float} "velocity": {"x": float, "y": float, "z": float} "orientation": {"w": float, "x": float, "y": float, "z": float} "angular_velocity": {"x": float, "y": float, "z": float} "is_environment": bool (false for inertial, true for environment) Ticket:\n 0072e_live_simulation_cleanup (FR-1)','public',0,0,0,0,1,0);
