INSERT INTO "members" VALUES (615,'classmsd__sim_1_1_e_p_a_1ac70efeff02641d0c7296ee5cbc4d7399',62,'function','computeContactInfo','msd_sim::EPA::computeContactInfo','CollisionResult','CollisionResult msd_sim::EPA::computeContactInfo','(const std::vector< Coordinate > &simplex, int maxIterations=64)',NULL,93,'Compute contact information from GJK terminating simplex.','Assumes simplex contains the origin ( GJK returned true). Expands polytope iteratively until closest face found within tolerance. simplex GJK terminating simplex (4 vertices in Minkowski space) maxIterations Maximum expansion iterations (default: 64) CollisionResult with penetration depth, normal, contact point. If EPA does not fully converge, returns the best approximation from the closest polytope face found so far. std::invalid_argument if simplex size != 4','public',0,0,0,0,0,0);
