INSERT INTO "members" VALUES (700,'classmsd__sim_1_1_friction_constraint_1aac85b3a3660de44ea70b41e97af3272c',83,'function','FrictionConstraint','msd_sim::FrictionConstraint::FrictionConstraint','','msd_sim::FrictionConstraint::FrictionConstraint','(size_t bodyAIndex, size_t bodyBIndex, const Coordinate &normal, const Coordinate &contactPointA, const Coordinate &contactPointB, const Coordinate &comA, const Coordinate &comB, double frictionCoefficient)',NULL,79,'Construct friction constraint for a contact point.','bodyAIndex Index of body A in solver body list bodyBIndex Index of body B in solver body list normal Contact normal (A → B, unit length) contactPointA Contact point on A''s surface (world space) [m] contactPointB Contact point on B''s surface (world space) [m] comA Center of mass of body A (world space) [m] comB Center of mass of body B (world space) [m] frictionCoefficient Combined friction coefficient μ [0, ∞) std::invalid_argument if normal is not unit length (within 1e-6) std::invalid_argument if frictionCoefficient < 0 Thread safety: Not thread-safe during construction Complexity: O(1) - computes tangent basis and lever arms once','public',0,0,0,0,0,0);
