INSERT INTO "members" VALUES (702,'classmsd__sim_1_1_friction_constraint_1a8ac283c8c52457ecab0775280efeabcb',83,'function','dimension','msd_sim::FrictionConstraint::dimension','int','int msd_sim::FrictionConstraint::dimension','() const override',NULL,96,'Number of scalar constraint equations (always 2 for friction).','2 (one row for t1 direction, one row for t2 direction)','public',0,1,0,1,1,0);
INSERT INTO "members" VALUES (703,'classmsd__sim_1_1_friction_constraint_1a0f3fd0398dd3b621ac6ac0ffa7e0c582',83,'function','evaluate','msd_sim::FrictionConstraint::evaluate','Eigen::VectorXd','Eigen::VectorXd msd_sim::FrictionConstraint::evaluate','(const InertialState &stateA, const InertialState &stateB, double time) const override',NULL,115,'Evaluate tangential relative velocities at contact point.','Computes: C(0) = v_rel · t1 (relative velocity in first tangent direction) C(1) = v_rel · t2 (relative velocity in second tangent direction) where v_rel = (vA + ωA × rA) - (vB + ωB × rB) stateA Inertial state of body A stateB Inertial state of body B time Simulation time [s] (unused for friction) 2×1 vector of tangential relative velocities [m/s]','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (704,'classmsd__sim_1_1_friction_constraint_1a8d8cf2e4fe7f31f3c294b9688228979c',83,'function','jacobian','msd_sim::FrictionConstraint::jacobian','Eigen::MatrixXd','Eigen::MatrixXd msd_sim::FrictionConstraint::jacobian','(const InertialState &stateA, const InertialState &stateB, double time) const override',NULL,133,'Compute two-body Jacobian for friction constraints.','Returns 2×12 matrix: Row 0: J_t1 = [t1^T, (rA×t1)^T, -t1^T, -(rB×t1)^T] Row 1: J_t2 = [t2^T, (rA×t2)^T, -t2^T, -(rB×t2)^T] Each row has structure: [v_A (3), ω_A (3), v_B (3), ω_B (3)] stateA Inertial state of body A (unused, pre-computed geometry) stateB Inertial state of body B (unused, pre-computed geometry) time Simulation time [s] (unused for friction) 2×12 Jacobian matrix','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (705,'classmsd__sim_1_1_friction_constraint_1a6d76f3af402b585b75afe100ed49d0c7',83,'function','isActive','msd_sim::FrictionConstraint::isActive','bool','bool msd_sim::FrictionConstraint::isActive','(const InertialState &stateA, const InertialState &stateB, double time) const override',NULL,149,'Check if friction constraint is active.','Friction is active when: Normal contact force λn > 0 (contact is active) Friction coefficient μ > 0 (non-zero friction) stateA Inertial state of body A (unused for activation check) stateB Inertial state of body B (unused for activation check) time Simulation time [s] (unused for activation check) true if friction should be enforced','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (706,'classmsd__sim_1_1_friction_constraint_1ae6230180f1506609a1cc209d5bce77d7',83,'function','lambdaBounds','msd_sim::FrictionConstraint::lambdaBounds','LambdaBounds','LambdaBounds msd_sim::FrictionConstraint::lambdaBounds','() const override',NULL,153,'Get Lagrange multiplier bounds.','Specifies the lower and upper bounds on the constraint''s Lagrange multiplier: Bilateral constraints: (-∞, +∞) Unilateral constraints: (0, +∞) Box-constrained: (lo, hi) LambdaBounds struct with lower and upper fields','public',0,1,0,1,1,0);
INSERT INTO "members" VALUES (707,'classmsd__sim_1_1_friction_constraint_1a4fc56d3b0d2847df6bef286ae26ae78a',83,'function','bodyCount','msd_sim::FrictionConstraint::bodyCount','int','int msd_sim::FrictionConstraint::bodyCount','() const override',NULL,159,'Number of bodies involved in this constraint.','Single-body constraints ( UnitQuaternionConstraint , DistanceConstraint ) return 1. Two-body constraints ( ContactConstraint , FrictionConstraint ) return 2. 1 for single-body, 2 for two-body','public',0,1,0,1,1,0);
INSERT INTO "members" VALUES (708,'classmsd__sim_1_1_friction_constraint_1a255bf2764554613369ddf42ab9aaf12e',83,'function','typeName','msd_sim::FrictionConstraint::typeName','std::string','std::string msd_sim::FrictionConstraint::typeName','() const override',NULL,164,'Constraint type identifier for debugging/logging.','Human-readable constraint type name','public',0,1,0,1,1,0);
INSERT INTO "members" VALUES (709,'classmsd__sim_1_1_friction_constraint_1abad6b7c307884525c95bf6c118ec3c3e',83,'function','recordState','msd_sim::FrictionConstraint::recordState','void','void msd_sim::FrictionConstraint::recordState','(msd_transfer::ConstraintRecordVisitor &visitor, uint32_t bodyAId, uint32_t bodyBId) const override',NULL,169,'Record constraint state via visitor pattern.','Builds a typed constraint record (ContactConstraintRecord, FrictionConstraintRecord, etc.) and dispatches to the visitor via overload resolution. The visitor decides what to do with the record (e.g., buffer to DataRecorder DAO). Enables compile-time type-safe constraint recording without dynamic_cast or std::any_cast. New constraint types extend ConstraintRecordVisitor with a new visit() overload. visitor Visitor that processes the typed constraint record bodyAId Persistent ID of body A for database FK reference bodyBId Persistent ID of body B for database FK reference (ignored for single-body) msd_transfer::ConstraintRecordVisitor msd_sim::DataRecorderVisitor','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (710,'classmsd__sim_1_1_friction_constraint_1ac5f2c0bf87a625230e3392583aee17ac',83,'function','setNormalLambda','msd_sim::FrictionConstraint::setNormalLambda','void','void msd_sim::FrictionConstraint::setNormalLambda','(double normalLambda)',NULL,185,'Update normal contact force for friction bound computation.','Called by solver each iteration to update friction bounds based on current normal force. Must be called before getFrictionBounds() . normalLambda Normal contact force λn from ContactConstraint [N] Thread safety: Not thread-safe (mutates internal state)','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (711,'classmsd__sim_1_1_friction_constraint_1ac5b1cc5b21d688053a91c9aaa04c49d1',83,'function','setSlidingMode','msd_sim::FrictionConstraint::setSlidingMode','void','void msd_sim::FrictionConstraint::setSlidingMode','(const Vector3D &slidingDirection)',NULL,204,'Enable sliding friction mode with aligned tangent basis.','Overrides the tangent basis to align t1 with -slidingDirection (opposing motion), with t2 perpendicular to both t1 and the contact normal. This ensures lambda_t1 directly corresponds to deceleration along the sliding direction. When sliding mode is active, lambda_t1 bounds are made unilateral (>= 0) by the NLopt solver to prevent friction from accelerating in the sliding direction. slidingDirection Unit sliding direction (world frame) Thread safety: Not thread-safe (mutates tangent basis) Ticket:\n 0069_friction_velocity_reversal','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (712,'classmsd__sim_1_1_friction_constraint_1afb192b4971d13bd35afd886e2ba0c8ab',83,'function','setTangentLambdas','msd_sim::FrictionConstraint::setTangentLambdas','void','void msd_sim::FrictionConstraint::setTangentLambdas','(double t1Lambda, double t2Lambda)',NULL,215,'Set solved tangent force magnitudes for recording.','Called after solver completes to store the actual tangent friction forces (in Newtons) for database recording and visualization. t1Lambda Solved tangent1 force [N] t2Lambda Solved tangent2 force [N]','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (713,'classmsd__sim_1_1_friction_constraint_1a0fe7fcb168e46f13776574922f369111',83,'function','getFrictionBounds','msd_sim::FrictionConstraint::getFrictionBounds','std::pair< double, double >','std::pair< double, double > msd_sim::FrictionConstraint::getFrictionBounds','() const',NULL,232,'Get friction force bounds for box-constrained LCP.','Returns bounds for friction forces in both tangent directions: Lower bound: -μ/√2 · λn Upper bound: +μ/√2 · λn The √2 factor distributes the circular Coulomb cone into two orthogonal box constraints (inscribed square approximation). {lower_bound, upper_bound} pair [N] Thread safety: Not thread-safe if setNormalLambda() called concurrently Precondition: setNormalLambda() must have been called with valid λn','public',0,1,0,0,0,0);
INSERT INTO "members" VALUES (714,'classmsd__sim_1_1_friction_constraint_1a23345973ea9c23fcfaf0f2c65ab2d968',83,'function','getTangent1','msd_sim::FrictionConstraint::getTangent1','const Coordinate &','const Coordinate & msd_sim::FrictionConstraint::getTangent1','() const',NULL,238,'Get first tangent direction (world space).','Unit tangent vector t1','public',0,1,0,0,1,0);
INSERT INTO "members" VALUES (715,'classmsd__sim_1_1_friction_constraint_1aaf7e2b8042441591e3ed7dc1cba7f1dc',83,'function','getTangent2','msd_sim::FrictionConstraint::getTangent2','const Coordinate &','const Coordinate & msd_sim::FrictionConstraint::getTangent2','() const',NULL,247,'Get second tangent direction (world space).','Unit tangent vector t2','public',0,1,0,0,1,0);
