INSERT INTO "members" VALUES (757,'classmsd__assets_1_1_geometry_factory_1af60ea6a52c6ccd734a29593ace5c35c4',88,'function','createCube','msd_assets::GeometryFactory::createCube','msd_transfer::MeshRecord','msd_transfer::MeshRecord msd_assets::GeometryFactory::createCube','(double size)',NULL,43,'Create a cube centered at origin.','Creates a cube with side length ''size'', triangulated into 12 triangles (2 per face, 6 faces). Vertices are ordered for proper rendering. The cube extends from -size/2 to +size/2 in all dimensions. T Either MeshRecord or CollisionMeshRecord size Side length of the cube MeshRecord object containing 36 vertices (12 triangles × 3 vertices)','public',1,0,0,0,0,0);
INSERT INTO "members" VALUES (758,'classmsd__assets_1_1_geometry_factory_1aa77717bf66835cbbf4534e2ec65dc24b',88,'function','createCubeWireframe','msd_assets::GeometryFactory::createCubeWireframe','msd_transfer::MeshRecord','msd_transfer::MeshRecord msd_assets::GeometryFactory::createCubeWireframe','(double size)',NULL,55,'Create a wireframe cube (edges only) centered at origin.','Creates vertices for the 12 edges of a cube, useful for line rendering. Returns pairs of vertices representing each edge. T Either MeshRecord or CollisionMeshRecord size Side length of the cube MeshRecord object containing 24 vertices (12 edges × 2 vertices)','public',1,0,0,0,0,0);
