INSERT INTO "members" VALUES (970,'classmsd__sim_1_1_motion_controller_1a58f0a4d99d761affacef7b0040a81fab',109,'function','updateTransform','msd_sim::MotionController::updateTransform','void','void msd_sim::MotionController::updateTransform','(ReferenceFrame &frame, const InputCommands &commands, std::chrono::milliseconds deltaTime) const',NULL,72,'Update a ReferenceFrame based on input commands.','frame ReferenceFrame to update (non-owning reference) commands Input commands (boolean flags) deltaTime Time elapsed since last update (for frame-rate independence) Applies linear movement in local frame: moveForward: -Z local direction moveBackward: +Z local direction moveLeft: -X local direction moveRight: +X local direction moveUp: +Y local direction moveDown: -Y local direction Applies rotation: pitchUp: Increase pitch angle pitchDown: Decrease pitch angle yawLeft: Increase yaw angle yawRight: Decrease yaw angle All movements scaled by moveSpeed * sensitivity and deltaTime. All rotations scaled by rotSpeed and deltaTime.','public',0,1,0,0,0,0);
