INSERT INTO "members" VALUES (984,'classmsd__sim_1_1_n_lopt_friction_solver_1a883712494b6bafa258ef8c4f8d1132aa',110,'function','solve','msd_sim::NLoptFrictionSolver::solve','SolveResult','NLoptFrictionSolver::SolveResult msd_sim::NLoptFrictionSolver::solve','(const Eigen::MatrixXd &A, const Eigen::VectorXd &b, const std::vector< double > &mu, const Eigen::VectorXd &lambda0=Eigen::VectorXd{}, const std::vector< double > &normalUpperBounds={}, const std::vector< double > &tangent1LowerBounds={})',NULL,83,'Solve the friction cone constrained QP.','A Effective mass matrix (3C x 3C), symmetric positive definite b RHS vector (3C x 1) with restitution/velocity terms mu Per-contact friction coefficients (C entries). Invalid values (< 0) clamped to 0. lambda0 Warm-start vector (3C x 1). If empty or wrong size, cold start from zero. normalUpperBounds Per-contact upper bounds on normal impulses (C entries). If non-empty, constrains lambda_n_i <= normalUpperBounds[i]. Used to prevent the coupled QP from inflating normal impulses beyond non-penetration needs. tangent1LowerBounds Per-contact lower bounds on tangent1 impulses (C entries). If non-empty, constrains lambda_t1_i >= tangent1LowerBounds[i]. Used to prevent friction from reversing sliding direction (typically 0.0 for sliding mode, omitted for bilateral friction). Default: empty (bilateral). SolveResult with optimal lambda and diagnostics Ticket:\n 0069_friction_velocity_reversal','public',0,0,0,0,0,0);
