INSERT INTO "members" VALUES (996,'classmsd__sim_1_1_n_lopt_friction_solver_1afbed2e6548405f906d3042d70c865223',110,'function','coneConstraint','msd_sim::NLoptFrictionSolver::coneConstraint','double','double msd_sim::NLoptFrictionSolver::coneConstraint','(const std::vector< double > &lambda, std::vector< double > &grad, void *data)',NULL,138,'Cone constraint callback for contact i: c_i(lambda) = mu^2*n^2 - t1^2 - t2^2.','Note: NLopt expects constraints as c(x) <= 0, so we negate to -c(x) <= 0 which is equivalent to c(x) >= 0. lambda Current iterate (3C x 1) grad Output gradient (3 x 1): [2*mu^2*n, -2*t1, -2*t2] data Pointer to ConstraintData struct Constraint value (negated for NLopt convention)','private',1,0,0,0,0,0);
