INSERT INTO "members" VALUES (1090,'classmsd__sim_1_1_projected_gauss_seidel_1a6b2498c73c87f4f0a3258bf96eae38ec',122,'function','solve','msd_sim::ProjectedGaussSeidel::solve','SolveResult','ProjectedGaussSeidel::SolveResult msd_sim::ProjectedGaussSeidel::solve','(const std::vector< Constraint * > &constraints, const std::vector< std::reference_wrapper< const InertialState > > &states, const std::vector< double > &inverseMasses, const std::vector< Eigen::Matrix3d > &inverseInertias, size_t numBodies, double dt, const std::optional< Eigen::VectorXd > &initialLambda=std::nullopt)',NULL,103,'Solve mixed LCP using Projected Gauss-Seidel.','Accepts an interleaved [CC, FC, CC, FC, ...] constraint list. Uses ConstraintSolver::flattenConstraints() to expand multi-row constraints into per-row entries, then performs PGS sweeps. Friction rows use ball-projection (not lambdaBounds() box bounds). setNormalLambda() is NOT called during PGS sweeps (bypassed by design). constraints Interleaved ContactConstraint and FrictionConstraint ptrs states Per-body kinematic state inverseMasses Per-body inverse mass (size = numBodies) inverseInertias Per-body inverse inertia tensor (size = numBodies) numBodies Number of bodies in the system dt Timestep [s] initialLambda Warm-start vector (same size as active rows); zeros if empty or wrong size. SolveResult with bodyForces, lambdas, iterations, converged, residual','public',0,0,0,0,0,0);
