INSERT INTO "members" VALUES (1095,'classmsd__sim_1_1_projected_gauss_seidel_1a7c73ab0a58504cf1df85c600aff5db26',122,'function','sweepOnce','msd_sim::ProjectedGaussSeidel::sweepOnce','double','double msd_sim::ProjectedGaussSeidel::sweepOnce','(const std::vector< FlatRow > &rows, const std::vector< double > &muPerContact, const Eigen::VectorXd &diag, const Eigen::VectorXd &b, Eigen::VectorXd &lambda, const std::vector< double > &inverseMasses, const std::vector< Eigen::Matrix3d > &inverseInertias)',NULL,178,'Execute one Gauss-Seidel sweep using velocity-residual approach.','Processes rows in flat order. When a Normal row is followed by two Tangent rows (standard friction pair), they are solved together with ball-projection. Updates vRes_ member in-place. rows Flattened per-row data muPerContact Friction coefficient per contact (indexed by contact) diag Diagonal effective-mass elements A_ii (size = numRows) b RHS vector (size = numRows) lambda In/out lambda vector updated in-place inverseMasses Per-body inverse mass inverseInertias Per-body inverse inertia max |delta_lambda| this sweep (for convergence check)','private',0,0,0,0,0,0);
INSERT INTO "members" VALUES (1096,'classmsd__sim_1_1_projected_gauss_seidel_1a843fcae1d085b2c7a2eeac71a66d4d6d',122,'function','updateVRes','msd_sim::ProjectedGaussSeidel::updateVRes','void','void msd_sim::ProjectedGaussSeidel::updateVRes','(const std::vector< FlatRow > &rows, size_t rowIdx, double dLambda, const std::vector< double > &inverseMasses, const std::vector< Eigen::Matrix3d > &inverseInertias)',NULL,191,'Update velocity residual after a lambda change on row rowIdx. vRes_ += M^{-1} * J_i^T * dLambda.','','private',0,0,0,0,0,0);
