INSERT INTO "members" VALUES (1173,'classmsd__sim_1_1_reference_frame_1acfcc78feef0571965bafdc015c51bf02',129,'function','ReferenceFrame','msd_sim::ReferenceFrame::ReferenceFrame','','msd_sim::ReferenceFrame::ReferenceFrame','(Coordinate origin, const Coordinate &xDirection, const Coordinate &zDirection)',NULL,97,'Constructor from local X and Z axes (right-hand rule).','Constructs a reference frame from two vectors representing the local X-axis (tangent direction) and Z-axis (normal direction). The Y-axis is computed using the cross product Y = Z × X to follow the right-hand rule. The input vectors do not need to be normalized or perfectly orthogonal - they will be processed as follows: Z is normalized (takes precedence as the primary/normal direction) X is orthogonalized against Z and normalized Y is computed as Z × X This is useful for constructing a local coordinate frame based on a surface normal (Z) and tangent direction (X), common in collision response. origin The origin of this frame in global coordinates xDirection Vector representing the local positive X-axis direction zDirection Vector representing the local positive Z-axis direction std::invalid_argument if either vector is zero or if vectors are parallel','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (1174,'classmsd__sim_1_1_reference_frame_1a492080dfa1c697081edbd87b48902a14',129,'function','ReferenceFrame','msd_sim::ReferenceFrame::ReferenceFrame','','msd_sim::ReferenceFrame::ReferenceFrame','(Coordinate origin, const Eigen::Quaterniond &quaternion)',NULL,110,'Constructor with origin and quaternion orientation.','Constructs a reference frame using a quaternion to specify orientation. The quaternion will be normalized internally for robustness. origin The origin of this frame in global coordinates quaternion The orientation as a unit quaternion (will be normalized)','public',0,0,0,0,0,0);
