INSERT INTO "members" VALUES (1311,'classmsd__sim_1_1_unit_quaternion_constraint_1a3c325f40dd4357b11a8cd1da228609c5',151,'function','dimension','msd_sim::UnitQuaternionConstraint::dimension','int','int msd_sim::UnitQuaternionConstraint::dimension','() const override',NULL,52,'Number of scalar constraint equations.','Dimension of constraint vector C(q, t)','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (1312,'classmsd__sim_1_1_unit_quaternion_constraint_1ac2afbe551104bae8b01b7336728f5832',151,'function','evaluate','msd_sim::UnitQuaternionConstraint::evaluate','Eigen::VectorXd','Eigen::VectorXd msd_sim::UnitQuaternionConstraint::evaluate','(const InertialState &stateA, const InertialState &stateB, double time) const override',NULL,55,'Evaluate constraint function C(qA, qB, t) for two bodies.','Returns vector of constraint violations. For bilateral constraints, C = 0 is the target. For unilateral constraints, C ≥ 0 is the target. Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Constraint violation vector (dimension × 1) std::invalid_argument if state is invalid','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (1313,'classmsd__sim_1_1_unit_quaternion_constraint_1a08204a799a5b448eb52fa31c50702b89',151,'function','jacobian','msd_sim::UnitQuaternionConstraint::jacobian','Eigen::MatrixXd','Eigen::MatrixXd msd_sim::UnitQuaternionConstraint::jacobian','(const InertialState &stateA, const InertialState &stateB, double time) const override',NULL,60,'Compute constraint Jacobian J = ∂C/∂q for two bodies.','Returns partial derivatives of constraint function w.r.t. position-level or velocity-level DOFs (depending on bodyCount): Single-body ( bodyCount() == 1): dimension × 7 (X: 3, Q: 4) Two-body ( bodyCount() == 2): dimension × 12 (v_A: 3, ω_A: 3, v_B: 3, ω_B: 3) Single-body constraints ignore stateB. stateA Current inertial state of body A (or single body) stateB Current inertial state of body B (ignored for single-body) time Simulation time [s] Jacobian matrix (dimension × 7 or dimension × 12) std::invalid_argument if state is invalid','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (1314,'classmsd__sim_1_1_unit_quaternion_constraint_1ab7a00171c2ebdddbe2ec20bb3005663e',151,'function','partialTimeDerivative','msd_sim::UnitQuaternionConstraint::partialTimeDerivative','Eigen::VectorXd','Eigen::VectorXd msd_sim::UnitQuaternionConstraint::partialTimeDerivative','(const InertialState &state, double time) const override',NULL,63,'Compute constraint time derivative ∂C/∂t (optional).','Returns partial derivative of constraint w.r.t. explicit time dependence. For time-independent constraints, this returns a zero vector. Default implementation: zero vector (no explicit time dependence) state Current inertial state time Simulation time [s] Time derivative vector (dimension × 1)','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (1315,'classmsd__sim_1_1_unit_quaternion_constraint_1afb924584a3e99da7417880c40da19e57',151,'function','lambdaBounds','msd_sim::UnitQuaternionConstraint::lambdaBounds','LambdaBounds','LambdaBounds msd_sim::UnitQuaternionConstraint::lambdaBounds','() const override',NULL,65,'Get Lagrange multiplier bounds.','Specifies the lower and upper bounds on the constraint''s Lagrange multiplier: Bilateral constraints: (-∞, +∞) Unilateral constraints: (0, +∞) Box-constrained: (lo, hi) LambdaBounds struct with lower and upper fields','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (1316,'classmsd__sim_1_1_unit_quaternion_constraint_1a85a0a2b3d79f45d8dc965d8a47320d8a',151,'function','typeName','msd_sim::UnitQuaternionConstraint::typeName','std::string','std::string msd_sim::UnitQuaternionConstraint::typeName','() const override',NULL,66,'Constraint type identifier for debugging/logging.','Human-readable constraint type name','public',0,1,0,1,0,0);
INSERT INTO "members" VALUES (1317,'classmsd__sim_1_1_unit_quaternion_constraint_1a7e09bf76e2a390f1a57353f978717a20',151,'function','recordState','msd_sim::UnitQuaternionConstraint::recordState','void','void msd_sim::UnitQuaternionConstraint::recordState','(msd_transfer::ConstraintRecordVisitor &visitor, uint32_t bodyAId, uint32_t bodyBId) const override',NULL,68,'Record constraint state via visitor pattern.','Builds a typed constraint record (ContactConstraintRecord, FrictionConstraintRecord, etc.) and dispatches to the visitor via overload resolution. The visitor decides what to do with the record (e.g., buffer to DataRecorder DAO). Enables compile-time type-safe constraint recording without dynamic_cast or std::any_cast. New constraint types extend ConstraintRecordVisitor with a new visit() overload. visitor Visitor that processes the typed constraint record bodyAId Persistent ID of body A for database FK reference bodyBId Persistent ID of body B for database FK reference (ignored for single-body) msd_transfer::ConstraintRecordVisitor msd_sim::DataRecorderVisitor','public',0,1,0,1,0,0);
