INSERT INTO "members" VALUES (1427,'classmsd__sim_1_1_world_model_1ad6d09c4046f1df8b24798d249a29bcdf',163,'function','enableRecording','msd_sim::WorldModel::enableRecording','void','void msd_sim::WorldModel::enableRecording','(const std::string &dbPath, std::chrono::milliseconds flushInterval=std::chrono::milliseconds{100})',NULL,304,'Enable simulation data recording to SQLite database.','Creates a DataRecorder instance that operates on a background thread, periodically flushing buffered records. Recording begins immediately and continues until disableRecording() is called or WorldModel is destroyed. dbPath Path to SQLite database file (created if doesn''t exist) flushInterval How often to flush buffered records to disk std::runtime_error if database cannot be opened Ticket:\n 0038_simulation_data_recorder','public',0,0,0,0,0,0);
INSERT INTO "members" VALUES (1428,'classmsd__sim_1_1_world_model_1aabd5ea39d9619cab0ac21e17bcdf2dd2',163,'function','disableRecording','msd_sim::WorldModel::disableRecording','void','void msd_sim::WorldModel::disableRecording','()',NULL,316,'Disable simulation data recording.','Flushes all pending records and stops the recorder thread. After this call, no more recording occurs until enableRecording() is called. Ticket:\n 0038_simulation_data_recorder','public',0,0,0,0,0,0);
