INSERT INTO "members" VALUES (1430,'classmsd__sim_1_1_world_model_1a1f9d7646ec2f9a261ed5fa35faed25c3',163,'function','updateCollisions','msd_sim::WorldModel::updateCollisions','void','void msd_sim::WorldModel::updateCollisions','(double dt)',NULL,337,'Detect and resolve collisions using constraint-based approach.','Creates transient contact constraints from collision results, solves them via Projected Gauss-Seidel (PGS), and applies constraint forces to bodies. dt Timestep [s] (needed for PGS solver force conversion) Ticket:\n 0032_contact_constraint_refactor','private',0,0,0,0,0,0);
