BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "compounds" (
	"id"	INTEGER,
	"refid"	TEXT NOT NULL UNIQUE,
	"kind"	TEXT NOT NULL,
	"name"	TEXT NOT NULL,
	"qualified_name"	TEXT NOT NULL,
	"file_id"	INTEGER,
	"line_number"	INTEGER,
	"brief_description"	TEXT,
	"detailed_description"	TEXT,
	"base_classes"	TEXT,
	"is_final"	INTEGER DEFAULT 0,
	"is_abstract"	INTEGER DEFAULT 0,
	PRIMARY KEY("id"),
	FOREIGN KEY("file_id") REFERENCES "files"("id")
);
CREATE TABLE IF NOT EXISTS "files" (
	"id"	INTEGER,
	"refid"	TEXT NOT NULL UNIQUE,
	"name"	TEXT NOT NULL,
	"path"	TEXT,
	"language"	TEXT,
	PRIMARY KEY("id")
);
CREATE TABLE IF NOT EXISTSAL TABLE fts_docs USING fts5(
            name,
            qualified_name,
            description,
            tokenize='porter'
        );
CREATE TABLE IF NOT EXISTS "fts_docs_config" (
	"k"	,
	"v"	,
	PRIMARY KEY("k")
) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS "fts_docs_content" (
	"id"	INTEGER,
	"c0"	,
	"c1"	,
	"c2"	,
	PRIMARY KEY("id")
);
CREATE TABLE IF NOT EXISTS "fts_docs_data" (
	"id"	INTEGER,
	"block"	BLOB,
	PRIMARY KEY("id")
);
CREATE TABLE IF NOT EXISTS "fts_docs_docsize" (
	"id"	INTEGER,
	"sz"	BLOB,
	PRIMARY KEY("id")
);
CREATE TABLE IF NOT EXISTS "fts_docs_idx" (
	"segid"	,
	"term"	,
	"pgno"	,
	PRIMARY KEY("segid","term")
) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS "includes" (
	"id"	INTEGER,
	"file_id"	INTEGER,
	"included_file"	TEXT NOT NULL,
	"included_refid"	TEXT,
	"is_local"	INTEGER DEFAULT 0,
	PRIMARY KEY("id"),
	FOREIGN KEY("file_id") REFERENCES "files"("id")
);
CREATE TABLE IF NOT EXISTS "members" (
	"id"	INTEGER,
	"refid"	TEXT NOT NULL UNIQUE,
	"compound_id"	INTEGER,
	"kind"	TEXT NOT NULL,
	"name"	TEXT NOT NULL,
	"qualified_name"	TEXT NOT NULL,
	"type"	TEXT,
	"definition"	TEXT,
	"argsstring"	TEXT,
	"file_id"	INTEGER,
	"line_number"	INTEGER,
	"brief_description"	TEXT,
	"detailed_description"	TEXT,
	"protection"	TEXT,
	"is_static"	INTEGER DEFAULT 0,
	"is_const"	INTEGER DEFAULT 0,
	"is_constexpr"	INTEGER DEFAULT 0,
	"is_virtual"	INTEGER DEFAULT 0,
	"is_inline"	INTEGER DEFAULT 0,
	"is_explicit"	INTEGER DEFAULT 0,
	PRIMARY KEY("id"),
	FOREIGN KEY("compound_id") REFERENCES "compounds"("id"),
	FOREIGN KEY("file_id") REFERENCES "files"("id")
);
CREATE TABLE IF NOT EXISTS "metadata" (
	"key"	TEXT,
	"value"	TEXT,
	PRIMARY KEY("key")
);
CREATE TABLE IF NOT EXISTS "namespaces" (
	"id"	INTEGER,
	"refid"	TEXT NOT NULL UNIQUE,
	"name"	TEXT NOT NULL,
	"qualified_name"	TEXT NOT NULL,
	PRIMARY KEY("id")
);
CREATE TABLE IF NOT EXISTS "parameters" (
	"id"	INTEGER,
	"member_id"	INTEGER,
	"position"	INTEGER NOT NULL,
	"name"	TEXT,
	"type"	TEXT NOT NULL,
	"default_value"	TEXT,
	"description"	TEXT,
	PRIMARY KEY("id"),
	FOREIGN KEY("member_id") REFERENCES "members"("id")
);
CREATE TABLE IF NOT EXISTS "symbol_refs" (
	"id"	INTEGER,
	"from_member_id"	INTEGER,
	"to_member_refid"	TEXT NOT NULL,
	"to_member_name"	TEXT NOT NULL,
	"relationship"	TEXT NOT NULL,
	PRIMARY KEY("id"),
	FOREIGN KEY("from_member_id") REFERENCES "members"("id")
);
